const ShopPage = lazy(() => import('@/pages/shop/index'))
const ProductDetailPage = lazy(() => import('@/pages/shop/product-detail'))
const CartPage = lazy(() => import('@/pages/shop/cart'))
const CheckoutPage = lazy(() => import('@/pages/shop/checkout'))
