  onSend: (data: { title: string; body: string }) => void
  loading?: boolean
  recentBroadcasts?: BroadcastLogEntry[]
  collectiveName?: string
}

function relativeTime(dateStr: string): string {
  const now = Date.now()
  const then = new Date(dateStr).getTime()
  const diffMs = now - then
  const diffMin = Math.floor(diffMs / 60000)
  if (diffMin < 1) return 'Just now'
  if (diffMin < 60) return `${diffMin}m ago`
  const diffHr = Math.floor(diffMin / 60)
  if (diffHr < 24) return `${diffHr}h ago`
  const diffDays = Math.floor(diffHr / 24)
  if (diffDays < 7) return `${diffDays}d ago`
  return new Date(dateStr).toLocaleDateString('en-AU', { day: 'numeric', month: 'short' })
}

export function BroadcastNotificationSheet({
  open,
  onClose,
  onSend,
  loading,
  recentBroadcasts = [],
  collectiveName,
}: BroadcastNotificationSheetProps) {
  const [title, setTitle] = useState('')
  const [body, setBody] = useState('')

  const canSend = title.trim().length > 0 && body.trim().length > 0

  const handleSend = () => {
    if (!canSend) return
    onSend({ title: title.trim(), body: body.trim() })
    setTitle('')
    setBody('')
  }

  // Recent broadcasts within last 24h for dedup awareness
  const [now] = useState(() => Date.now())
  const recentBroadcasts24h = recentBroadcasts.filter(
    (b) => now - new Date(b.created_at).getTime() < 24 * 60 * 60 * 1000,
  )

  return (
    <CenteredDialog open={open} onClose={onClose}>
      <div className="pb-4">
        {/* Header */}
        <div className="flex items-center gap-2.5 mb-4">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-warning-100 text-warning-600">
            <Bell size={20} />
          </div>
          <div>
            <h3 className="text-base font-bold text-primary-900">Push Notification</h3>
            <p className="text-xs text-primary-400">
              Send to all {collectiveName ? `${collectiveName} ` : ''}members
            </p>
          </div>
        </div>

        {/* Recent broadcasts warning (dedup) */}
        {recentBroadcasts24h.length > 0 && (
          <div className="mb-4 rounded-xl bg-warning-50 p-3 ring-1 ring-warning-200/60">
            <p className="text-xs font-semibold text-warning-700 mb-2 flex items-center gap-1.5">
              <Clock size={12} />
              Recent notifications (last 24h)
            </p>
            <div className="space-y-2">
              {recentBroadcasts24h.slice(0, 3).map((b) => (
                <div key={b.id} className="flex items-start gap-2">
                  <Avatar
                    src={b.profiles?.avatar_url}
                    name={b.profiles?.display_name}
                    size="xs"
                  />
                  <div className="flex-1 min-w-0">
                    <p className="text-[11px] font-semibold text-warning-800 truncate">
                      {b.profiles?.display_name ?? 'Staff'}: {b.title}
                    </p>
                    <p className="text-[11px] text-warning-500">
                      {relativeTime(b.created_at)} &middot; sent to {b.recipient_count} member{b.recipient_count !== 1 ? 's' : ''}
                    </p>
                  </div>
                </div>
              ))}
            </div>
            <p className="text-[11px] text-warning-500 mt-2 italic">
              Check above to avoid sending duplicate notifications
            </p>
          </div>
        )}

        {/* Title */}
        <div className="mb-3">
          <label htmlFor="broadcast-title" className="text-xs font-semibold text-primary-600 mb-1 block">
            Notification Title
          </label>
          <input
            id="broadcast-title"
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder="e.g. Beach Cleanup This Saturday!"
            maxLength={100}
            className="w-full rounded-xl bg-primary-50/50 px-3.5 py-2.5 text-sm text-primary-800 placeholder:text-primary-400 outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white min-h-11"
          />
        </div>

        {/* Body */}
        <div className="mb-4">
          <label htmlFor="broadcast-body" className="text-xs font-semibold text-primary-600 mb-1 block">
            Message
          </label>
          <textarea
            id="broadcast-body"
            value={body}
            onChange={(e) => setBody(e.target.value)}
            placeholder="Tell members what they need to know..."
            rows={3}
            maxLength={300}
            className="w-full rounded-xl bg-primary-50/50 px-3.5 py-2.5 text-sm text-primary-800 placeholder:text-primary-400 outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white resize-none"
          />
          <p className="text-[11px] text-primary-400 mt-1 text-right">
            {body.length}/300
          </p>
        </div>

        {/* Warning */}
        <p className="text-[11px] text-primary-400 mb-3 bg-primary-50 rounded-lg px-3 py-2">
          This will send a push notification to <strong>all registered members</strong> of this collective who have notifications enabled. Use sparingly.
        </p>

        {/* Send */}
        <Button
          variant="primary"
          size="lg"
          fullWidth
          onClick={handleSend}
          disabled={!canSend || loading}
          loading={loading}
          icon={<Bell size={16} />}
        >
          Send Push Notification
        </Button>
      </div>
    </CenteredDialog>
  )
}

import {
  type ReactNode,
  createContext,
  useContext,
  forwardRef,
} from 'react'
import { motion, useReducedMotion } from 'framer-motion'
import { cn } from '@/lib/cn'

/* ------------------------------------------------------------------ */
/*  Context                                                            */
/* ------------------------------------------------------------------ */

type CardVariant =
  | 'event'
  | 'collective'
  | 'stat'
  | 'profile'
  | 'merch'
  | 'announcement'

interface CardContextValue {
  variant: CardVariant
}

const CardContext = createContext<CardContextValue>({ variant: 'event' })

function useCard() {
  return useContext(CardContext)
}

/* ------------------------------------------------------------------ */
/*  Variant-specific styling                                           */
/* ------------------------------------------------------------------ */

const variantWrapper: Record<CardVariant, string> = {
  event: 'bg-surface-0',
  collective: 'bg-surface-2',
  stat: 'bg-gradient-to-br from-surface-0 to-primary-100/60',
  profile: 'bg-surface-2',
  merch: 'bg-surface-0',
  announcement:
    'bg-gradient-to-br from-surface-0 to-accent-100',
}

/* ------------------------------------------------------------------ */
/*  Card (root)                                                        */
/* ------------------------------------------------------------------ */

interface CardRootProps {
  variant?: CardVariant
  children: ReactNode
  className?: string
  onClick?: React.MouseEventHandler<HTMLDivElement>
  'aria-label'?: string
}

const CardRoot = forwardRef<HTMLDivElement, CardRootProps>(function CardRoot(
  { variant = 'event', children, className, onClick, 'aria-label': ariaLabel },
  ref,
) {
  const shouldReduceMotion = useReducedMotion()
  const isInteractive = !!onClick

  return (
    <CardContext.Provider value={{ variant }}>
      <motion.div
        ref={ref}
        role={isInteractive ? 'button' : 'article'}
        tabIndex={isInteractive ? 0 : undefined}
        aria-label={ariaLabel}
        onClick={onClick}
        onKeyDown={
          isInteractive
            ? (e: React.KeyboardEvent) => {
                if (e.key === 'Enter' || e.key === ' ') {
                  e.preventDefault()
                  onClick?.(e as unknown as React.MouseEvent<HTMLDivElement>)
                }
              }
            : undefined
        }
        whileTap={
          isInteractive && !shouldReduceMotion
            ? { scale: 0.98 }
            : undefined
        }
        transition={{ type: 'spring', stiffness: 400, damping: 26, mass: 0.7 }}
        className={cn(
          'rounded-2xl shadow-md overflow-hidden',
          isInteractive && 'cursor-pointer select-none',
          'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary-400 focus-visible:ring-offset-2',
          variantWrapper[variant],
          className,
        )}
      >
        {children}
      </motion.div>
    </CardContext.Provider>
  )
})

/* ------------------------------------------------------------------ */
/*  Card.Image                                                         */
/* ------------------------------------------------------------------ */

interface CardImageProps {
  src: string
  alt: string
  aspectRatio?: string
  className?: string
}

function CardImage({
  src,
  alt,
  aspectRatio = '16/9',
  className,
}: CardImageProps) {
  const { variant } = useCard()
  const hasGradient = variant === 'event'

  return (
    <div
      className={cn('relative w-full overflow-hidden', className)}
      style={{ aspectRatio }}
    >
      <img
        src={src}
        alt={alt}
        loading="lazy"
        className="absolute inset-0 w-full h-full object-cover"
      />
      {hasGradient && (
        <div
          className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-transparent"
          aria-hidden="true"
        />
      )}
    </div>
  )
}

/* ------------------------------------------------------------------ */
/*  Card.Badge                                                         */
/* ------------------------------------------------------------------ */

interface CardBadgeProps {
  children: ReactNode
  position?: 'top-left' | 'top-right' | 'bottom-left' | 'bottom-right'
  className?: string
}

const badgePositionMap: Record<NonNullable<CardBadgeProps['position']>, string> = {
  'top-left': 'top-2 left-2',
  'top-right': 'top-2 right-2',
  'bottom-left': 'bottom-2 left-2',
  'bottom-right': 'bottom-2 right-2',
}

function CardBadge({
  children,
  position = 'top-right',
  className,
}: CardBadgeProps) {
  return (
    <span
      className={cn(
        'absolute z-10',
        badgePositionMap[position],
        className,
      )}
    >
      {children}
    </span>
  )
}

/* ------------------------------------------------------------------ */
/*  Card.Content                                                       */
/* ------------------------------------------------------------------ */

interface CardContentProps {
  children: ReactNode
  className?: string
}

function CardContent({ children, className }: CardContentProps) {
  return <div className={cn('p-4', className)}>{children}</div>
}

/* ------------------------------------------------------------------ */
/*  Card.Title                                                         */
/* ------------------------------------------------------------------ */

interface CardTitleProps {
  children: ReactNode
  as?: 'h2' | 'h3' | 'h4' | 'h5'
  className?: string
}

function CardTitle({ children, as: Tag = 'h3', className }: CardTitleProps) {
  return (
    <Tag
      className={cn(
        'font-heading font-semibold text-primary-800 leading-tight',
        className,
      )}
    >
      {children}
    </Tag>
  )
}

/* ------------------------------------------------------------------ */
/*  Card.Meta                                                          */
/* ------------------------------------------------------------------ */

interface CardMetaProps {
  children: ReactNode
  className?: string
}

function CardMeta({ children, className }: CardMetaProps) {
  return (
    <p className={cn('text-caption text-primary-400 mt-1', className)}>
      {children}
    </p>
  )
}

/* ------------------------------------------------------------------ */
/*  Card.Skeleton                                                      */
/* ------------------------------------------------------------------ */

interface CardSkeletonProps {
  hasImage?: boolean
  lines?: number
  className?: string
}

function CardSkeleton({
  hasImage = true,
  lines = 3,
  className,
}: CardSkeletonProps) {
  return (
    <div
      role="status"
      aria-label="Loading card"
      className={cn(
        'rounded-2xl shadow-md overflow-hidden bg-surface-0 animate-pulse',
        className,
      )}
    >
      {hasImage && (
        <div className="w-full bg-primary-100" style={{ aspectRatio: '16/9' }} />
      )}
      <div className="p-4 space-y-2.5">
        {Array.from({ length: lines }).map((_, i) => (
          <div
            key={i}
            className={cn(
              'h-3.5 bg-primary-100 rounded',
              i === 0 && 'w-3/4 h-4',
              i === lines - 1 && 'w-1/2',
            )}
          />
        ))}
      </div>
    </div>
  )
}

/* ------------------------------------------------------------------ */
/*  Compound export                                                    */
/* ------------------------------------------------------------------ */

export const Card = Object.assign(CardRoot, {
  Root: CardRoot,
  Image: CardImage,
  Badge: CardBadge,
  Content: CardContent,
  Title: CardTitle,
  Meta: CardMeta,
  Skeleton: CardSkeleton,
})

