export function CreateAnnouncementSheet({
  open,
  onClose,
  onSubmit,
  onInviteCollectives,
  loading,
  defaultType = 'announcement',
  collectiveId,
}: CreateAnnouncementSheetProps) {
  const [type, setType] = useState<'announcement' | 'event_invite' | 'rsvp'>(defaultType)
  const [title, setTitle] = useState('')
  const [body, setBody] = useState('')
  const [eventId, setEventId] = useState('')
  const [inviteCollectiveIds, setInviteCollectiveIds] = useState<string[]>([])
  const [inviteMessage, setInviteMessage] = useState('')

  // Fetch upcoming events for this collective
  const { data: upcomingEvents = [], isLoading: eventsLoading } = useCollectiveEvents(
    open && type === 'event_invite' ? collectiveId : undefined,
  )

  // Reset form when opened with new defaultType
  useEffect(() => {
    if (open) {
      startTransition(() => {
        setType(defaultType)
        setTitle('')
        setBody('')
        setEventId('')
        setInviteCollectiveIds([])
        setInviteMessage('')
      })
    }
  }, [open, defaultType])

  // Auto-fill title when event is selected
  useEffect(() => {
    if (eventId && type === 'event_invite') {
      const event = upcomingEvents.find((e) => e.id === eventId)
      if (event && !title) {
        startTransition(() => setTitle(`Join us: ${event.title}`))
      }
    }
  }, [eventId, type, upcomingEvents, title])

  const canSubmit = title.trim().length > 0 && (type !== 'event_invite' || eventId)

  const handleToggleCollective = (id: string) => {
    setInviteCollectiveIds((prev) =>
      prev.includes(id) ? prev.filter((x) => x !== id) : [...prev, id],
    )
  }

  const handleSubmit = () => {
    if (!canSubmit) return

    // Post the announcement/invite to chat
    onSubmit({
      type,
      title: title.trim(),
      body: body.trim() || undefined,
      metadata: type === 'event_invite' && eventId ? { event_id: eventId } : undefined,
    })

    // If collectives were selected for collaboration, fire that too
    if (type === 'event_invite' && eventId && inviteCollectiveIds.length > 0 && onInviteCollectives) {
      onInviteCollectives({
        eventId,
        collectiveIds: inviteCollectiveIds,
        message: inviteMessage.trim() || undefined,
      })
    }

    setTitle('')
    setBody('')
    setEventId('')
    setInviteCollectiveIds([])
    setInviteMessage('')
  }

  const typeOptions = [
    { value: 'announcement' as const, label: 'Announcement', icon: Megaphone, desc: 'Share news with your collective' },
    { value: 'event_invite' as const, label: 'Event Invite', icon: CalendarPlus, desc: 'Invite members to an event' },
    { value: 'rsvp' as const, label: 'RSVP Request', icon: CalendarPlus, desc: 'Ask members to RSVP' },
  ]

  return (
    <CenteredDialog open={open} onClose={onClose}>
      <div className="pb-4 max-h-[80vh] overflow-y-auto overscroll-contain">
        {/* Header */}
        <div className="flex items-center gap-2.5 mb-4">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-accent-100 text-accent-600">
            <Megaphone size={20} />
          </div>
          <div>
            <h3 className="text-base font-bold text-primary-900">Create Announcement</h3>
            <p className="text-xs text-primary-400">Share something with your collective</p>
          </div>
        </div>

        {/* Type selector */}
        <div className="mb-4">
          <label className="text-xs font-semibold text-primary-600 mb-1.5 block">Type</label>
          <div className="flex gap-2">
            {typeOptions.map((opt) => (
              <button
                key={opt.value}
                type="button"
                onClick={() => setType(opt.value)}
                className={cn(
                  'flex-1 rounded-xl py-2.5 px-2 text-center transition-all duration-150 min-h-11',
                  'active:scale-[0.95] cursor-pointer select-none',
                  type === opt.value
                    ? 'bg-primary-600 text-white shadow-sm'
                    : 'bg-primary-50 text-primary-600 ring-1 ring-primary-200/60',
                )}
              >
                <opt.icon size={16} className="mx-auto mb-0.5" />
                <span className="text-[11px] font-semibold block">{opt.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Event picker (for event invites) */}
        {type === 'event_invite' && (
          <div className="mb-3">
            <label className="text-xs font-semibold text-primary-600 mb-1 block">
              Event
            </label>
            <EventPicker
              events={upcomingEvents}
              selectedId={eventId}
              onSelect={setEventId}
              isLoading={eventsLoading}
            />
            {!eventsLoading && upcomingEvents.length === 0 && (
              <p className="text-[11px] text-warning-600 mt-1">
                No upcoming events found. Create an event first, then invite from here.
              </p>
            )}
          </div>
        )}

        {/* Title */}
        <div className="mb-3">
          <label htmlFor="ann-title" className="text-xs font-semibold text-primary-600 mb-1 block">
            Title
          </label>
          <input
            id="ann-title"
            type="text"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            placeholder={type === 'event_invite' ? 'Come join us at...' : 'Your announcement title'}
            maxLength={150}
            className="w-full rounded-xl bg-primary-50/50 px-3.5 py-2.5 text-sm text-primary-800 placeholder:text-primary-400 outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white min-h-11"
          />
        </div>

        {/* Body */}
        <div className="mb-3">
          <label htmlFor="ann-body" className="text-xs font-semibold text-primary-600 mb-1 block">
            Details (optional)
          </label>
          <textarea
            id="ann-body"
            value={body}
            onChange={(e) => setBody(e.target.value)}
            placeholder="Add more details..."
            rows={3}
            maxLength={500}
            className="w-full rounded-xl bg-primary-50/50 px-3.5 py-2.5 text-sm text-primary-800 placeholder:text-primary-400 outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white resize-none"
          />
        </div>

        {/* Invite other collectives to collaborate (event invites only) */}
        {type === 'event_invite' && eventId && collectiveId && (
          <div className="mb-4">
            <div className="flex items-center gap-2 mb-1.5">
              <Users2 size={14} className="text-primary-500" />
              <label className="text-xs font-semibold text-primary-600">
                Invite collectives to collaborate (optional)
              </label>
            </div>
            <p className="text-[11px] text-primary-400 mb-2">
              Invite other collectives to co-host this event. Their leaders will be notified and can accept the collaboration.
            </p>
            <CollectivePicker
              currentCollectiveId={collectiveId}
              selectedIds={inviteCollectiveIds}
              onToggle={handleToggleCollective}
            />

            {/* Collaboration message */}
            {inviteCollectiveIds.length > 0 && (
              <div className="mt-2.5">
                <label htmlFor="collab-msg" className="text-[11px] font-semibold text-primary-500 mb-1 block">
                  Message to invited collectives (optional)
                </label>
                <input
                  id="collab-msg"
                  type="text"
                  value={inviteMessage}
                  onChange={(e) => setInviteMessage(e.target.value)}
                  placeholder="Hey! Want to join forces on this one?"
                  maxLength={300}
                  className="w-full rounded-xl bg-primary-50/50 px-3.5 py-2 text-sm text-primary-800 placeholder:text-primary-400 outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white min-h-11"
                />
              </div>
            )}
          </div>
        )}

        {/* Submit */}
        <Button
          variant="primary"
          size="lg"
          fullWidth
          onClick={handleSubmit}
          disabled={!canSubmit || loading}
          loading={loading}
        >
          {type === 'event_invite'
            ? inviteCollectiveIds.length > 0
              ? `Post Invite & Invite ${inviteCollectiveIds.length} Collective${inviteCollectiveIds.length !== 1 ? 's' : ''}`
              : 'Post Event Invite'
            : type === 'rsvp'
              ? 'Post RSVP Request'
              : 'Post Announcement'}
        </Button>
      </div>
    </CenteredDialog>
  )
}

import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { Plus, Trash2, BarChart3 } from 'lucide-react'
import { CenteredDialog } from '@/components/centered-dialog'
import { Button } from '@/components/button'
import { cn } from '@/lib/cn'

interface CreatePollSheetProps {
  open: boolean
  onClose: () => void
  onSubmit: (data: {
    question: string
    options: string[]
    allowMultiple: boolean
    anonymous: boolean
  }) => void
  loading?: boolean
}

export function CreatePollSheet({ open, onClose, onSubmit, loading }: CreatePollSheetProps) {
  const [question, setQuestion] = useState('')
  const [options, setOptions] = useState(['', ''])
  const [allowMultiple, setAllowMultiple] = useState(false)
  const [anonymous, setAnonymous] = useState(false)

  const canSubmit = question.trim().length > 0 && options.filter((o) => o.trim()).length >= 2

  const handleSubmit = () => {
    if (!canSubmit) return
    onSubmit({
      question: question.trim(),
      options: options.filter((o) => o.trim()).map((o) => o.trim()),
      allowMultiple,
      anonymous,
    })
    // Reset
    setQuestion('')
    setOptions(['', ''])
    setAllowMultiple(false)
    setAnonymous(false)
  }

  const addOption = () => {
    if (options.length >= 8) return
    setOptions([...options, ''])
  }

  const removeOption = (index: number) => {
    if (options.length <= 2) return
    setOptions(options.filter((_, i) => i !== index))
  }

  return (
    <CenteredDialog open={open} onClose={onClose}>
      <div className="pb-4">
        {/* Header */}
        <div className="flex items-center gap-2.5 mb-4">
          <div className="flex h-10 w-10 items-center justify-center rounded-xl bg-primary-100 text-primary-600">
            <BarChart3 size={20} />
          </div>
          <div>
            <h3 className="text-base font-bold text-primary-900">Create Poll</h3>
            <p className="text-xs text-primary-400">Ask your collective a question</p>
          </div>
        </div>

        {/* Question */}
        <div className="mb-4">
          <label htmlFor="poll-question" className="text-xs font-semibold text-primary-600 mb-1 block">
            Question
          </label>
          <input
            id="poll-question"
            type="text"
            value={question}
            onChange={(e) => setQuestion(e.target.value)}
            placeholder="What would you like to ask?"
            maxLength={200}
            className="w-full rounded-xl bg-primary-50/40 px-3.5 py-2.5 text-sm text-primary-800 placeholder:text-primary-400 outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white min-h-11"
          />
        </div>

        {/* Options */}
        <div className="mb-4">
          <label className="text-xs font-semibold text-primary-600 mb-1.5 block">
            Options (min 2, max 8)
          </label>
          <div className="space-y-2">
            {options.map((opt, i) => (
              <div key={i} className="flex items-center gap-2">
                <input
                  type="text"
                  value={opt}
                  onChange={(e) => {
                    const newOpts = [...options]
                    newOpts[i] = e.target.value
                    setOptions(newOpts)
                  }}
                  placeholder={`Option ${i + 1}`}
                  maxLength={100}
                  className="flex-1 rounded-xl bg-primary-50/40 px-3 py-2 text-sm text-primary-800 placeholder:text-primary-400 outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white min-h-11"
                />
                {options.length > 2 && (
                  <button
                    type="button"
                    onClick={() => removeOption(i)}
                    className="flex items-center justify-center min-h-11 min-w-11 rounded-full text-error-400 hover:bg-error-50 active:scale-[0.95] transition-all duration-150 cursor-pointer select-none"
                    aria-label={`Remove option ${i + 1}`}
                  >
                    <Trash2 size={16} />
                  </button>
                )}
              </div>
            ))}
          </div>

          {options.length < 8 && (
            <button
              type="button"
              onClick={addOption}
              className="flex items-center gap-1.5 mt-2 text-xs font-semibold text-primary-500 hover:text-primary-700 active:scale-[0.97] transition-all duration-150 cursor-pointer select-none min-h-11 px-1"
            >
              <Plus size={14} />
              Add option
            </button>
          )}
        </div>

        {/* Toggles */}
        <div className="space-y-3 mb-5">
          <label className="flex items-center gap-3 cursor-pointer select-none min-h-11">
            <input
              type="checkbox"
              checked={allowMultiple}
              onChange={(e) => setAllowMultiple(e.target.checked)}
              className="h-5 w-5 rounded text-primary-600 focus:ring-primary-400 accent-primary-600"
            />
            <span className="text-sm text-primary-700">Allow multiple votes</span>
          </label>
          <label className="flex items-center gap-3 cursor-pointer select-none min-h-11">
            <input
              type="checkbox"
              checked={anonymous}
              onChange={(e) => setAnonymous(e.target.checked)}
              className="h-5 w-5 rounded text-primary-600 focus:ring-primary-400 accent-primary-600"
            />
            <span className="text-sm text-primary-700">Anonymous voting</span>
          </label>
        </div>

        {/* Submit */}
        <Button
          variant="primary"
          size="lg"
          fullWidth
          onClick={handleSubmit}
          disabled={!canSubmit || loading}
          loading={loading}
        >
          Post Poll
        </Button>
      </div>
    </CenteredDialog>
  )
}

import { type ReactNode } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion, useReducedMotion } from 'framer-motion'
import { ArrowLeft } from 'lucide-react'
import { cn } from '@/lib/cn'

interface HeaderProps {
  title: string
  back?: boolean
  onBack?: () => void
  rightActions?: ReactNode
  transparent?: boolean
  className?: string
}

export function Header({
  title,
  back = false,
  onBack,
  rightActions,
  transparent = false,
  className,
}: HeaderProps) {
  const navigate = useNavigate()
  const shouldReduceMotion = useReducedMotion()

  const handleBack = () => {
    if (onBack) {
      onBack()
    } else {
      navigate(-1)
    }
  }

  // No back button and no right actions → nothing to render
  if (!back && !rightActions) return null

  return (
    <div
      className={cn(
        'sticky top-0 z-40',
        'px-4',
        className,
      )}
      style={{
        paddingTop: 'var(--safe-top)',
      }}
      aria-label={`${title} page header`}
    >
      <div className="flex items-center h-14">
        {/* Left zone: back button */}
        <div className="flex items-center shrink-0 w-10">
          {back && (
            <motion.button
              type="button"
              onClick={handleBack}
              whileTap={shouldReduceMotion ? undefined : { scale: 0.9 }}
              transition={{ type: 'spring', stiffness: 500, damping: 30 }}
              className={cn(
                'flex items-center justify-center',
                'w-11 h-11 -ml-1 rounded-full',
                'text-primary-800 hover:bg-primary-50/80',
                'cursor-pointer select-none',
                'transition-colors duration-150',
                'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary-400',
              )}
              aria-label="Go back"
            >
              <ArrowLeft size={22} />
            </motion.button>
          )}
        </div>

        {/* Center zone: spacer */}
        <div className="flex-1 min-w-0" />

        {/* Right zone: actions */}
        <div className="flex items-center shrink-0 gap-1 justify-end">
          {rightActions}
        </div>
      </div>
    </div>
  )
}

import {
  type ReactNode,
  forwardRef,
  useState,
  useId,
  useRef,
  useCallback,
} from 'react'
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion'
import { Search, Eye, EyeOff } from 'lucide-react'
import { cn } from '@/lib/cn'

type InputType = 'text' | 'email' | 'password' | 'search' | 'textarea' | 'date' | 'tel' | 'number'

export interface InputProps {
  type?: InputType
  label?: string
  compact?: boolean
  value?: string
  defaultValue?: string
  onChange?: React.ChangeEventHandler<HTMLInputElement | HTMLTextAreaElement>
  onBlur?: React.FocusEventHandler<HTMLInputElement | HTMLTextAreaElement>
  onFocus?: React.FocusEventHandler<HTMLInputElement | HTMLTextAreaElement>
  error?: string
  helperText?: string
  disabled?: boolean
  required?: boolean
  placeholder?: string
  name?: string
  autoComplete?: string
  rows?: number
  icon?: ReactNode
  className?: string
  /** Extra classes merged onto the <input>/<textarea> element itself (e.g. bg override). */
  inputClassName?: string
  'aria-label'?: string
  maxLength?: number
  max?: string
  min?: string
}

export const Input = forwardRef<
  HTMLInputElement | HTMLTextAreaElement,
  InputProps
>(function Input(
  {
    type = 'text',
    label,
    value,
    defaultValue,
    onChange,
    onBlur,
    onFocus,
    error,
    helperText,
    disabled = false,
    required = false,
    placeholder,
    name,
    autoComplete,
    rows = 4,
    icon,
    className,
    inputClassName,
    'aria-label': ariaLabel,
  },
  ref,
) {
  const id = useId()
  const errorId = `${id}-error`
  const helperId = `${id}-helper`
  const shouldReduceMotion = useReducedMotion()

  const [focused, setFocused] = useState(false)
  const [uncontrolledFilled, setUncontrolledFilled] = useState(
    () => !!(value ?? defaultValue),
  )
  const filled = value !== undefined ? value.length > 0 : uncontrolledFilled
  const [showPassword, setShowPassword] = useState(false)

  const internalRef = useRef<HTMLInputElement | HTMLTextAreaElement | null>(null)

  const setRef = useCallback(
    (node: HTMLInputElement | HTMLTextAreaElement | null) => {
      internalRef.current = node
      if (typeof ref === 'function') ref(node)
      else if (ref) (ref as React.MutableRefObject<typeof node>).current = node
    },
    [ref],
  )

  const handleFocus = useCallback(
    (e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      setFocused(true)
      onFocus?.(e)
    },
    [onFocus],
  )

  const handleBlur = useCallback(
    (e: React.FocusEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      setFocused(false)
      const val = e.currentTarget.value
      setUncontrolledFilled(val.length > 0)
      onBlur?.(e)
    },
    [onBlur],
  )

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      setUncontrolledFilled(e.currentTarget.value.length > 0)
      onChange?.(e)
    },
    [onChange],
  )

  const isDate = type === 'date'
  const isFloating = focused || filled || isDate
  const isTextarea = type === 'textarea'
  const isSearch = type === 'search'
  const isPassword = type === 'password'
  const inputType = isPassword ? (showPassword ? 'text' : 'password') : type

  const sharedClasses = cn(
    'peer w-full rounded-lg px-4 pt-7 pb-2',
    inputClassName ?? 'bg-white',
    'text-[16px] leading-normal text-primary-800',
    'outline-none transition-all duration-150',
    'disabled:opacity-50 disabled:cursor-not-allowed',
    (isSearch || icon) && 'pl-10',
    isPassword && 'pr-12',
    error
      ? 'ring-2 ring-error focus:ring-error'
      : 'focus:ring-2 focus:ring-primary-500',
  )

  const labelMotion = {
    initial: false as const,
    animate: {
      y: isFloating ? -2 : 10,
      scale: isFloating ? 0.75 : 1,
      originX: 0,
    },
    transition: shouldReduceMotion
      ? { duration: 0 }
      : { type: 'spring', stiffness: 400, damping: 30 },
  }

  const describedBy = [
    error ? errorId : null,
    helperText && !error ? helperId : null,
  ]
    .filter(Boolean)
    .join(' ') || undefined

  return (
    <div className={cn('w-full', className)}>
      <div className="relative">
        {/* Search icon */}
        {isSearch && (
          <Search
            size={18}
            className="absolute left-3 top-1/2 -translate-y-1/2 text-primary-400 pointer-events-none"
            aria-hidden="true"
          />
        )}

        {/* Custom icon */}
        {icon && !isSearch && (
          <span className="absolute left-3 top-1/2 -translate-y-1/2 text-primary-400 pointer-events-none">
            {icon}
          </span>
        )}

        {isTextarea ? (
          <textarea
            ref={setRef as React.Ref<HTMLTextAreaElement>}
            id={id}
            name={name}
            rows={rows}
            value={value}
            defaultValue={defaultValue}
            onChange={handleChange}
            onFocus={handleFocus}
            onBlur={handleBlur}
            disabled={disabled}
            required={required}
            autoComplete={autoComplete}
            placeholder={focused ? placeholder : undefined}
            aria-label={ariaLabel}
            aria-invalid={!!error}
            aria-describedby={describedBy}
            className={cn(sharedClasses, 'resize-y min-h-[100px]')}
          />
        ) : (
          <input
            ref={setRef as React.Ref<HTMLInputElement>}
            id={id}
            type={isTextarea ? undefined : inputType}
            name={name}
            value={value}
            defaultValue={defaultValue}
            onChange={handleChange}
            onFocus={handleFocus}
            onBlur={handleBlur}
            disabled={disabled}
            required={required}
            autoComplete={autoComplete}
            placeholder={focused ? placeholder : undefined}
            aria-label={ariaLabel}
            aria-invalid={!!error}
            aria-describedby={describedBy}
            className={sharedClasses}
          />
        )}

        {/* Floating label */}
        <motion.label
          htmlFor={id}
          {...(labelMotion as any)}
          className={cn(
            'absolute left-4 top-3 pointer-events-none',
            'text-[16px] leading-normal origin-left',
            (isSearch || icon) && 'left-10',
            error ? 'text-error' : focused ? 'text-primary-400' : 'text-primary-400',
          )}
        >
          {label}
          {required && <span className="text-error ml-0.5">*</span>}
        </motion.label>

        {/* Password toggle */}
        {isPassword && (
          <button
            type="button"
            onClick={() => setShowPassword((p) => !p)}
            aria-label={showPassword ? 'Hide password' : 'Show password'}
            className={cn(
              'absolute right-1 top-1/2 -translate-y-1/2',
              'min-w-11 min-h-11 flex items-center justify-center',
              'rounded-xl text-primary-400 hover:text-primary-800',
              'cursor-pointer select-none',
              'active:scale-[0.97] transition-all duration-150',
              'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary-400',
            )}
          >
            {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
          </button>
        )}
      </div>

      {/* Error / helper text */}
      <AnimatePresence mode="wait">
        {error ? (
          <motion.p
            key="error"
            id={errorId}
            role="alert"
            initial={shouldReduceMotion ? false : { opacity: 0, y: -4 }}
            animate={{ opacity: 1, y: 0 }}
            exit={shouldReduceMotion ? undefined : { opacity: 0, y: -4 }}
            transition={{ duration: 0.15 }}
            className="mt-1.5 text-caption text-error"
          >
            {error}
          </motion.p>
        ) : helperText ? (
          <motion.p
            key="helper"
            id={helperId}
            initial={shouldReduceMotion ? false : { opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={shouldReduceMotion ? undefined : { opacity: 0 }}
            transition={{ duration: 0.15 }}
            className="mt-1.5 text-caption text-primary-400"
          >
            {helperText}
          </motion.p>
        ) : null}
      </AnimatePresence>
    </div>
  )
})

import { type ReactElement, useRef, useEffect, useState } from 'react'
import { useLocation, useOutlet } from 'react-router-dom'

const MAX_CACHED = 5

interface CachedPage {
  /** Pathname used as cache key (without search/hash) */
  path: string
  /** The frozen outlet element for this route */
  element: ReactElement
}

/**
 * Keeps the last N route outlets alive in the DOM (hidden) so that
 * navigating back renders instantly with no re-mount or data refetch.
 *
 * Only the active route is visible - cached routes are hidden via
 * CSS `display: none` which preserves scroll position, DOM state,
 * and React component state (including hooks / query caches).
 */
export function KeepAlive() {
  const location = useLocation()
  const outlet = useOutlet()
  const path = location.pathname

  // Stable cache - survives re-renders
  const cacheRef = useRef<CachedPage[]>([])
  const [, forceUpdate] = useState(0)

  useEffect(() => {
    if (!outlet) return

    const cache = cacheRef.current
    const existingIdx = cache.findIndex((c) => c.path === path)

    if (existingIdx >= 0) {
      // Move to end (most recently visited) and update element
      const [entry] = cache.splice(existingIdx, 1)
      entry.element = outlet as ReactElement
      cache.push(entry)
    } else {
      // New entry - evict oldest if over limit
      if (cache.length >= MAX_CACHED) {
        cache.shift()
      }
      cache.push({ path, element: outlet as ReactElement })
    }

    forceUpdate((n) => n + 1)
  }, [path, outlet])

  return (
    <>
      {cacheRef.current.map((cached) => (
        <div
          key={cached.path}
          className="flex-1 flex flex-col min-h-0"
          style={{ display: cached.path === path ? undefined : 'none' }}
        >
          {cached.element}
        </div>
      ))}
    </>
  )
}

