/* ------------------------------------------------------------------ */
/*  LeaderLayout  route-level layout, renders <Outlet />              */
/* ------------------------------------------------------------------ */

export function LeaderLayout() {
  const location = useLocation()
  const { collectiveRoles } = useAuth()
  const { navMode } = useLayout()
  const showBottomTabs = navMode === 'bottom-tabs'
  const [header, setHeaderState] = useState<LeaderHeaderState>({ title: '' })
  const scrollRef = useRef<HTMLDivElement>(null)

  // Get user's primary collective where they are leader
  const collectiveId = useMemo(() => {
    const membership = collectiveRoles.find(
      (m) => ['leader', 'co_leader', 'assist_leader'].includes(m.role),
    )
    return membership?.collective_id
  }, [collectiveRoles])

  const { data: collectiveDetail } = useCollective(collectiveId)
  const collectiveSlug = collectiveDetail?.slug ?? collectiveId
  const collectiveNameRaw = collectiveDetail?.name ?? 'My Collective'
  // Strip trailing "Collective" - e.g. "Byron Bay Collective" → "Byron Bay"
  const collectiveName = collectiveNameRaw.replace(/\s+Collective$/i, '')

  // Scroll content to top on route change
  useEffect(() => {
    scrollRef.current?.scrollTo({ top: 0, behavior: 'smooth' })
  }, [location.pathname])

  const setHeader = useCallback((opts: LeaderHeaderState) => {
    setHeaderState((prev) => {
      // Skip state update if nothing changed - prevents cascading re-renders
      if (
        prev.title === opts.title &&
        prev.subtitle === opts.subtitle &&
        prev.fullBleed === opts.fullBleed &&
        prev.actions === opts.actions &&
        prev.heroContent === opts.heroContent
      ) return prev
      return opts
    })
  }, [])

  const headerCtx = useMemo(() => ({ setHeader, collectiveId, collectiveSlug }), [setHeader, collectiveId, collectiveSlug])

  return (
    <LeaderHeaderContext.Provider value={headerCtx}>
      <div className="flex flex-1 min-h-0">
        {/* Desktop sidebar is handled by UnifiedSidebar in AppShell */}

        {/* Mobile drawer + hamburger removed - handled by UnifiedSidebar in AppShell */}

        {/* ── Main content ── */}
        <div ref={scrollRef} className={cn(
          'flex-1 flex flex-col min-w-0 min-h-0 bg-surface-1',
          showBottomTabs && 'overflow-y-auto overscroll-none',
        )}>
          {/* Shared hero bar - only for non-fullBleed pages */}
          {!header.fullBleed && header.title ? (() => {
            const cfg = PAGE_HERO_CONFIG[header.title] ?? DEFAULT_HERO
            const subtitle = header.subtitle ?? cfg.defaultSubtitle
            const shapes = LEADER_FORMATIONS[cfg.f % LEADER_FORMATIONS.length]
            return (
              <div
                className={cn(
                  'relative overflow-hidden',
                  'bg-gradient-to-br',
                  cfg.hue,
                  'px-6 pt-12 pb-14 sm:px-8 sm:pt-16 sm:pb-16',
                  'before:absolute before:inset-x-0 before:bottom-full before:h-[200px] before:bg-inherit',
                )}
              >
                {/* Decorative shapes - unique formation per page */}
                {shapes.map((s, i) => (
                  <div key={i} className={cn('pointer-events-none', s.className)} />
                ))}

                <div className="relative z-10">
                  <div className="flex items-end justify-between gap-4 flex-wrap">
                    <div>
                      <h1 className="font-heading text-2xl sm:text-3xl font-bold text-white tracking-tight">
                        {header.title}
                      </h1>
                      {subtitle && (
                        <p className="mt-1 text-sm text-white/50">{subtitle}</p>
                      )}
                    </div>
                    {header.actions && (
                      <div className="flex items-center gap-2 shrink-0">{header.actions}</div>
                    )}
                  </div>

                  {header.heroContent && (
                    <div className="mt-5">{header.heroContent}</div>
                  )}
                </div>

                {/* Wave divider */}
                <div className="absolute bottom-0 left-0 right-0 z-20">
                  <svg
                    viewBox="0 0 1440 70"
                    preserveAspectRatio="none"
                    className="w-full h-7 sm:h-10 block"
                    xmlns="http://www.w3.org/2000/svg"
                  >
                    <path d={WAVE_PATHS[cfg.w % WAVE_PATHS.length]} className="fill-surface-1" />
                  </svg>
                </div>
              </div>
            )
          })() : null}

          {/* Content rendered by nested <Route> children */}
          <div className={cn(
            'relative flex-1 overflow-clip',
            header.fullBleed ? 'p-0' : 'p-6',
            !header.fullBleed && 'bg-gradient-to-b from-moss-50/40 via-white to-primary-50/20',
            showBottomTabs && 'pb-[calc(5rem+var(--safe-bottom))]',
          )}>

            <Suspense fallback={null}>
              <Outlet />
            </Suspense>
          </div>
        </div>

        {/* Leader bottom tab bar - mobile only */}
        {showBottomTabs && (
          <LeaderBottomTabs />
        )}
      </div>
    </LeaderHeaderContext.Provider>
  )
}

import { useEffect, useRef } from 'react'
import L from 'leaflet'
import 'leaflet/dist/leaflet.css'
import 'leaflet-draw/dist/leaflet.draw.css'
import 'leaflet-draw'
import { cn } from '@/lib/cn'
import type { MapCenter } from './map-view'

/* ------------------------------------------------------------------ */
/*  Styles                                                             */
/* ------------------------------------------------------------------ */

const STYLE_ID = 'coexist-draw-overrides'

function injectDrawStyles() {
  if (document.getElementById(STYLE_ID)) return
  const style = document.createElement('style')
  style.id = STYLE_ID
  style.textContent = `
    .leaflet-draw-toolbar a { border-radius: 6px !important; }
    .leaflet-draw-actions a { border-radius: 4px !important; }
  `
  document.head.appendChild(style)
}

/* ------------------------------------------------------------------ */
/*  Props                                                              */
/* ------------------------------------------------------------------ */

export interface AreaGeoJSON {
  type: 'Feature'
  geometry: {
    type: 'Polygon' | 'Circle'
    coordinates: number[][] | number[][][]
  }
  properties: { radius?: number }
}

interface LeafletDrawMapProps {
  center?: MapCenter
  zoom?: number
  onAreaChange?: (area: AreaGeoJSON | null) => void
  className?: string
  'aria-label'?: string
}

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

const TILE_URL = 'https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png'
const TILE_ATTR = '&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'

export default function LeafletDrawMap({
  center = { lat: -33.8688, lng: 151.2093 },
  zoom = 14,
  onAreaChange,
  className,
  'aria-label': ariaLabel = 'Draw area on map',
}: LeafletDrawMapProps) {
  const containerRef = useRef<HTMLDivElement>(null)
  const mapRef = useRef<L.Map | null>(null)
  const onAreaChangeRef = useRef(onAreaChange)
  onAreaChangeRef.current = onAreaChange

  useEffect(() => {
    if (!containerRef.current || mapRef.current) return
    injectDrawStyles()

    const map = L.map(containerRef.current, {
      center: [center.lat, center.lng],
      zoom,
      attributionControl: true,
    })

    L.tileLayer(TILE_URL, { attribution: TILE_ATTR, maxZoom: 19 }).addTo(map)

    const drawnItems = new L.FeatureGroup()
    map.addLayer(drawnItems)

    const drawControl = new L.Control.Draw({
      position: 'topright',
      draw: {
        polygon: {
          allowIntersection: false,
          showArea: true,
          shapeOptions: { color: '#4a7c59', fillColor: '#4a7c59', fillOpacity: 0.15, weight: 2 },
        },
        circle: {
          shapeOptions: { color: '#4a7c59', fillColor: '#4a7c59', fillOpacity: 0.15, weight: 2 },
        },
        rectangle: {
          shapeOptions: { color: '#4a7c59', fillColor: '#4a7c59', fillOpacity: 0.15, weight: 2 },
        },
        polyline: false,
        marker: false,
        circlemarker: false,
      },
      edit: {
        featureGroup: drawnItems,
        remove: true,
      },
    })

    map.addControl(drawControl)

    function emitArea() {
      const layers = drawnItems.getLayers()
      if (layers.length === 0) {
        onAreaChangeRef.current?.(null)
        return
      }

      const last = layers[layers.length - 1]
      const geoJSON = (last as L.Polygon | L.Circle).toGeoJSON() as AreaGeoJSON

      // For circles, include the radius in properties
      if (last instanceof L.Circle) {
        geoJSON.properties = { radius: last.getRadius() }
      }

      onAreaChangeRef.current?.(geoJSON)
    }

    map.on(L.Draw.Event.CREATED, ((e: L.DrawEvents.Created) => {
      // Only keep one shape at a time
      drawnItems.clearLayers()
      drawnItems.addLayer(e.layer)
      emitArea()
    }) as any)

    map.on(L.Draw.Event.EDITED, () => emitArea())
    map.on(L.Draw.Event.DELETED, () => emitArea())

    mapRef.current = map

    requestAnimationFrame(() => map.invalidateSize())

    return () => {
      map.remove()
      mapRef.current = null
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  // Update center
  useEffect(() => {
    mapRef.current?.setView([center.lat, center.lng], zoom)
  }, [center.lat, center.lng, zoom])

  return (
    <div
      role="region"
      aria-label={ariaLabel}
      className={cn('relative w-full overflow-hidden rounded-2xl bg-white', className)}
    >
      <div ref={containerRef} className="h-full w-full min-h-[250px]" style={{ zIndex: 0 }} />
    </div>
  )
}

import {
  useState,
  useRef,
  useCallback,
  useEffect,
} from 'react'
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion'
import {
  SendHorizontal,
  Paperclip,
  Plus,
  BarChart3,
  Megaphone,
  Bell,
  X,
} from 'lucide-react'
import { cn } from '@/lib/cn'
import { containsProfanity } from '@/lib/profanity'

interface MessageInputProps {
  onSend: (message: string) => void
  onAttach?: () => void
  onTyping?: () => void
  placeholder?: string
  disabled?: boolean
  className?: string
  'aria-label'?: string
  initialValue?: string
  onValueChange?: (value: string) => void
  maxLength?: number
  padForTabBar?: boolean
  /** Show leader action buttons (poll, announce, invite, broadcast) */
  isLeader?: boolean
  onCreatePoll?: () => void
  onCreateAnnouncement?: () => void
  onCreateEventInvite?: () => void
  onBroadcastNotification?: () => void
}

export function MessageInput({
  onSend,
  onAttach,
  onTyping,
  placeholder = 'Type a message...',
  disabled = false,
  className,
  'aria-label': ariaLabel = 'Message input',
  initialValue = '',
  onValueChange,
  maxLength = 4000,
  padForTabBar = false,
  isLeader = false,
  onCreatePoll,
  onCreateAnnouncement,
  onCreateEventInvite,
  onBroadcastNotification,
}: MessageInputProps) {
  const shouldReduceMotion = useReducedMotion()
  const [value, setValue] = useState(initialValue)
  const [showLeaderActions, setShowLeaderActions] = useState(false)
  const [profanityWarning, setProfanityWarning] = useState(false)

  // Sync when initialValue changes (e.g. entering edit mode)
  useEffect(() => {
    setValue(initialValue)
  }, [initialValue])
  const textareaRef = useRef<HTMLTextAreaElement>(null)
  const hasText = value.trim().length > 0

  const adjustHeight = useCallback(() => {
    const textarea = textareaRef.current
    if (!textarea) return
    textarea.style.height = 'auto'
    const lineHeight = 24
    const maxHeight = lineHeight * 4
    textarea.style.height = `${Math.min(textarea.scrollHeight, maxHeight)}px`
  }, [])

  useEffect(() => {
    adjustHeight()
  }, [value, adjustHeight])

  const handleSend = useCallback(() => {
    const trimmed = value.trim()
    if (!trimmed || disabled) return

    if (containsProfanity(trimmed)) {
      setProfanityWarning(true)
      setTimeout(() => setProfanityWarning(false), 4000)
      return
    }

    onSend(trimmed)
    setValue('')
    setProfanityWarning(false)
    requestAnimationFrame(() => {
      if (textareaRef.current) {
        textareaRef.current.style.height = 'auto'
      }
    })
  }, [value, disabled, onSend])

  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault()
        handleSend()
      }
    },
    [handleSend],
  )

  const handleChange = useCallback(
    (e: React.ChangeEvent<HTMLTextAreaElement>) => {
      const newVal = maxLength ? e.target.value.slice(0, maxLength) : e.target.value
      setValue(newVal)
      onValueChange?.(newVal)
      onTyping?.()
    },
    [maxLength, onValueChange, onTyping],
  )

  const leaderActions = [
    { icon: BarChart3, label: 'Poll', onClick: onCreatePoll, color: 'text-white bg-primary-600 shadow-md' },
    { icon: Megaphone, label: 'Announce', onClick: onCreateAnnouncement, color: 'text-white bg-accent-600 shadow-md' },
    { icon: Bell, label: 'Push Alert', onClick: onBroadcastNotification, color: 'text-white bg-warning-600 shadow-md' },
  ]

  return (
    <div
      className={cn(
        'z-10 bg-white shadow-[0_-2px_12px_0_rgb(0_0_0/0.08)] border-t border-primary-100/50',
        className,
      )}
      style={{
        paddingBottom: padForTabBar
          ? 'calc(3.5rem + var(--safe-bottom, 0px) + 0.75rem)'
          : 'calc(var(--safe-bottom, 0px) + 0.75rem)',
      }}
    >
      {/* Leader actions panel */}
      <AnimatePresence>
        {showLeaderActions && isLeader && (
          <motion.div
            initial={shouldReduceMotion ? { opacity: 0 } : { opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={shouldReduceMotion ? { opacity: 0 } : { opacity: 0, height: 0 }}
            transition={{ duration: 0.2, ease: 'easeOut' }}
            className="bg-primary-50/60 px-3 py-3"
          >
            <div className="flex items-center gap-1.5 mb-1.5">
              <p className="text-[11px] font-extrabold uppercase tracking-wider text-primary-600 flex-1">
                Leader Actions
              </p>
              <button
                type="button"
                onClick={() => setShowLeaderActions(false)}
                className="flex items-center justify-center min-h-11 min-w-11 rounded-full text-primary-400 hover:bg-primary-100 active:scale-[0.95] transition-all duration-150 cursor-pointer select-none"
                aria-label="Close actions"
              >
                <X size={14} />
              </button>
            </div>
            <div className="flex gap-2">
              {leaderActions.map((action) => (
                <button
                  key={action.label}
                  type="button"
                  onClick={() => {
                    action.onClick?.()
                    setShowLeaderActions(false)
                  }}
                  disabled={!action.onClick}
                  className={cn(
                    'flex flex-1 flex-col items-center gap-1 rounded-xl py-2.5 px-1',
                    'transition-all duration-150 active:scale-[0.95] cursor-pointer select-none min-h-11',
                    action.color,
                    'hover:shadow-sm',
                    !action.onClick && 'opacity-40 cursor-default',
                  )}
                >
                  <action.icon size={18} />
                  <span className="text-[11px] font-semibold leading-tight text-center">
                    {action.label}
                  </span>
                </button>
              ))}
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Profanity warning */}
      <AnimatePresence>
        {profanityWarning && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            exit={{ opacity: 0, height: 0 }}
            transition={{ duration: 0.2, ease: 'easeOut' }}
            className="px-3 pt-2"
          >
            <div className="flex items-center gap-2 rounded-xl bg-warning-100 px-3.5 py-2.5 border border-warning-200/60">
              <p className="text-xs font-semibold text-warning-800">
                Please keep it friendly! Your message contains language that isn't allowed. Try rephrasing it.
              </p>
              <button
                type="button"
                onClick={() => setProfanityWarning(false)}
                className="flex items-center justify-center min-h-8 min-w-8 rounded-full text-warning-500 hover:bg-warning-200 shrink-0"
                aria-label="Dismiss warning"
              >
                <X size={14} />
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Input bar */}
      <div className="px-3 pt-2">
        <div
          role="toolbar"
          aria-label={ariaLabel}
          className={cn(
            'flex items-end gap-2 rounded-2xl bg-primary-50/60 px-3.5 py-2.5',
            'transition-all duration-200',
            'ring-1 ring-primary-200/50',
            'focus-within:bg-white focus-within:shadow-md focus-within:ring-2 focus-within:ring-primary-400/70',
            disabled && 'opacity-50',
          )}
        >
          {/* Leader plus button */}
          {isLeader && (
            <button
              type="button"
              onClick={() => setShowLeaderActions(!showLeaderActions)}
              disabled={disabled}
              aria-label="Leader actions"
              className={cn(
                'flex-shrink-0 rounded-full min-w-11 min-h-11 flex items-center justify-center',
                'transition-all duration-200',
                showLeaderActions
                  ? 'bg-primary-600 text-white rotate-45'
                  : 'text-primary-400 hover:bg-primary-100 hover:text-primary-600',
                'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary-400',
                'disabled:pointer-events-none',
              )}
            >
              <Plus size={20} aria-hidden="true" />
            </button>
          )}

          {/* Attachment button */}
          {onAttach && (
            <button
              type="button"
              onClick={onAttach}
              disabled={disabled}
              aria-label="Attach file"
              className={cn(
                'flex-shrink-0 rounded-full min-w-11 min-h-11 flex items-center justify-center text-primary-400',
                'transition-colors duration-150',
                'hover:bg-primary-100 hover:text-primary-600',
                'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary-400',
                'disabled:pointer-events-none',
              )}
            >
              <Paperclip size={20} aria-hidden="true" />
            </button>
          )}

          {/* Textarea */}
          <textarea
            ref={textareaRef}
            value={value}
            onChange={handleChange}
            onKeyDown={handleKeyDown}
            placeholder={placeholder}
            disabled={disabled}
            rows={1}
            maxLength={maxLength}
            aria-label="Message text"
            className={cn(
              'flex-1 resize-none bg-transparent text-[14px] font-medium text-primary-900',
              'placeholder:text-primary-400 placeholder:font-normal',
              'outline-none',
              'disabled:cursor-not-allowed',
              'leading-6 min-h-11 py-2.5',
            )}
            style={{ maxHeight: 24 * 4 }}
          />

          {/* Send button */}
          <AnimatePresence>
            {hasText && (
              <motion.button
                type="button"
                onClick={handleSend}
                disabled={disabled}
                aria-label="Send message"
                initial={shouldReduceMotion ? { opacity: 1 } : { opacity: 0, scale: 0.5 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={shouldReduceMotion ? { opacity: 0 } : { opacity: 0, scale: 0.5 }}
                transition={{ type: 'spring', stiffness: 500, damping: 30 }}
                className={cn(
                  'flex-shrink-0 rounded-full bg-gradient-to-br from-primary-500 to-primary-700 min-w-11 min-h-11 flex items-center justify-center text-white',
                  'transition-all duration-150',
                  'hover:from-primary-600 hover:to-primary-800',
                  'shadow-lg shadow-primary-300/40',
                  'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary-400 focus-visible:ring-offset-1',
                  'disabled:pointer-events-none disabled:opacity-50',
                )}
              >
                <SendHorizontal size={19} strokeWidth={2.5} aria-hidden="true" />
              </motion.button>
            )}
          </AnimatePresence>
        </div>

      </div>
    </div>
  )
}

