import { type ReactNode, useRef } from 'react'
import { motion, useReducedMotion } from 'framer-motion'
import { useLocation } from 'react-router-dom'

interface PageTransitionProps {
  children: ReactNode
  mode?: 'push' | 'fade'
}

/* ------------------------------------------------------------------ */
/*  First-visit: full slide-up entrance                                */
/* ------------------------------------------------------------------ */

const pushVariants = {
  initial: { opacity: 0.6, y: 6 },
  animate: { opacity: 1, y: 0 },
}

const pushTransition = {
  type: 'spring' as const,
  stiffness: 400,
  damping: 34,
  mass: 0.6,
}

/* ------------------------------------------------------------------ */
/*  Revisit: instant - pages have their own entrance animations        */
/* ------------------------------------------------------------------ */

const revisitVariants = {
  initial: { opacity: 1 },
  animate: { opacity: 1 },
}

const revisitTransition = { duration: 0 }

/* ------------------------------------------------------------------ */
/*  Fade mode (used explicitly)                                        */
/* ------------------------------------------------------------------ */

const fadeVariants = {
  initial: { opacity: 0.7 },
  animate: { opacity: 1 },
}

const fadeTransition = {
  duration: 0.15,
  ease: [0.25, 0.1, 0.25, 1] as const,
}

/* ------------------------------------------------------------------ */
/*  Reduced motion                                                     */
/* ------------------------------------------------------------------ */

const instantVariants = {
  initial: { opacity: 1 },
  animate: { opacity: 1 },
}

const instantTransition = { duration: 0 }

/* ------------------------------------------------------------------ */
/*  Visited path cache - persists for the session                      */
/* ------------------------------------------------------------------ */

const visitedPaths = new Set<string>()

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export function PageTransition({ children, mode = 'push' }: PageTransitionProps) {
  const shouldReduceMotion = useReducedMotion()
  const location = useLocation()
  const path = location.pathname

  // Use path change count as key to re-trigger entry animation
  const genRef = useRef({ path, gen: 0 })
  if (genRef.current.path !== path) {
    genRef.current = { path, gen: genRef.current.gen + 1 }
  }
  const gen = genRef.current.gen

  const isFirstVisit = !visitedPaths.has(path)
  if (!visitedPaths.has(path)) {
    visitedPaths.add(path)
  }

  if (shouldReduceMotion) {
    return (
      <div className="flex-1 flex flex-col min-h-0">
        {children}
      </div>
    )
  }

  if (mode === 'fade') {
    return (
      <motion.div
        key={gen}
        className="flex-1 flex flex-col min-h-0"
        variants={fadeVariants}
        initial="initial"
        animate="animate"
        transition={fadeTransition}
      >
        {children}
      </motion.div>
    )
  }

  // Push mode: full animation on first visit, quick fade on revisit
  const variants = isFirstVisit ? pushVariants : revisitVariants
  const transition = isFirstVisit ? pushTransition : revisitTransition

  return (
    <motion.div
      key={gen}
      className="flex-1 flex flex-col min-h-0"
      variants={variants}
      initial="initial"
      animate="animate"
      transition={transition}
    >
      {children}
    </motion.div>
  )
}

import { type ReactNode, useState, useEffect, startTransition } from 'react'
import { Navigate, useLocation } from 'react-router-dom'
import { useAuth } from '@/hooks/use-auth'
import { useCollectiveRole } from '@/hooks/use-collective-role'
import type { Database } from '@/types/database.types'

type UserRole = Database['public']['Enums']['user_role']
type CollectiveRole = Database['public']['Enums']['collective_role']

const _GLOBAL_RANK: Record<UserRole, number> = {
  participant: 0,
  national_staff: 1,
  national_admin: 2,
  super_admin: 3,
}

/* ------------------------------------------------------------------ */
/*  RequireAuth - redirect to /login if not authenticated              */
/* ------------------------------------------------------------------ */

interface RequireAuthProps {
  children: ReactNode
}

export function RequireAuth({ children }: RequireAuthProps) {
  const { user, profile, isLoading, isSuspended, needsTosAcceptance, onboardingDone } = useAuth()
  const location = useLocation()

  // Safety timeout: if we have a user but profile never arrives,
  // don't hang on a blank screen forever - show the app anyway
  // (onboardingDone flag will prevent false onboarding redirect).
  const [profileTimeout, setProfileTimeout] = useState(false)
  useEffect(() => {
    if (profile || !user) {
      startTransition(() => setProfileTimeout(false))
      return
    }
    const timer = setTimeout(() => startTransition(() => setProfileTimeout(true)), 8000)
    return () => clearTimeout(timer)
  }, [profile, user])

  if (isLoading) {
    return <div className="min-h-dvh bg-white" />
  }

  if (!user) {
    return <Navigate to="/login" state={{ from: location }} replace />
  }

  // Check suspended (uses auth hook which already handles expiry)
  if (isSuspended) {
    return <Navigate to="/suspended" replace />
  }

  // TOS re-acceptance required
  if (needsTosAcceptance && !location.pathname.startsWith('/accept-terms')) {
    return <Navigate to="/accept-terms" replace />
  }

  // Profile not loaded yet - wait rather than flashing onboarding.
  // If we already know onboarding is done (local flag), skip the wait
  // and render children immediately.
  if (!profile && !profileTimeout && !onboardingDone) {
    return <div className="min-h-dvh bg-white" />
  }

  // Redirect to onboarding ONLY if:
  // 1. Profile explicitly says not completed, AND
  // 2. The persistent local flag is not set (prevents re-onboarding on fetch failures)
  if (!onboardingDone && (!profile || !profile.onboarding_completed) && !location.pathname.startsWith('/onboarding')) {
    return <Navigate to="/onboarding" replace />
  }

  return <>{children}</>
}

/* ------------------------------------------------------------------ */
/*  RequireRole - check global role minimum                            */
/* ------------------------------------------------------------------ */

interface RequireRoleProps {
  minRole: UserRole
  children: ReactNode
}

export function RequireRole({ minRole: _minRole, children }: RequireRoleProps) {
  const { user, role: _role, isLoading } = useAuth()
  const location = useLocation()

  if (isLoading) {
    return <div className="min-h-dvh bg-white" />
  }

  // Must be authenticated first
  if (!user) {
    return <Navigate to="/login" state={{ from: location }} replace />
  }

  // TODO: admin guard nullified for dev/testing - re-enable before production
  // if (GLOBAL_RANK[role] < GLOBAL_RANK[minRole]) {
  //   return <Navigate to="/" replace />
  // }

  return <>{children}</>
}

/* ------------------------------------------------------------------ */
/*  RequireCollectiveRole - check collective-specific role              */
/* ------------------------------------------------------------------ */

interface RequireCollectiveRoleProps {
  minRole: CollectiveRole
  collectiveId: string
  children: ReactNode
}

/* ------------------------------------------------------------------ */
/*  RequireCapability - check frontend capability                      */
/* ------------------------------------------------------------------ */

interface RequireCapabilityProps {
  cap: string
  children: ReactNode
}

export function RequireCapability({ cap, children }: RequireCapabilityProps) {
  const { user, hasCapability, isLoading } = useAuth()
  const location = useLocation()

  if (isLoading) {
    return <div className="min-h-dvh bg-white" />
  }

  if (!user) {
    return <Navigate to="/login" state={{ from: location }} replace />
  }

  if (!hasCapability(cap)) {
    return <Navigate to="/admin" replace />
  }

  return <>{children}</>
}

/* ------------------------------------------------------------------ */
/*  RequireCollectiveRole - check collective-specific role              */
/* ------------------------------------------------------------------ */

export function RequireCollectiveRole({
  minRole,
  collectiveId,
  children,
}: RequireCollectiveRoleProps) {
  const { user, isLoading: authLoading } = useAuth()
  const { hasMinRole, isLoading } = useCollectiveRole(collectiveId)
  const location = useLocation()

  if (authLoading || isLoading) {
    return <div className="min-h-dvh bg-white" />
  }

  // Must be authenticated first
  if (!user) {
    return <Navigate to="/login" state={{ from: location }} replace />
  }

  if (!hasMinRole(minRole)) {
    return <Navigate to="/" replace />
  }

  return <>{children}</>
}

import { Link, useLocation } from 'react-router-dom'
import {
  CalendarDays,
  BarChart3,
  Settings,
  Shield,
  ShoppingBag,
  Heart,
  Bell,
  Megaphone,
  Mail,
  Handshake,
  Users,
  Home,
  MessageCircle,
} from 'lucide-react'
import { cn } from '@/lib/cn'
import { useAuth } from '@/hooks/use-auth'
import { Avatar } from '@/components/avatar'
import { SidebarShell, type SidebarNavCategory } from '@/components/sidebar-shell'

const mainCategories: SidebarNavCategory[] = [
  {
    label: 'Main',
    items: [
      { label: 'Home', path: '/', icon: <Home size={17} strokeWidth={1.5} />, desktopOnly: true },
      { label: 'Updates', path: '/announcements', icon: <Megaphone size={17} strokeWidth={1.5} /> },
      { label: 'Events', path: '/events', icon: <CalendarDays size={17} strokeWidth={1.5} /> },
      { label: 'Chat', path: '/chat', icon: <MessageCircle size={17} strokeWidth={1.5} />, desktopOnly: true },
      { label: 'Notifications', path: '/notifications', icon: <Bell size={17} strokeWidth={1.5} /> },
    ],
  },
  {
    label: 'Support',
    items: [
      { label: 'Shop', path: '/shop', icon: <ShoppingBag size={17} strokeWidth={1.5} /> },
      { label: 'Donate', path: '/donate', icon: <Heart size={17} strokeWidth={1.5} /> },
      { label: 'Leadership Opportunities', path: '/leadership', icon: <Users size={17} strokeWidth={1.5} /> },
      { label: 'Our Partners', path: '/partners', icon: <Handshake size={17} strokeWidth={1.5} /> },
      { label: 'Contact Us', path: '/contact', icon: <Mail size={17} strokeWidth={1.5} /> },
    ],
  },
]

interface SidebarNavProps {
  className?: string
}

export function SidebarNav({ className }: SidebarNavProps) {
  const { profile, collectiveRoles, isStaff } = useAuth()
  const location = useLocation()

  const isAnyLeader = collectiveRoles.some(
    (m) => ['leader', 'co_leader', 'assist_leader'].includes(m.role),
  )

  // Build management category dynamically
  const managementItems = [
    ...(isAnyLeader
      ? [{ label: 'Leader Dashboard', path: '/leader', icon: <BarChart3 size={17} strokeWidth={1.5} /> }]
      : []),
    ...(isStaff
      ? [{ label: 'Admin Dashboard', path: '/admin', icon: <Shield size={17} strokeWidth={1.5} /> }]
      : []),
  ]

  const categories: SidebarNavCategory[] = [
    ...mainCategories,
    ...(managementItems.length > 0 ? [{ label: 'Management', items: managementItems }] : []),
  ]

  return (
    <SidebarShell
      ariaLabel="Sidebar navigation"
      categories={categories}
      accent="primary"
      layoutId="sidebar-active"
      className={className}
      footer={(collapsed) => (
        <div className="p-2.5 border-t border-primary-100/40">
          <Link
            to="/profile"
            className={cn(
              'flex items-center gap-3 min-w-0',
              'rounded-xl p-2',
              'transition-all duration-200',
              'cursor-pointer select-none',
              'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary-400',
              collapsed && 'justify-center',
              location.pathname.startsWith('/profile')
                ? 'bg-primary-50 text-primary-800'
                : 'text-primary-500 hover:text-primary-800 hover:bg-primary-50/60',
            )}
            aria-label="View profile"
            title={collapsed ? profile?.display_name || 'Profile' : undefined}
          >
            <Avatar
              src={profile?.avatar_url}
              name={profile?.display_name || ''}
              size="sm"
            />
            {!collapsed && (
              <div className="flex-1 min-w-0">
                <p className="font-heading text-[13px] font-semibold text-primary-800 truncate">
                  {profile?.display_name}
                </p>
                {(profile as any)?.collective_name && (
                  <p className="text-[11px] text-primary-400 truncate">
                    {(profile as any).collective_name}
                  </p>
                )}
              </div>
            )}
          </Link>
        </div>
      )}
    />
  )
}

import { useState, type ReactNode } from 'react'
import { Link, useLocation } from 'react-router-dom'
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion'
import { PanelLeftClose } from 'lucide-react'
import { cn } from '@/lib/cn'
import { APP_NAME } from '@/lib/constants'

/* ------------------------------------------------------------------ */
/*  Shared types                                                       */
/* ------------------------------------------------------------------ */

export interface SidebarNavItem {
  label: string
  path: string
  icon: ReactNode
  /** Only show this item on md+ screens (desktop sidebar) */
  desktopOnly?: boolean
}

export interface SidebarNavCategory {
  label: string
  items: SidebarNavItem[]
}

export interface SidebarShellProps {
  /** Unique aria-label for the <aside> */
  ariaLabel: string
  /** Navigation categories to render */
  categories: SidebarNavCategory[]
  /** Accent color family for active/hover states */
  accent?: 'primary' | 'moss'
  /** Unique layoutId prefix for the active indicator animation */
  layoutId: string
  /** Content rendered between the wordmark and the nav list (badges, "back to app", etc.) */
  header?: (collapsed: boolean) => ReactNode
  /** Content rendered in the footer area above the collapse button (profile link, etc.) */
  footer?: (collapsed: boolean) => ReactNode
  /** Additional className on the <aside> */
  className?: string
  /** Hide on mobile, show on md+ (admin/leader pattern). Default false. */
  hideOnMobile?: boolean
}

/* ------------------------------------------------------------------ */
/*  Widths - identical across all suites                               */
/* ------------------------------------------------------------------ */

const EXPANDED_WIDTH = 'w-[240px]'
const COLLAPSED_WIDTH = 'w-[60px]'

/* ------------------------------------------------------------------ */
/*  Session-level cache - only stagger on first mount per suite        */
/* ------------------------------------------------------------------ */

const mountedSuites = new Set<string>()

/** True once *any* sidebar has mounted - used to skip wordmark entry animation on suite switches */
let anySidebarMounted = false

/* ------------------------------------------------------------------ */
/*  Stagger animation (first mount only)                               */
/* ------------------------------------------------------------------ */

const staggerContainer = {
  hidden: {},
  visible: {
    transition: { staggerChildren: 0.03, delayChildren: 0.06 },
  },
}

const staggerItem = {
  hidden: { opacity: 0, x: -8 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { duration: 0.25, ease: [0.25, 0.1, 0.25, 1] },
  },
}

const headerEnter = {
  hidden: { opacity: 0, y: -4 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.3, ease: [0.25, 0.1, 0.25, 1] },
  },
}

/* ------------------------------------------------------------------ */
/*  Revisit - near-instant fade, no stagger                            */
/* ------------------------------------------------------------------ */

const quickFadeContainer = {
  hidden: {},
  visible: { transition: { duration: 0 } },
}

const quickFadeItem = {
  hidden: { opacity: 0.6 },
  visible: {
    opacity: 1,
    transition: { duration: 0.1 },
  },
}

const quickFadeHeader = {
  hidden: { opacity: 0.6 },
  visible: {
    opacity: 1,
    transition: { duration: 0.1 },
  },
}

/* ------------------------------------------------------------------ */
/*  Reduced motion                                                     */
/* ------------------------------------------------------------------ */

const instantVariants = {
  hidden: { opacity: 1 },
  visible: { opacity: 1 },
}

/* ------------------------------------------------------------------ */
/*  SidebarShell                                                       */
/* ------------------------------------------------------------------ */

export function SidebarShell({
  ariaLabel,
  categories,
  accent = 'primary',
  layoutId,
  header,
  footer,
  className,
  hideOnMobile = false,
}: SidebarShellProps) {
  const location = useLocation()
  const shouldReduceMotion = useReducedMotion()
  const [collapsed, setCollapsed] = useState(false)

  const isActive = (path: string) => {
    if (path === '/' || path === '/admin' || path === '/leader') {
      return location.pathname === path
    }
    return location.pathname.startsWith(path)
  }

  const reduced = !!shouldReduceMotion
  const isFirstMount = !mountedSuites.has(layoutId)
  if (isFirstMount) mountedSuites.add(layoutId)

  // Skip wordmark animation when switching between suites (not cold app load)
  const skipWordmarkAnim = anySidebarMounted
  anySidebarMounted = true

  /* ---- Pick animation set ---- */
  const containerV = reduced ? undefined : isFirstMount ? staggerContainer : quickFadeContainer
  const itemV = reduced ? instantVariants : isFirstMount ? staggerItem : quickFadeItem
  const headerV = reduced ? instantVariants : isFirstMount ? headerEnter : quickFadeHeader

  /* ---- Accent-driven classes ---- */
  const borderColor = accent === 'moss' ? 'border-moss-100/40' : 'border-primary-100/40'
  const dividerColor = accent === 'moss' ? 'bg-moss-100/30' : 'bg-primary-100/30'
  const activeClasses = accent === 'moss'
    ? 'bg-moss-50/70 text-moss-800 font-medium'
    : 'bg-primary-50/80 text-primary-700 font-medium'
  const hoverClasses = accent === 'moss'
    ? 'text-primary-400 hover:bg-moss-50/40 hover:text-moss-700'
    : 'text-primary-400 hover:bg-primary-50/50 hover:text-primary-700'
  const indicatorFrom = accent === 'moss' ? 'from-moss-400' : 'from-primary-500'
  const indicatorTo = accent === 'moss' ? 'to-moss-600' : 'to-primary-700'
  const dotColor = accent === 'moss' ? 'bg-moss-500' : 'bg-primary-600'
  const focusRing = accent === 'moss' ? 'focus-visible:ring-moss-400' : 'focus-visible:ring-primary-400'
  const collapseHover = accent === 'moss'
    ? 'hover:text-primary-600 hover:bg-moss-50/50'
    : 'hover:text-primary-600 hover:bg-primary-50/50'

  return (
    <aside
      className={cn(
        hideOnMobile && 'hidden md:flex',
        !hideOnMobile && 'flex',
        'flex-col',
        'sticky top-0 self-start max-h-dvh z-50',
        'bg-white',
        'border-r',
        borderColor,
        'shadow-[4px_0_24px_-4px_rgba(0,0,0,0.08),8px_0_16px_-8px_rgba(0,0,0,0.04)]',
        'transition-[width] duration-250 ease-in-out',
        collapsed ? COLLAPSED_WIDTH : EXPANDED_WIDTH,
        className,
      )}
      aria-label={ariaLabel}
    >
      {/* ---- Wordmark (identical everywhere - no animation on suite switch) ---- */}
      <div className="flex items-center justify-center px-4 py-4">
        <Link
          to="/"
          className={cn('focus-visible:outline-none focus-visible:ring-2 rounded-md', focusRing)}
          aria-label={`${APP_NAME} home`}
        >
          {skipWordmarkAnim ? (
            <img
              src={collapsed ? '/logos/black-logo-transparent.png' : '/logos/black-wordmark.png'}
              alt={APP_NAME}
              className={cn(collapsed ? 'h-6 w-6 object-contain' : 'h-5 w-auto')}
            />
          ) : (
            <AnimatePresence mode="wait">
              <motion.img
                key={collapsed ? 'icon' : 'wordmark'}
                src={collapsed ? '/logos/black-logo-transparent.png' : '/logos/black-wordmark.png'}
                alt={APP_NAME}
                className={cn(collapsed ? 'h-6 w-6 object-contain' : 'h-5 w-auto')}
                initial={{ opacity: 0, scale: 0.92 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.92 }}
                transition={{ duration: 0.15 }}
              />
            </AnimatePresence>
          )}
        </Link>
      </div>

      {/* ---- Suite-specific header (badges, "back to app", etc.) ---- */}
      <motion.div
        variants={headerV}
        initial="hidden"
        animate="visible"
      >
        {header?.(collapsed)}
      </motion.div>

      {/* ---- Nav categories ---- */}
      <motion.nav
        className="flex-1 overflow-y-auto py-2 px-2"
        variants={containerV}
        initial="hidden"
        animate="visible"
      >
        {categories.map((cat, catIdx) => {
          if (cat.items.length === 0) return null
          const showLabel = catIdx > 0
          return (
            <div key={cat.label}>
              {showLabel && (
                <motion.div variants={itemV}>
                  {!collapsed && (
                    <p className="text-[11px] font-semibold uppercase tracking-[0.08em] text-primary-300 px-2.5 mt-4 mb-1.5">
                      {cat.label}
                    </p>
                  )}
                  {collapsed && <div className={cn('my-2.5 mx-2 h-px', dividerColor)} />}
                </motion.div>
              )}

              <ul className="space-y-0.5">
                {cat.items.map((item) => {
                  const active = isActive(item.path)
                  return (
                    <motion.li key={item.path} variants={itemV} className={item.desktopOnly ? 'hidden md:list-item' : undefined}>
                      <Link
                        to={item.path}
                        onClick={() => window.scrollTo({ top: 0 })}
                        className={cn(
                          'relative flex items-center gap-2.5',
                          'rounded-xl text-[13px]',
                          'transition-colors duration-150',
                          'cursor-pointer select-none',
                          'focus-visible:outline-none focus-visible:ring-2',
                          focusRing,
                          collapsed ? 'justify-center h-9 w-9 mx-auto' : 'px-2.5 h-9',
                          active ? activeClasses : hoverClasses,
                        )}
                        aria-current={active ? 'page' : undefined}
                        title={collapsed ? item.label : undefined}
                      >
                        {/* Active indicator bar */}
                        {active && !collapsed && (
                          <motion.span
                            layoutId={reduced ? undefined : layoutId}
                            className={cn(
                              'absolute left-0 top-1.5 bottom-1.5 w-[3px] rounded-full bg-gradient-to-b',
                              indicatorFrom,
                              indicatorTo,
                            )}
                            transition={{ type: 'spring', stiffness: 400, damping: 30 }}
                          />
                        )}

                        {/* Active dot (collapsed) */}
                        {active && collapsed && (
                          <motion.span
                            layoutId={reduced ? undefined : `${layoutId}-dot`}
                            className={cn(
                              'absolute left-0.5 top-1/2 -translate-y-1/2 w-1 h-1 rounded-full',
                              dotColor,
                            )}
                            transition={{ type: 'spring', stiffness: 400, damping: 30 }}
                          />
                        )}

                        <span
                          className={cn(
                            'flex items-center justify-center shrink-0 transition-transform duration-150',
                            active && 'scale-105',
                          )}
                        >
                          {item.icon}
                        </span>
                        {!collapsed && <span className="truncate">{item.label}</span>}
                      </Link>
                    </motion.li>
                  )
                })}
              </ul>
            </div>
          )
        })}
      </motion.nav>

      {/* ---- Suite-specific footer (profile, etc.) ---- */}
      <motion.div
        variants={headerV}
        initial="hidden"
        animate="visible"
      >
        {footer?.(collapsed)}
      </motion.div>

      {/* ---- Collapse toggle ---- */}
      <motion.div
        className={cn('p-2 border-t', borderColor)}
        variants={headerV}
        initial="hidden"
        animate="visible"
      >
        <button
          type="button"
          onClick={() => setCollapsed((p) => !p)}
          className={cn(
            'flex items-center justify-center gap-2 w-full',
            'h-8 rounded-xl text-[13px]',
            'text-primary-300',
            collapseHover,
            'cursor-pointer select-none',
            'transition-all duration-200',
            'focus-visible:outline-none focus-visible:ring-2',
            focusRing,
          )}
          aria-label={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
        >
          <motion.span
            animate={{ rotate: collapsed ? 180 : 0 }}
            transition={{ type: 'spring', stiffness: 300, damping: 25 }}
            className="flex items-center justify-center"
          >
            <PanelLeftClose size={15} strokeWidth={1.5} />
          </motion.span>
          {!collapsed && <span>Collapse</span>}
        </button>
      </motion.div>
    </aside>
  )
}

import { useRef, useState } from 'react'
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion'
import { cn } from '@/lib/cn'

interface SlotCounterProps {
  value: number
  /** Format with Intl.NumberFormat */
  locale?: string
  className?: string
  /** Prefix like "+" or "$" */
  prefix?: string
  /** Suffix like " pts" */
  suffix?: string
}

/**
 * Slot-machine style counter - old number slides up and out,
 * new number slides up from below.
 * §55.3.5: Points increment.
 */
export function SlotCounter({
  value,
  locale = 'en-AU',
  className,
  prefix = '',
  suffix = '',
}: SlotCounterProps) {
  const shouldReduceMotion = useReducedMotion()
  const prevRef = useRef(value)
  const [displayValue, setDisplayValue] = useState(value)
  const [direction, setDirection] = useState<'up' | 'down'>('up')

  if (value !== prevRef.current) {
    setDirection(value > prevRef.current ? 'up' : 'down')
    setDisplayValue(value)
    prevRef.current = value
  }

  const formatted = new Intl.NumberFormat(locale).format(displayValue)

  if (shouldReduceMotion) {
    return (
      <span className={className} aria-live="polite">
        {prefix}{formatted}{suffix}
      </span>
    )
  }

  const yIn = direction === 'up' ? 20 : -20
  const yOut = direction === 'up' ? -20 : 20

  return (
    <span
      className={cn('inline-flex items-baseline overflow-hidden', className)}
      aria-live="polite"
    >
      {prefix && <span>{prefix}</span>}
      <span className="relative inline-block" style={{ minWidth: '1ch' }}>
        <AnimatePresence mode="popLayout" initial={false}>
          <motion.span
            key={displayValue}
            className="inline-block"
            initial={{ y: yIn, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            exit={{ y: yOut, opacity: 0 }}
            transition={{ type: 'spring', stiffness: 380, damping: 28, mass: 0.7 }}
          >
            {formatted}
          </motion.span>
        </AnimatePresence>
      </span>
      {suffix && <span>{suffix}</span>}
    </span>
  )
}

import { type ReactNode, useEffect, useState, startTransition } from 'react'
import { motion, useReducedMotion } from 'framer-motion'
import { TrendingUp, TrendingDown } from 'lucide-react'
import { cn } from '@/lib/cn'

interface Trend {
  value: number
  direction: 'up' | 'down'
}

interface StatCardProps {
  value: number | string
  label: string
  trend?: Trend
  icon?: ReactNode
  className?: string
  'aria-label'?: string
}

export function useCountUp(target: number, duration: number, enabled: boolean) {
  const [current, setCurrent] = useState(enabled ? 0 : target)

  useEffect(() => {
    if (!enabled) {
      startTransition(() => setCurrent(target))
      return
    }

    const startTime = performance.now()
    let frame: number

    function tick(now: number) {
      const elapsed = now - startTime
      const progress = Math.min(elapsed / duration, 1)
      // Ease-out cubic
      const eased = 1 - Math.pow(1 - progress, 3)
      startTransition(() => setCurrent(Math.round(eased * target)))

      if (progress < 1) {
        frame = requestAnimationFrame(tick)
      }
    }

    frame = requestAnimationFrame(tick)
    return () => cancelAnimationFrame(frame)
  }, [target, duration, enabled])

  return current
}

export function StatCard({
  value,
  label,
  trend,
  icon,
  className,
  'aria-label': ariaLabel,
}: StatCardProps) {
  const shouldReduceMotion = useReducedMotion()
  const isNumeric = typeof value === 'number'
  const displayValue = useCountUp(
    isNumeric ? value : 0,
    1200,
    isNumeric && !shouldReduceMotion,
  )

  return (
    <motion.div
      initial={shouldReduceMotion ? { opacity: 1 } : { opacity: 0, y: 8 }}
      animate={{ opacity: 1, y: 0 }}
      transition={
        shouldReduceMotion
          ? { duration: 0 }
          : { type: 'spring', stiffness: 300, damping: 25 }
      }
      aria-label={ariaLabel ?? `${label}: ${value}`}
      className={cn(
        'rounded-xl shadow-sm p-4',
        'bg-gradient-to-br from-surface-0 to-primary-100/60',
        className,
      )}
    >
      <div className="flex items-start justify-between">
        <div className="flex-1 min-w-0">
          <p className="font-heading text-3xl font-bold text-primary-800 tabular-nums">
            {isNumeric ? displayValue.toLocaleString() : value}
          </p>
          <p className="mt-1 text-sm text-primary-400 truncate">{label}</p>
        </div>
        {icon && (
          <span
            className="flex items-center justify-center shrink-0 ml-3 text-primary-500"
            aria-hidden="true"
          >
            {icon}
          </span>
        )}
      </div>
      {trend && (
        <div
          className={cn(
            'mt-3 inline-flex items-center gap-1 text-sm font-medium',
            trend.direction === 'up' ? 'text-success' : 'text-error',
          )}
          aria-label={`Trend: ${trend.direction === 'up' ? 'up' : 'down'} ${trend.value}%`}
        >
          {trend.direction === 'up' ? (
            <TrendingUp className="w-4 h-4" aria-hidden="true" />
          ) : (
            <TrendingDown className="w-4 h-4" aria-hidden="true" />
          )}
          <span className="tabular-nums">{trend.value}%</span>
        </div>
      )}
    </motion.div>
  )
}

import {
  createContext,
  useContext,
  useCallback,
  useState,
  useRef,
  type ReactNode,
} from 'react'
import { createPortal } from 'react-dom'
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion'
import { CheckCircle, XCircle, Info, AlertTriangle, X } from 'lucide-react'
import { cn } from '@/lib/cn'

/* -------------------------------------------------------------------------- */
/*  Types                                                                     */
/* -------------------------------------------------------------------------- */

type ToastType = 'success' | 'error' | 'info' | 'warning'

interface ToastItem {
  id: string
  type: ToastType
  message: string
  duration: number
}

interface ToastApi {
  success: (message: string, duration?: number) => void
  error: (message: string, duration?: number) => void
  info: (message: string, duration?: number) => void
  warning: (message: string, duration?: number) => void
}

interface ToastContextValue {
  toast: ToastApi
}

/* -------------------------------------------------------------------------- */
/*  Config                                                                    */
/* -------------------------------------------------------------------------- */

const DEFAULT_DURATION = 4000
const MAX_VISIBLE = 5

const typeConfig: Record<
  ToastType,
  { icon: typeof CheckCircle; iconClass: string; barClass: string; bgClass: string }
> = {
  success: {
    icon: CheckCircle,
    iconClass: 'text-primary-400',
    barClass: 'bg-primary-500',
    bgClass: 'bg-surface-0',
  },
  error: {
    icon: XCircle,
    iconClass: 'text-error',
    barClass: 'bg-error',
    bgClass: 'bg-error-50',
  },
  info: {
    icon: Info,
    iconClass: 'text-info',
    barClass: 'bg-info',
    bgClass: 'bg-info-50',
  },
  warning: {
    icon: AlertTriangle,
    iconClass: 'text-warning',
    barClass: 'bg-warning',
    bgClass: 'bg-warning-50',
  },
}

/* -------------------------------------------------------------------------- */
/*  Context                                                                   */
/* -------------------------------------------------------------------------- */

const ToastContext = createContext<ToastContextValue | null>(null)

const noop = () => {}
const noopToast: ToastContextValue = {
  toast: { success: noop, error: noop, info: noop, warning: noop },
}

export function useToast(): ToastContextValue {
  const ctx = useContext(ToastContext)
  // Return no-op during HMR transitions when context may be temporarily null
  return ctx ?? noopToast
}

/* -------------------------------------------------------------------------- */
/*  Provider                                                                  */
/* -------------------------------------------------------------------------- */

interface ToastProviderProps {
  children: ReactNode
  className?: string
}

export function ToastProvider({ children, className }: ToastProviderProps) {
  const [toasts, setToasts] = useState<ToastItem[]>([])
  const idCounter = useRef(0)

  const dismiss = useCallback((id: string) => {
    setToasts((prev) => prev.filter((t) => t.id !== id))
  }, [])

  const add = useCallback(
    (type: ToastType, message: string, duration = DEFAULT_DURATION) => {
      const id = `toast-${++idCounter.current}`
      setToasts((prev) => [{ id, type, message, duration }, ...prev].slice(0, MAX_VISIBLE))

      if (duration > 0) {
        setTimeout(() => dismiss(id), duration)
      }
    },
    [dismiss],
  )

  const toast: ToastApi = {
    success: (msg, dur) => add('success', msg, dur),
    error: (msg, dur) => add('error', msg, dur),
    info: (msg, dur) => add('info', msg, dur),
    warning: (msg, dur) => add('warning', msg, dur),
  }

  return (
    <ToastContext.Provider value={{ toast }}>
      {children}
      {createPortal(
        <div
          className={cn(
            'fixed top-0 inset-x-0 z-[100] flex flex-col items-center gap-2',
            'pointer-events-none px-4',
            className,
          )}
          style={{ paddingTop: 'calc(var(--safe-top, 0px) + 1rem)' }}
          aria-live="polite"
          aria-label="Notifications"
        >
          <AnimatePresence initial={false}>
            {toasts.map((t) => (
              <ToastCard key={t.id} item={t} onDismiss={() => dismiss(t.id)} />
            ))}
          </AnimatePresence>
        </div>,
        document.body,
      )}
    </ToastContext.Provider>
  )
}

/* -------------------------------------------------------------------------- */
/*  Toast card                                                                */
/* -------------------------------------------------------------------------- */

const springTransition = { type: 'spring' as const, damping: 28, stiffness: 340, mass: 0.8 }
const instantTransition = { duration: 0 }

function ToastCard({
  item,
  onDismiss,
}: {
  item: ToastItem
  onDismiss: () => void
}) {
  const { type, message } = item
  const config = typeConfig[type]
  const Icon = config.icon
  const shouldReduceMotion = useReducedMotion()
  const transition = shouldReduceMotion ? instantTransition : springTransition

  return (
    <motion.div
      layout
      role="alert"
      initial={{ opacity: 0, y: -32, scale: 0.96 }}
      animate={{ opacity: 1, y: 0, scale: 1, transition }}
      exit={{
        opacity: 0,
        y: -16,
        scale: 0.97,
        transition: shouldReduceMotion ? instantTransition : { duration: 0.18, ease: [0.4, 0, 0.2, 1] },
      }}
      className={cn(
        'pointer-events-auto w-full max-w-sm gpu-panel',
        'flex items-start gap-3 rounded-xl px-4 py-3 shadow-lg',
        config.bgClass,
      )}
    >
      <Icon size={20} className={cn('shrink-0 mt-0.5', config.iconClass)} aria-hidden="true" />
      <p className="flex-1 text-sm font-medium text-primary-800">{message}</p>
      <button
        onClick={onDismiss}
        className="shrink-0 rounded-full p-0.5 text-primary-400 transition-colors hover:bg-black/5 hover:text-primary-400"
        aria-label="Dismiss notification"
      >
        <X size={16} />
      </button>
    </motion.div>
  )
}

import { type ReactNode, useState, useRef, useEffect } from 'react'
