                size={14}
                className={cn(
                  'text-primary-400 transition-transform duration-150',
                  dropdownOpen && 'rotate-180',
                )}
              />
            </button>

            <AnimatePresence>
              {dropdownOpen && (
                <motion.div
                  initial={{ opacity: 0, scale: 0.95, y: -4 }}
                  animate={{ opacity: 1, scale: 1, y: 0 }}
                  exit={{ opacity: 0, scale: 0.95, y: -4 }}
                  transition={{ duration: 0.15 }}
                  className={cn(
                    'absolute right-0 top-full mt-2',
                    'w-56 py-1.5 rounded-xl',
                    'bg-white',
                    'shadow-lg',
                  )}
                  role="menu"
                >
                  {/* User info */}
                  <div className="px-4 py-3 bg-primary-50/40">
                    <p className="font-heading text-sm font-semibold text-primary-800 truncate">
                      {profile?.display_name}
                    </p>
                    <p className="text-caption text-primary-400 truncate">
                      @{(profile as any)?.handle}
                    </p>
                  </div>

                  <DropdownItem
                    icon={<User size={16} />}
                    label="Profile"
                    onClick={() => navigate('/profile')}
                  />
                  <DropdownItem
                    icon={<TrendingUp size={16} />}
                    label="My Impact"
                    onClick={() => navigate('/profile')}
                  />
                  <DropdownItem
                    icon={<ShoppingBag size={16} />}
                    label="Shop"
                    onClick={() => navigate('/shop')}
                  />
                  <DropdownItem
                    icon={<Heart size={16} />}
                    label="Donate"
                    onClick={() => navigate('/donate')}
                  />
                  <div className="my-1.5 h-px bg-primary-100/40" />
                  <DropdownItem
                    icon={<Settings size={16} />}
                    label="Settings"
                    onClick={() => navigate('/settings')}
                  />
                  {isStaff && (
                    <DropdownItem
                      icon={<Shield size={16} />}
                      label="Admin"
                      onClick={() => navigate('/admin')}
                    />
                  )}
                  <div className="my-1.5 h-px bg-primary-100/40" />
                  <DropdownItem
                    icon={<LogOut size={16} />}
                    label="Log out"
                    onClick={signOut}
                    danger
                  />
                </motion.div>
              )}
            </AnimatePresence>
          </div>
        </div>
      </div>
    </header>
  )
}

function DropdownItem({
  icon,
  label,
  onClick,
  danger = false,
}: {
  icon: ReactNode
  label: string
  onClick: () => void
  danger?: boolean
}) {
  return (
    <button
      type="button"
      role="menuitem"
      onClick={onClick}
      className={cn(
        'flex items-center gap-3 w-full px-4 py-2.5',
        'min-h-11',
        'text-sm text-left',
        'cursor-pointer select-none',
        'active:scale-[0.97] transition-all duration-150',
        'focus-visible:outline-none focus-visible:bg-white',
        danger
          ? 'text-error hover:bg-error-50'
          : 'text-primary-800 hover:bg-primary-50',
      )}
    >
      <span className="flex items-center justify-center shrink-0">{icon}</span>
      {label}
    </button>
  )
}

