export function useAdminKpiDashboard(filters?: {
  collectiveId?: string
  dateFrom?: string
  dateTo?: string
}) {
  return useQuery({
    queryKey: ['admin-kpi-dashboard', filters],
    queryFn: async () => {
      let query = supabase
        .from('task_instances' as any)
        .select('id, collective_id, status, due_date, completed_at, completed_by, template_id, collectives(id, name)')

      if (filters?.collectiveId) {
        query = query.eq('collective_id', filters.collectiveId)
      }
      if (filters?.dateFrom) {
        query = query.gte('due_date', filters.dateFrom)
      }
      if (filters?.dateTo) {
        query = query.lte('due_date', filters.dateTo)
      }

      const { data, error } = await query
      if (error) throw error
      const instances = (data ?? []) as any[]

      // Aggregate per collective
      const byCollective = new Map<string, { name: string; total: number; completed: number; overdue: number }>()
      const now = new Date()

      for (const inst of instances) {
        const cId = inst.collective_id
        const cName = inst.collectives?.name ?? 'Unknown'
        if (!byCollective.has(cId)) {
          byCollective.set(cId, { name: cName, total: 0, completed: 0, overdue: 0 })
        }
        const agg = byCollective.get(cId)!
        agg.total++
        if (inst.status === 'completed') agg.completed++
        if (inst.status === 'pending' && new Date(inst.due_date) < now) agg.overdue++
      }

      const stats: KpiStat[] = Array.from(byCollective.entries()).map(([id, agg]) => ({
        collective_id: id,
        collective_name: agg.name,
        total: agg.total,
        completed: agg.completed,
        overdue: agg.overdue,
        rate: agg.total > 0 ? Math.round((agg.completed / agg.total) * 100) : 0,
      }))

      // Sort by rate ascending (worst first)
      stats.sort((a, b) => a.rate - b.rate)

      // Overall stats
      const totals = {
        total: instances.length,
        completed: instances.filter((i: any) => i.status === 'completed').length,
        overdue: instances.filter((i: any) => i.status === 'pending' && new Date(i.due_date) < now).length,
        rate: instances.length > 0
          ? Math.round((instances.filter((i: any) => i.status === 'completed').length / instances.length) * 100)
          : 0,
      }

      return { stats, totals }
    },
    staleTime: 30 * 1000,
  })
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'
import { logAudit } from '@/lib/audit'
import { resolveCapabilities } from '@/lib/capabilities'
import type { Database } from '@/types/database.types'

type CollectiveRole = Database['public']['Enums']['collective_role']
type UserRole = Database['public']['Enums']['user_role']

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface UserCollectiveRole {
  id: string
  collective_id: string
  role: CollectiveRole
  status: string
  joined_at: string
  collective: {
    id: string
    name: string
    slug: string
    state: string | null
    region: string | null
  }
}

/* ------------------------------------------------------------------ */
/*  useUserCollectiveRoles — all collective memberships for a user     */
/* ------------------------------------------------------------------ */

export function useUserCollectiveRoles(userId: string | undefined) {
  return useQuery({
    queryKey: ['admin-user-collective-roles', userId],
    queryFn: async () => {
      if (!userId) return []
      const { data, error } = await supabase
        .from('collective_members')
        .select('id, collective_id, role, status, joined_at, collectives(id, name, slug, state, region)')
        .eq('user_id', userId)
        .order('role', { ascending: false })

      if (error) throw error
      return (data ?? []).map((row: any) => ({
        id: row.id,
        collective_id: row.collective_id,
        role: row.role as CollectiveRole,
        status: row.status,
        joined_at: row.joined_at,
        collective: row.collectives,
      })) as UserCollectiveRole[]
    },
    enabled: !!userId,
    staleTime: 30 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  useAdminAssignCollectiveRole — add/update user collective role     */
/* ------------------------------------------------------------------ */

export function useAdminAssignCollectiveRole() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async ({
      userId,
      collectiveId,
      role,
    }: {
      userId: string
      collectiveId: string
      role: CollectiveRole
    }) => {
      const { error } = await supabase
        .from('collective_members')
        .upsert(
          {
            user_id: userId,
            collective_id: collectiveId,
            role,
            status: 'active',
          },
          { onConflict: 'collective_id,user_id' },
        )
      if (error) throw error

      if (role === 'leader') {
        await supabase
          .from('collectives')
          .update({ leader_id: userId })
          .eq('id', collectiveId)
      }
      await logAudit({ action: 'member_role_changed', target_type: 'collective_member', target_id: userId, details: { collective_id: collectiveId, new_role: role } })
    },
    onMutate: async (variables) => {
      const key = ['admin-user-collective-roles', variables.userId]
      await queryClient.cancelQueries({ queryKey: key })
      const previous = queryClient.getQueryData<UserCollectiveRole[]>(key)

      queryClient.setQueryData<UserCollectiveRole[]>(key, (old) => {
        if (!old) return old
        const idx = old.findIndex((r) => r.collective_id === variables.collectiveId)
        if (idx >= 0) {
          const updated = [...old]
          updated[idx] = { ...updated[idx], role: variables.role, status: 'active' }
          return updated
        }
        return old
      })

      return { previous }
    },
    onError: (_err, variables, context) => {
      if (context?.previous) {
        queryClient.setQueryData(['admin-user-collective-roles', variables.userId], context.previous)
      }
    },
    onSettled: (_data, _err, variables) => {
      queryClient.invalidateQueries({ queryKey: ['admin-user-collective-roles', variables.userId] })
      queryClient.invalidateQueries({ queryKey: ['admin-collective-members'] })
      queryClient.invalidateQueries({ queryKey: ['admin-collective-detail'] })
    },
  })
}

/* ------------------------------------------------------------------ */
/*  useAdminRemoveFromCollective — remove user from collective         */
/* ------------------------------------------------------------------ */

export function useAdminRemoveFromCollective() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async ({
      userId,
      collectiveId,
    }: {
      userId: string
      collectiveId: string
    }) => {
      const { error } = await supabase
        .from('collective_members')
        .update({ status: 'removed' })
        .eq('user_id', userId)
        .eq('collective_id', collectiveId)
      if (error) throw error
      await logAudit({ action: 'member_removed', target_type: 'collective_member', target_id: userId, details: { collective_id: collectiveId } })
    },
    onMutate: async (variables) => {
      const key = ['admin-user-collective-roles', variables.userId]
      await queryClient.cancelQueries({ queryKey: key })
      const previous = queryClient.getQueryData<UserCollectiveRole[]>(key)

      queryClient.setQueryData<UserCollectiveRole[]>(key, (old) =>
        old?.map((r) =>
          r.collective_id === variables.collectiveId ? { ...r, status: 'removed' } : r,
        ),
      )

      return { previous }
    },
    onError: (_err, variables, context) => {
      if (context?.previous) {
        queryClient.setQueryData(['admin-user-collective-roles', variables.userId], context.previous)
      }
    },
    onSettled: (_data, _err, variables) => {
      queryClient.invalidateQueries({ queryKey: ['admin-user-collective-roles', variables.userId] })
      queryClient.invalidateQueries({ queryKey: ['admin-collective-members'] })
    },
  })
}

/* ------------------------------------------------------------------ */
/*  useAdminUpdateCapabilities — update staff_roles.permissions        */
/* ------------------------------------------------------------------ */

export function useAdminUpdateCapabilities() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async ({
      userId,
      permissions,
    }: {
      userId: string
      permissions: Record<string, boolean>
    }) => {
      const { error } = await supabase
        .from('staff_roles' as any)
        .upsert(
          { user_id: userId, permissions },
          { onConflict: 'user_id' },
        )
      if (error) throw error
    },
    onMutate: async (variables) => {
      const key = ['admin-user-resolved-caps', variables.userId]
      await queryClient.cancelQueries({ queryKey: key })
      const previous = queryClient.getQueryData(key)

      queryClient.setQueryData(key, (old: any) => {
        if (!old) return old
        const newCaps = resolveCapabilities(old.role, variables.permissions)
        return { ...old, overrides: variables.permissions, capabilities: newCaps }
      })

      return { previous }
    },
    onError: (_err, variables, context) => {
      if (context?.previous) {
        queryClient.setQueryData(['admin-user-resolved-caps', variables.userId], context.previous)
      }
    },
    onSettled: (_data, _err, variables) => {
      queryClient.invalidateQueries({ queryKey: ['admin-user-resolved-caps', variables.userId] })
      queryClient.invalidateQueries({ queryKey: ['staff-permissions'] })
      queryClient.invalidateQueries({ queryKey: ['admin-staff-directory'] })
    },
  })
}

/* ------------------------------------------------------------------ */
/*  useUserResolvedCapabilities — fetch and resolve caps for any user  */
/* ------------------------------------------------------------------ */

export function useUserResolvedCapabilities(userId: string | undefined) {
  return useQuery({
    queryKey: ['admin-user-resolved-caps', userId],
    queryFn: async () => {
      if (!userId) return { role: 'participant' as UserRole, overrides: {} as Record<string, boolean>, capabilities: new Set<string>() }

      const [profileRes, staffRes] = await Promise.all([
        supabase.from('profiles').select('role').eq('id', userId).single(),
        supabase.from('staff_roles' as any).select('permissions').eq('user_id', userId).maybeSingle(),
      ])

      const role = (profileRes.data?.role ?? 'participant') as UserRole
      const overrides = ((staffRes.data as any)?.permissions as Record<string, boolean>) ?? {}
      const capabilities = resolveCapabilities(role, overrides)

      return { role, overrides, capabilities }
    },
    enabled: !!userId,
    staleTime: 30 * 1000,
  })
}

import { useQuery } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'

/** All configurable image slot keys */
export type AppImageKey =
  | 'home_hero'
  | 'shop_hero'
  | 'placeholder_event'
  | 'placeholder_merch'
  | 'hero_welcome'
  | 'hero_download'
  | 'placeholder_collective'
  | 'onboarding_bg'
  | 'email_header'

interface AppImageRow {
  key: AppImageKey
  url: string
  label: string
}

/** Static fallbacks used when no admin image is configured */
const FALLBACKS: Record<AppImageKey, string> = {
  home_hero: '',
  shop_hero: '',
  placeholder_event: '/img/placeholder-event.jpg',
  placeholder_merch: '/img/placeholder-merch.jpg',
  hero_welcome: '/img/hero-welcome.jpg',
  hero_download: '/img/hero-download.jpg',
  placeholder_collective: '',
  onboarding_bg: '',
  email_header: '',
}

/**
 * Fetch all app images and return a map of key → url.
 * Falls back to static assets when a slot has no configured URL.
 * Cached for 10 minutes — images change rarely.
 */
export function useAppImages() {
  const query = useQuery({
    queryKey: ['app-images'],
    queryFn: async () => {
      const { data, error } = await (supabase as any)
        .from('app_images')
        .select('key, url, label')
      if (error) throw error

      const map: Record<string, string> = { ...FALLBACKS }
      for (const row of (data ?? []) as unknown as AppImageRow[]) {
        if (row.url) map[row.key] = row.url
      }
      return map
    },
    staleTime: 10 * 60 * 1000,
  })

  return query
}

/**
 * Get a single app image URL with fallback.
 * Convenience wrapper — prefer useAppImages() when you need multiple.
 */
export function useAppImage(key: AppImageKey): string {
  const { data } = useAppImages()
  return data?.[key] || FALLBACKS[key]
}

import { useEffect, useState } from 'react'
import { supabase } from '@/lib/supabase'

const APP_VERSION = '1.0.0'

interface UpdateStatus {
  updateAvailable: boolean
  latestVersion: string | null
  forceUpdate: boolean
  maintenanceMode: boolean
  maintenanceMessage?: string
}

/**
 * Checks for app updates and maintenance mode via Supabase config.
 * §42 items 66-67.
 */
export function useAppUpdate(): UpdateStatus {
  const [status, setStatus] = useState<UpdateStatus>({
    updateAvailable: false,
    latestVersion: null,
    forceUpdate: false,
    maintenanceMode: false,
  })

  useEffect(() => {
    let cancelled = false

    async function check() {
      try {
        const { data, error } = await supabase
          .from('feature_flags')
          .select('key, enabled, value')
          .in('key', [
            'app_min_version',
            'app_latest_version',
            'maintenance_mode',
            'maintenance_message',
          ])

        if (error || !data || cancelled) return

        const flags: Record<string, { enabled: boolean; value: string | null }> = {}
        for (const row of data as any[]) {
          flags[row.key] = { enabled: row.enabled, value: row.value }
        }

        const latest = flags['app_latest_version']?.value ?? APP_VERSION
        const minVersion = flags['app_min_version']?.value ?? '0.0.0'
        const maintenance = flags['maintenance_mode']?.enabled === true

        setStatus({
          updateAvailable: compareVersions(APP_VERSION, latest) < 0,
          latestVersion: latest,
          forceUpdate: compareVersions(APP_VERSION, minVersion) < 0,
          maintenanceMode: maintenance,
          maintenanceMessage: flags['maintenance_message']?.value ?? undefined,
        })
      } catch (err) {
        // Log but don't block - missing table or network blip shouldn't lock users out
        console.warn('[app-update] check failed:', err)
      }
    }

    check()
    // Re-check every 5 minutes
    const interval = setInterval(check, 5 * 60 * 1000)
    return () => {
      cancelled = true
      clearInterval(interval)
    }
  }, [])

  return status
}

/** Simple semver comparison: returns -1, 0, or 1 */
function compareVersions(a: string, b: string): number {
  const pa = a.split('.').map(Number)
  const pb = b.split('.').map(Number)

  for (let i = 0; i < 3; i++) {
    const va = pa[i] ?? 0
    const vb = pb[i] ?? 0
    if (va < vb) return -1
    if (va > vb) return 1
  }
  return 0
}

import { useState, useEffect, useCallback, useMemo, createContext, useContext } from 'react'
import type { User, Session, AuthError } from '@supabase/supabase-js'
import { Capacitor } from '@capacitor/core'
import { Preferences } from '@capacitor/preferences'
import { supabase } from '@/lib/supabase'
import { resolveCapabilities } from '@/lib/capabilities'
import type { Database } from '@/types/database.types'

type Profile = Database['public']['Tables']['profiles']['Row']
type UserRole = Database['public']['Enums']['user_role']
type CollectiveRole = Database['public']['Enums']['collective_role']

/* ------------------------------------------------------------------ */
/*  Role hierarchy helpers                                             */
/* ------------------------------------------------------------------ */

const GLOBAL_ROLE_RANK: Record<UserRole, number> = {
  participant: 0,
  national_staff: 1,
  national_admin: 2,
  super_admin: 3,
}

const COLLECTIVE_ROLE_RANK: Record<CollectiveRole, number> = {
  member: 0,
  assist_leader: 1,
  co_leader: 2,
  leader: 3,
}

/* ------------------------------------------------------------------ */
/*  Capacitor persistence helpers                                      */
/* ------------------------------------------------------------------ */

const STORAGE_KEY = 'coexist-auth-session'
const PROFILE_STORAGE_KEY = 'coexist-auth-profile'
const ONBOARDING_DONE_KEY = 'coexist-onboarding-done'

async function persistSession(session: Session | null) {
  if (!Capacitor.isNativePlatform()) return
  if (session) {
    await Preferences.set({ key: STORAGE_KEY, value: JSON.stringify(session) })
  } else {
    await Preferences.remove({ key: STORAGE_KEY })
  }
}

async function restoreSession(): Promise<Session | null> {
  if (!Capacitor.isNativePlatform()) return null
  const { value } = await Preferences.get({ key: STORAGE_KEY })
  if (!value) return null
  try {
    return JSON.parse(value) as Session
  } catch {
    return null
  }
}

/** Lightweight flag that survives even when profile fetch fails */
function markOnboardingDone() {
  try {
    localStorage.setItem(ONBOARDING_DONE_KEY, '1')
  } catch { /* non-critical */ }
  if (Capacitor.isNativePlatform()) {
    Preferences.set({ key: ONBOARDING_DONE_KEY, value: '1' }).catch(() => {})
  }
}

function getOnboardingDoneSync(): boolean {
  try {
    return localStorage.getItem(ONBOARDING_DONE_KEY) === '1'
  } catch {
    return false
  }
}

async function persistProfile(profile: Profile | null) {
  try {
    if (profile) {
      await Preferences.set({ key: PROFILE_STORAGE_KEY, value: JSON.stringify(profile) })
    } else {
      await Preferences.remove({ key: PROFILE_STORAGE_KEY })
    }
  } catch {
    // Non-critical — worst case user sees a brief loading state
  }
}

async function restoreProfile(): Promise<Profile | null> {
  try {
    const { value } = await Preferences.get({ key: PROFILE_STORAGE_KEY })
    if (!value) return null
    return JSON.parse(value) as Profile
  } catch {
    return null
  }
}

/* ------------------------------------------------------------------ */
/*  Auth context types                                                 */
/* ------------------------------------------------------------------ */

interface AuthContextValue {
  user: User | null
  profile: Profile | null
  session: Session | null
  role: UserRole
  collectiveRoles: CollectiveMembership[]
  isLoading: boolean
  isSuspended: boolean
  suspendedReason: string | null
  suspendedUntil: string | null
  needsTosAcceptance: boolean
  isLeader: (collectiveId: string) => boolean
  isAssistLeader: (collectiveId: string) => boolean
  isCoLeader: (collectiveId: string) => boolean
  capabilities: Set<string>
  hasCapability: (key: string) => boolean
  isStaff: boolean
  isAdmin: boolean
  isSuperAdmin: boolean
  signUp: (email: string, password: string, displayName: string, dateOfBirth?: string) => Promise<{ error: AuthError | null }>
  signIn: (email: string, password: string) => Promise<{ error: AuthError | null }>
  signInWithGoogle: () => Promise<{ error: AuthError | null }>
  signInWithApple: () => Promise<{ error: AuthError | null }>
  signInWithMagicLink: (email: string) => Promise<{ error: AuthError | null }>
  signOut: () => Promise<void>
  resetPassword: (email: string) => Promise<{ error: AuthError | null }>
  updatePassword: (newPassword: string) => Promise<{ error: AuthError | null }>
  refreshProfile: () => Promise<void>
  acceptTos: (version: string) => Promise<void>
  onboardingDone: boolean
  markOnboardingComplete: () => void
}

const CURRENT_TOS_VERSION = '1.0'

const AuthContext = createContext<AuthContextValue | null>(null)

/* ------------------------------------------------------------------ */
/*  Provider hook (internal)                                           */
/* ------------------------------------------------------------------ */

interface CollectiveMembership {
  collective_id: string
  role: CollectiveRole
}

export function useAuthProvider(): AuthContextValue {
  const [user, setUser] = useState<User | null>(null)
  const [profile, setProfile] = useState<Profile | null>(null)
  const [session, setSession] = useState<Session | null>(null)
  const [collectiveRoles, setCollectiveRoles] = useState<CollectiveMembership[]>([])
  const [permissionOverrides, setPermissionOverrides] = useState<Record<string, boolean> | null>(null)
  const [isLoading, setIsLoading] = useState(true)
  const [onboardingDone, setOnboardingDone] = useState(getOnboardingDoneSync)

  /* ---- fetch profile ---- */
  const fetchProfile = useCallback(async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .maybeSingle()
      if (error) {
        console.error('[auth] fetchProfile error:', error.message, error.code)
        return null
      }
      return data
    } catch (err) {
      console.error('[auth] fetchProfile exception:', err)
      return null
    }
  }, [])

  /* ---- fetch staff permission overrides ---- */
  const fetchPermissionOverrides = useCallback(async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('staff_roles' as any)
        .select('permissions')
        .eq('user_id', userId)
        .maybeSingle()
      if (error) return null
      return (data as any)?.permissions as Record<string, boolean> | null
    } catch {
      return null
    }
  }, [])

  /* ---- fetch collective memberships ---- */
  const fetchCollectiveRoles = useCallback(async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('collective_members')
        .select('collective_id, role')
        .eq('user_id', userId)
        .eq('status', 'active')
      if (error) {
        console.error('[auth] fetchCollectiveRoles error:', error.message, error.code)
        return []
      }
      return data ?? []
    } catch (err) {
      console.error('[auth] fetchCollectiveRoles exception:', err)
      return []
    }
  }, [])

  /* ---- load user data (profile + collective roles) ---- */
  const loadUserData = useCallback(async (userId: string) => {
    console.log('[auth] loadUserData start', userId)
    const timeout = new Promise<[null, CollectiveMembership[], Record<string, boolean> | null]>((resolve) =>
      setTimeout(() => {
        console.warn('[auth] loadUserData timed out after 8s')
        resolve([null, [], null])
      }, 8000),
    )
    const [profileData, roles, permOverrides] = await Promise.race([
      Promise.all([
        fetchProfile(userId),
        fetchCollectiveRoles(userId),
        fetchPermissionOverrides(userId),
      ]),
      timeout,
    ])
    console.log('[auth] loadUserData done', { hasProfile: !!profileData, rolesCount: roles.length })

    // If no profile row exists, it likely means the fetch timed out or
    // the auth trigger hasn't fired yet. Retry once before creating.
    if (!profileData) {
      console.warn('[auth] No profile found - retrying fetch once')
      const retried = await fetchProfile(userId)
      if (retried) {
        console.log('[auth] Profile found on retry')
        setProfile(retried)
        setCollectiveRoles(roles)
        setPermissionOverrides(permOverrides)
        persistProfile(retried)
        if (retried.onboarding_completed) { markOnboardingDone(); setOnboardingDone(true) }
        return retried
      }

      console.warn('[auth] Still no profile - creating one')
      try {
        const { data: authUser } = await supabase.auth.getUser()
        const meta = authUser?.user?.user_metadata
        const { data: created, error: createErr } = await supabase
          .from('profiles')
          .upsert({
            id: userId,
            display_name: meta?.display_name ?? meta?.full_name ?? meta?.email?.split('@')[0] ?? 'New User',
            avatar_url: meta?.avatar_url ?? null,
          }, { onConflict: 'id' })
          .select('*')
          .single()
        if (createErr) {
          console.error('[auth] Profile create/upsert error:', createErr.message, createErr.code)
        }
        if (created) {
          console.log('[auth] Profile created successfully')
          setProfile(created)
          setCollectiveRoles(roles)
          setPermissionOverrides(permOverrides)
          persistProfile(created)
          if (created.onboarding_completed) { markOnboardingDone(); setOnboardingDone(true) }
          return created
        }
      } catch (err) {
        console.error('[auth] Failed to create profile:', err)
      }
    }

    // Check suspension server-side (the RPC handles expiry clearance securely)
    if (profileData?.is_suspended) {
      try {
        const { data: suspCheck } = await supabase.rpc('check_user_suspended' as any, { uid: userId })
        if (suspCheck && !(suspCheck as any).suspended) {
          // Server cleared the expired suspension - refresh profile data
          profileData.is_suspended = false
          profileData.suspended_reason = null
          profileData.suspended_until = null
        }
      } catch {
        // If RPC fails, keep the client-side suspended state as-is
      }
    }

    // Check if account is pending deletion and user logged back in (recovery)
    // Use server-side RPC to handle this securely instead of direct client update
    if ((profileData as any)?.deletion_status === 'pending_deletion') {
      try {
        await supabase.rpc('recover_pending_deletion' as any, { uid: userId })
        ;(profileData as any).deletion_status = 'active'
        ;(profileData as any).deleted_at = null
        ;(profileData as any).deletion_requested_at = null
      } catch {
        // If RPC doesn't exist yet, the account stays pending - server wins
      }
    }

    setProfile(profileData)
    setCollectiveRoles(roles)
    setPermissionOverrides(permOverrides)
    persistProfile(profileData)
    if (profileData?.onboarding_completed) { markOnboardingDone(); setOnboardingDone(true) }
    return profileData
  }, [fetchProfile, fetchCollectiveRoles, fetchPermissionOverrides])

  /* ---- refresh profile (public) ---- */
  const refreshProfile = useCallback(async () => {
    if (!user) return
    await loadUserData(user.id)
  }, [user, loadUserData])

  /* ---- init: restore session + subscribe ---- */
  useEffect(() => {
    let mounted = true

    // Immediately seed cached profile so the route guard never flashes
    // onboarding while we wait for Supabase auth to resolve.
    restoreProfile().then((cached) => {
      if (cached && mounted) {
        console.log('[auth] restored cached profile')
        setProfile(cached)
        if (cached.onboarding_completed) { markOnboardingDone(); setOnboardingDone(true) }
      }
    })

    // For native: restore the persisted session and set it on the client.
    // This triggers onAuthStateChange SIGNED_IN which handles everything.
    if (Capacitor.isNativePlatform()) {
      restoreSession().then(async (restored) => {
        if (restored) {
          await supabase.auth.setSession(restored)
        }
        // If no restored session, onAuthStateChange INITIAL_SESSION
        // will fire with null — handled below.
      })
    }

    // Let onAuthStateChange be the single source of truth for auth state.
    // This avoids the getSession() timeout / lock deadlock issues.
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (event, newSession) => {
        console.log('[auth] onAuthStateChange:', event, !!newSession)
        if (!mounted) return

        setSession(newSession)
        setUser(newSession?.user ?? null)
        persistSession(newSession)

        if (newSession?.user) {
          const userId = newSession.user.id
          // Defer loadUserData — calling it inside onAuthStateChange can
          // deadlock because the Supabase JS client holds an internal auth
          // lock during token recovery, blocking any fetch that needs auth.
          setTimeout(async () => {
            if (!mounted) return
            try {
              console.log('[auth] loadUserData start (deferred)', userId)
              await loadUserData(userId)
            } catch (err) {
              console.error('[auth] loadUserData failed:', err)
            } finally {
              if (mounted) {
                console.log('[auth] setting isLoading=false')
                setIsLoading(false)
              }
            }
          }, 0)
        } else {
          setProfile(null)
          setCollectiveRoles([])
          setPermissionOverrides(null)
          persistProfile(null)
          setIsLoading(false)
        }
      },
    )

    // Safety: if nothing fires within 10s, unblock the UI.
    const safety = setTimeout(() => {
      if (mounted) {
        console.warn('[auth] safety timeout - forcing isLoading=false')
        setIsLoading(false)
      }
    }, 10000)

    return () => {
      mounted = false
      clearTimeout(safety)
      subscription.unsubscribe()
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [])

  /* ---- collective role checkers ---- */
  const getCollectiveRole = useCallback(
    (collectiveId: string): CollectiveRole | null => {
      const membership = collectiveRoles.find((m) => m.collective_id === collectiveId)
      return membership?.role ?? null
    },
    [collectiveRoles],
  )

  const isLeader = useCallback(
    (collectiveId: string) => getCollectiveRole(collectiveId) === 'leader',
    [getCollectiveRole],
  )

  const isAssistLeader = useCallback(
    (collectiveId: string) => {
      const role = getCollectiveRole(collectiveId)
      return role !== null && COLLECTIVE_ROLE_RANK[role] >= COLLECTIVE_ROLE_RANK.assist_leader
    },
    [getCollectiveRole],
  )

  const isCoLeader = useCallback(
    (collectiveId: string) => {
      const role = getCollectiveRole(collectiveId)
      return role !== null && COLLECTIVE_ROLE_RANK[role] >= COLLECTIVE_ROLE_RANK.co_leader
    },
    [getCollectiveRole],
  )

  /* ---- global role checks ---- */
  const role = profile?.role ?? 'participant'
  const isStaff = GLOBAL_ROLE_RANK[role] >= GLOBAL_ROLE_RANK.national_staff
  const isAdmin = GLOBAL_ROLE_RANK[role] >= GLOBAL_ROLE_RANK.national_admin
  const isSuperAdmin = role === 'super_admin'

  /* ---- capabilities (frontend-only gating) ---- */
  const capabilities = useMemo(
    () => resolveCapabilities(role, permissionOverrides),
    [role, permissionOverrides],
  )

  const hasCapability = useCallback(
    (key: string) => capabilities.has(key),
    [capabilities],
  )

  /* ---- suspended / TOS checks ---- */
  const isSuspended = profile?.is_suspended ?? false
  const suspendedReason = profile?.suspended_reason ?? null
  const suspendedUntil = profile?.suspended_until ?? null
  const needsTosAcceptance = !!profile && profile.tos_accepted_version !== CURRENT_TOS_VERSION

  const markOnboardingComplete = useCallback(() => {
    markOnboardingDone()
    setOnboardingDone(true)
  }, [])

  const acceptTos = useCallback(async (version: string) => {
    if (!user) return
    // Only allow accepting the current TOS version to prevent future-version bypass
    if (version !== CURRENT_TOS_VERSION) return
    await supabase
      .from('profiles')
      .update({ tos_accepted_version: version, tos_accepted_at: new Date().toISOString() })
      .eq('id', user.id)
    await loadUserData(user.id)
  }, [user, loadUserData])

  /* ---- auth actions ---- */
  const signUp = useCallback(async (email: string, password: string, displayName: string, dateOfBirth?: string) => {
    const { error, data } = await supabase.auth.signUp({
      email,
      password,
      options: { data: { display_name: displayName, date_of_birth: dateOfBirth } },
    })

    // Send welcome email on successful signup
    if (!error && data.user) {
      supabase.functions.invoke('send-email', {
        body: {
          type: 'welcome',
          to: email,
          data: {
            name: displayName,
            app_url: 'https://app.coexistaus.org',
          },
        },
      }).catch(console.error)
    }

    return { error }
  }, [])

  const signIn = useCallback(async (email: string, password: string) => {
    const { error } = await supabase.auth.signInWithPassword({ email, password })
    return { error }
  }, [])

  const signInWithGoogle = useCallback(async () => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: { redirectTo: window.location.origin },
    })
    return { error }
  }, [])

  const signInWithApple = useCallback(async () => {
    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'apple',
      options: { redirectTo: window.location.origin },
    })
    return { error }
  }, [])

  const signInWithMagicLink = useCallback(async (email: string) => {
    const { error } = await supabase.auth.signInWithOtp({
      email,
      options: { emailRedirectTo: window.location.origin },
    })
    return { error }
  }, [])

  const signOut = useCallback(async () => {
    await supabase.auth.signOut()
    await persistSession(null)
    await persistProfile(null)
    // Clear onboarding flag so a different user gets a fresh start
    try { localStorage.removeItem(ONBOARDING_DONE_KEY) } catch { /* */ }
    if (Capacitor.isNativePlatform()) {
      Preferences.remove({ key: ONBOARDING_DONE_KEY }).catch(() => {})
    }
    setOnboardingDone(false)
  }, [])

  const resetPassword = useCallback(async (email: string) => {
    const { error } = await supabase.auth.resetPasswordForEmail(email, {
      redirectTo: `${window.location.origin}/reset-password`,
    })
    return { error }
  }, [])

  const updatePassword = useCallback(async (newPassword: string) => {
    const { error } = await supabase.auth.updateUser({ password: newPassword })
    return { error }
  }, [])

  return useMemo(
    () => ({
      user,
      profile,
      session,
      role,
      collectiveRoles,
      capabilities,
      hasCapability,
      isLoading,
      isSuspended,
      suspendedReason,
      suspendedUntil,
      needsTosAcceptance,
      isLeader,
      isAssistLeader,
      isCoLeader,
      isStaff,
      isAdmin,
      isSuperAdmin,
      signUp,
      signIn,
      signInWithGoogle,
      signInWithApple,
      signInWithMagicLink,
      signOut,
      resetPassword,
      updatePassword,
      refreshProfile,
      acceptTos,
      onboardingDone,
      markOnboardingComplete,
    }),
    [
      user, profile, session, role, collectiveRoles, capabilities, hasCapability,
      isLoading, isSuspended, suspendedReason, suspendedUntil, needsTosAcceptance,
      isLeader, isAssistLeader, isCoLeader, isStaff, isAdmin, isSuperAdmin,
      signUp, signIn, signInWithGoogle, signInWithApple, signInWithMagicLink,
      signOut, resetPassword, updatePassword, refreshProfile, acceptTos,
      onboardingDone, markOnboardingComplete,
    ],
  )
}

