      return collectiveId
    },
    onMutate: async ({ messageId, content, collectiveId }) => {
      await queryClient.cancelQueries({ queryKey: ['chat-messages', collectiveId] })
      const previous = queryClient.getQueryData(['chat-messages', collectiveId])
