      if (context?.previous) queryClient.setQueryData(['chat-messages', collectiveId], context.previous)
    },
    onSettled: (collectiveId) => {
      queryClient.invalidateQueries({ queryKey: ['chat-messages', collectiveId] })
    },
  })
