/* ------------------------------------------------------------------ */
/*  Unread count per collective                                        */
/* ------------------------------------------------------------------ */

export function useUnreadCounts() {
  const { user } = useAuth()

  return useQuery({
    queryKey: ['unread-counts', user?.id],
    queryFn: async () => {
      if (!user) return {}

      const { data: memberships } = await supabase
        .from('collective_members')
        .select('collective_id')
        .eq('user_id', user.id)
        .eq('status', 'active')

      if (!memberships?.length) return {}

      const { data: receipts } = await supabase
        .from('chat_read_receipts')
        .select('collective_id, last_read_at')
        .eq('user_id', user.id)

      const receiptMap = new Map(receipts?.map((r) => [r.collective_id, r.last_read_at]) ?? [])
      const counts: Record<string, number> = {}

      for (const m of memberships) {
        const lastRead = receiptMap.get(m.collective_id)
        let query = supabase
          .from('chat_messages')
          .select('*', { count: 'exact', head: true })
          .eq('collective_id', m.collective_id)
          .eq('is_deleted', false)
          .neq('user_id', user.id)

        if (lastRead) {
          query = query.gt('created_at', lastRead)
        }

        const { count } = await query
        counts[m.collective_id] = count ?? 0
      }

      return counts
    },
    enabled: !!user,
    staleTime: 30 * 1000,
    refetchInterval: 60 * 1000,
  })
}

