export function useCreatePoll() {
  const { user } = useAuth()
  const queryClient = useQueryClient()
  const sendMessage = useSendMessage()

  return useMutation({
    mutationFn: async ({
      collectiveId,
      question,
      options,
      allowMultiple = false,
      anonymous = false,
      closesAt,
    }: {
      collectiveId: string
      question: string
      options: string[]
      allowMultiple?: boolean
      anonymous?: boolean
      closesAt?: string
    }) => {
      if (!user) throw new Error('Not authenticated')

      const pollOptions = options.map((text, i) => ({
        id: `opt-${Date.now()}-${i}`,
        text,
      }))

      const { data: poll, error } = await (supabase as any)
        .from('chat_polls')
        .insert({
          collective_id: collectiveId,
          created_by: user.id,
          question,
          options: pollOptions,
          allow_multiple: allowMultiple,
          anonymous,
          closes_at: closesAt ?? null,
        })
        .select()
        .single()

      if (error) throw error

      // Send a poll message in the chat
      await sendMessage.mutateAsync({
        collectiveId,
        content: question,
        messageType: 'poll',
        pollId: (poll as any).id,
      })

      return poll
    },
    onSuccess: (_, input) => {
      queryClient.invalidateQueries({ queryKey: ['chat-polls', input.collectiveId] })
    },
  })
}

