/* ------------------------------------------------------------------ */
/*  Queries - Nearby & Collective Events                               */
/* ------------------------------------------------------------------ */

export function useNearbyEvents(limit = 20) {
  return useQuery({
    queryKey: ['nearby-events', limit],
