/** Collaborations where this collective was invited */
export function useIncomingCollaborations(collectiveId: string | undefined) {
  return useQuery({
    queryKey: ['collaborations-incoming', collectiveId],
    queryFn: async () => {
      if (!collectiveId) return []
      const { data, error } = await supabase
        .from('collective_event_collaborators')
        .select('*, events(id, title, date_start, date_end, activity_type, address), collectives:collective_id(id, name, cover_image_url), invited_by_collective:invited_by_collective_id(id, name)')
        .eq('collective_id', collectiveId)
        .order('created_at', { ascending: false })
      if (error) throw error
      return (data ?? []) as unknown as CollaborationWithDetails[]
    },
    enabled: !!collectiveId,
    staleTime: 2 * 60 * 1000,
  })
}

/** Collaborations this collective sent out */
export function useOutgoingCollaborations(collectiveId: string | undefined) {
  return useQuery({
    queryKey: ['collaborations-outgoing', collectiveId],
    queryFn: async () => {
      if (!collectiveId) return []
      const { data, error } = await supabase
        .from('collective_event_collaborators')
        .select('*, events(id, title, date_start, date_end, activity_type, address), collectives:collective_id(id, name, cover_image_url)')
        .eq('invited_by_collective_id', collectiveId)
        .order('created_at', { ascending: false })
      if (error) throw error
      return (data ?? []) as unknown as CollaborationWithDetails[]
    },
    enabled: !!collectiveId,
    staleTime: 2 * 60 * 1000,
  })
}

export function useInviteCollaborator() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async ({
      eventId,
      collectiveId,
      hostCollectiveId,
      message,
    }: {
      eventId: string
      collectiveId: string
      hostCollectiveId: string
      message?: string
    }) => {
      const { data, error } = await supabase.rpc('invite_collective_to_collaborate', {
        p_event_id: eventId,
        p_collective_id: collectiveId,
        p_host_collective_id: hostCollectiveId,
        p_message: message ?? null,
      })
      if (error) throw error
      return data
    },
    onSuccess: (_, vars) => {
      queryClient.invalidateQueries({ queryKey: ['collaborations-outgoing', vars.hostCollectiveId] })
      queryClient.invalidateQueries({ queryKey: ['collaborations-incoming', vars.collectiveId] })
      queryClient.invalidateQueries({ queryKey: ['event', vars.eventId] })
    },
  })
}

export function useRespondToCollaboration() {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async ({
      collaborationId,
      accept,
    }: {
      collaborationId: string
      accept: boolean
      collectiveId?: string
      hostCollectiveId?: string
    }) => {
      const { error } = await supabase.rpc('respond_to_collaboration', {
        p_collaboration_id: collaborationId,
        p_accept: accept,
      })
      if (error) throw error
    },
    onSuccess: (_, vars) => {
      if (vars.collectiveId) {
        queryClient.invalidateQueries({ queryKey: ['collaborations-incoming', vars.collectiveId] })
      }
      if (vars.hostCollectiveId) {
        queryClient.invalidateQueries({ queryKey: ['collaborations-outgoing', vars.hostCollectiveId] })
      }
    },
  })
}

export function getGoogleCalendarUrl(event: Event): string {
  const start = new Date(event.date_start)
  const end = event.date_end ? new Date(event.date_end) : new Date(start.getTime() + 2 * 60 * 60 * 1000)

  const formatGcalDate = (d: Date) =>
    d.toISOString().replace(/[-:]/g, '').replace(/\.\d{3}/, '')

  const params = new URLSearchParams({
    action: 'TEMPLATE',
    text: event.title,
    dates: `${formatGcalDate(start)}/${formatGcalDate(end)}`,
    details: event.description ?? '',
    location: event.address ?? '',
  })

  return `https://calendar.google.com/calendar/render?${params.toString()}`
}

import { useQuery } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/hooks/use-auth'

/* ------------------------------------------------------------------ */
/*  Canonical impact metrics                                           */
/* ------------------------------------------------------------------ */

/** The canonical Co-Exist impact metrics */
export interface CanonicalImpact {
  /* Community Events */
  eventsAttended: number
  volunteerHours: number
  eventsHeld: number
  /* Land Restoration Projects */
  treesPlanted: number
  invasiveWeedsPulled: number
  /* Cleanup Sites */
  rubbishCollectedTonnes: number
  cleanupSites: number
  /* Organisational */
  collectivesCount: number
  leadersEmpowered: number
}

/* ------------------------------------------------------------------ */
/*  National (aggregate) impact                                        */
/* ------------------------------------------------------------------ */

export interface NationalImpact extends CanonicalImpact {
  totalMembers: number
}

type TimeRange = 'all-time' | 'current-year'

export function useNationalImpact(timeRange: TimeRange = 'all-time') {
  return useQuery({
    queryKey: ['national-impact', timeRange],
    queryFn: async (): Promise<NationalImpact> => {
      const yearStart = new Date(new Date().getFullYear(), 0, 1).toISOString()

      let impactQuery = supabase
        .from('event_impact')
        .select('trees_planted, hours_total, rubbish_kg, invasive_weeds_pulled, leaders_trained, event_id')
      if (timeRange === 'current-year') {
        impactQuery = impactQuery.gte('logged_at', yearStart)
      }

      let eventsQuery = supabase
        .from('events')
        .select('id, activity_type', { count: 'exact' })
        .lt('date_start', new Date().toISOString())
      if (timeRange === 'current-year') {
        eventsQuery = eventsQuery.gte('date_start', yearStart)
      }

      // Cleanup events — fetch addresses so we can count unique sites
      let cleanupQuery = supabase
        .from('events')
        .select('id, address')
        .in('activity_type', ['shore_cleanup', 'marine_restoration'] as any)
        .lt('date_start', new Date().toISOString())
      if (timeRange === 'current-year') {
        cleanupQuery = cleanupQuery.gte('date_start', yearStart)
      }

      // Leaders empowered = anyone who holds a leadership role in any collective
      const leadersQuery = supabase
        .from('collective_members')
        .select('user_id')
        .in('role', ['assist_leader', 'co_leader', 'leader'] as any)

      const [impactRes, eventsRes, membersRes, collectivesRes, cleanupRes, leadersRes] = await Promise.all([
        impactQuery,
        eventsQuery,
        supabase.from('profiles').select('id', { count: 'exact', head: true }),
        supabase.from('collectives').select('id', { count: 'exact', head: true }),
        cleanupQuery,
        leadersQuery,
      ])

      const logs = (impactRes.data ?? []) as unknown as Record<string, number>[]
      const sum = (key: string) => logs.reduce((s, r) => s + (r[key] ?? 0), 0)

      // Count event attendances (non-unique sign-ins) across all events with impact
      let attendanceCount = 0
      const impactEventIds = [...new Set(logs.map((l) => l.event_id).filter(Boolean))]
      if (impactEventIds.length > 0) {
        // Batch in chunks to avoid URL length limits
        const chunks = []
        for (let i = 0; i < impactEventIds.length; i += 50) {
          chunks.push(impactEventIds.slice(i, i + 50))
        }
        for (const chunk of chunks) {
          const { count } = await supabase
            .from('event_registrations')
            .select('id', { count: 'exact', head: true })
            .in('event_id', chunk as any)
            .eq('status', 'attended')
          attendanceCount += count ?? 0
        }
      }

      // Count unique cleanup sites by address
      const cleanupAddresses = new Set(
        (cleanupRes.data ?? []).map((e: any) => (e.address ?? '').trim().toLowerCase()).filter(Boolean)
      )

      // Count unique users with leadership roles
      const uniqueLeaders = new Set((leadersRes.data ?? []).map((r: any) => r.user_id))

      return {
        eventsAttended: attendanceCount,
        volunteerHours: Math.round(sum('hours_total')),
        eventsHeld: eventsRes.count ?? 0,
        treesPlanted: sum('trees_planted'),
        invasiveWeedsPulled: sum('invasive_weeds_pulled'),
        rubbishCollectedTonnes: Math.round((sum('rubbish_kg') / 1000) * 100) / 100,
        cleanupSites: cleanupAddresses.size,
        collectivesCount: collectivesRes.count ?? 0,
        leadersEmpowered: uniqueLeaders.size,
        totalMembers: membersRes.count ?? 0,
      }
    },
    staleTime: 5 * 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  Collective impact (for home page toggle)                           */
/* ------------------------------------------------------------------ */

export function useCollectiveImpact(collectiveId: string | undefined, timeRange: TimeRange = 'all-time') {
  return useQuery({
    queryKey: ['collective-impact', collectiveId, timeRange],
    queryFn: async (): Promise<CanonicalImpact | null> => {
      if (!collectiveId) return null
      const yearStart = new Date(new Date().getFullYear(), 0, 1).toISOString()

      let impactQuery = supabase
        .from('event_impact')
        .select('trees_planted, hours_total, rubbish_kg, invasive_weeds_pulled, leaders_trained, event_id, events!inner(collective_id)')
        .eq('events.collective_id' as any, collectiveId)
      if (timeRange === 'current-year') {
        impactQuery = impactQuery.gte('logged_at', yearStart)
      }

      let cleanupQuery = supabase
        .from('events')
        .select('id, address')
        .eq('collective_id', collectiveId)
        .in('activity_type', ['shore_cleanup', 'marine_restoration'] as any)
        .lt('date_start', new Date().toISOString())
      if (timeRange === 'current-year') {
        cleanupQuery = cleanupQuery.gte('date_start', yearStart)
      }

      let eventsQuery = supabase
        .from('events')
        .select('id', { count: 'exact', head: true })
        .eq('collective_id', collectiveId)
        .lt('date_start', new Date().toISOString())
      if (timeRange === 'current-year') {
        eventsQuery = eventsQuery.gte('date_start', yearStart)
      }

      const leadersQuery = supabase
        .from('collective_members')
        .select('user_id')
        .eq('collective_id', collectiveId)
        .in('role', ['assist_leader', 'co_leader', 'leader'] as any)

      const [impactRes, cleanupRes, eventsCountRes, leadersRes] = await Promise.all([impactQuery, cleanupQuery, eventsQuery, leadersQuery])

      const rows = (impactRes.data ?? []) as any[]
      const sum = (key: string) => rows.reduce((s: number, r: any) => s + (r[key] ?? 0), 0)

      // Count event attendances for this collective's events
      const impactEventIds = [...new Set(rows.map((r: any) => r.event_id).filter(Boolean))]
      let attendanceCount = 0
      if (impactEventIds.length > 0) {
        const { count } = await supabase
          .from('event_registrations')
          .select('id', { count: 'exact', head: true })
          .in('event_id', impactEventIds)
          .eq('status', 'attended')
        attendanceCount = count ?? 0
      }

      const cleanupAddresses = new Set(
        (cleanupRes.data ?? []).map((e: any) => (e.address ?? '').trim().toLowerCase()).filter(Boolean)
      )
      const uniqueLeaders = new Set((leadersRes.data ?? []).map((r: any) => r.user_id))

      return {
        eventsAttended: attendanceCount,
        volunteerHours: Math.round(sum('hours_total')),
        eventsHeld: eventsCountRes.count ?? 0,
        treesPlanted: sum('trees_planted'),
        invasiveWeedsPulled: sum('invasive_weeds_pulled'),
        rubbishCollectedTonnes: Math.round((sum('rubbish_kg') / 1000) * 100) / 100,
        cleanupSites: cleanupAddresses.size,
        collectivesCount: 1,
        leadersEmpowered: uniqueLeaders.size,
      }
    },
    enabled: !!collectiveId,
    staleTime: 5 * 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  Per-user impact                                                    */
/* ------------------------------------------------------------------ */

export interface PersonalImpact extends CanonicalImpact {}

export function useImpactStats(userId?: string) {
  const { user } = useAuth()
  const id = userId ?? user?.id

  return useQuery({
    queryKey: ['impact-stats', id],
    queryFn: async (): Promise<PersonalImpact> => {
      if (!id) throw new Error('No user ID')

      const { data: registrations } = await supabase
        .from('event_registrations')
        .select('event_id')
        .eq('user_id', id)
        .eq('status', 'attended')

      const eventIds = registrations?.map((r) => r.event_id) ?? []
      const eventsAttended = eventIds.length

      if (eventIds.length === 0) {
        return {
          eventsAttended: 0,
          volunteerHours: 0,
          eventsHeld: 0,
          treesPlanted: 0,
          invasiveWeedsPulled: 0,
          rubbishCollectedTonnes: 0,
          cleanupSites: 0,
          collectivesCount: 0,
          leadersEmpowered: 0,
        }
      }

      const [impactsRes, cleanupRes, collectivesRes, leadersRes] = await Promise.all([
        supabase
          .from('event_impact')
          .select('*')
          .in('event_id', eventIds),
        supabase
          .from('events')
          .select('id, address')
          .in('id', eventIds)
          .in('activity_type', ['shore_cleanup', 'marine_restoration'] as any),
        supabase
          .from('collective_members')
          .select('collective_id, role')
          .eq('user_id', id),
        supabase
          .from('collective_members')
          .select('user_id')
          .eq('user_id', id)
          .in('role', ['assist_leader', 'co_leader', 'leader'] as any),
      ])

      const impacts = impactsRes.data ?? []
      let totalHours = 0
      let totalTrees = 0
      let totalWeeds = 0
      let totalRubbishKg = 0

      for (const impact of impacts) {
        totalHours += impact.hours_total
        totalTrees += impact.trees_planted
        totalWeeds += impact.invasive_weeds_pulled
        totalRubbishKg += impact.rubbish_kg
      }

      const cleanupAddresses = new Set(
        (cleanupRes.data ?? []).map((e: any) => (e.address ?? '').trim().toLowerCase()).filter(Boolean)
      )

      return {
        eventsAttended,
        volunteerHours: Math.round(totalHours),
        eventsHeld: eventIds.length,
        treesPlanted: totalTrees,
        invasiveWeedsPulled: totalWeeds,
        rubbishCollectedTonnes: Math.round((totalRubbishKg / 1000) * 100) / 100,
        cleanupSites: cleanupAddresses.size,
        collectivesCount: collectivesRes.count ?? 0,
        leadersEmpowered: (leadersRes.data ?? []).length > 0 ? 1 : 0,
      }
    },
    enabled: !!id,
    staleTime: 5 * 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  Monthly activity                                                   */
/* ------------------------------------------------------------------ */

interface MonthlyActivity {
  month: string
  count: number
}

export function useMonthlyActivity(userId?: string) {
  const { user } = useAuth()
  const id = userId ?? user?.id

  return useQuery({
    queryKey: ['monthly-activity', id],
    queryFn: async (): Promise<MonthlyActivity[]> => {
      if (!id) throw new Error('No user ID')

      const { data: registrations } = await supabase
        .from('event_registrations')
        .select('registered_at')
        .eq('user_id', id)
        .eq('status', 'attended')
        .order('registered_at', { ascending: true })

      if (!registrations?.length) return []

      const monthCounts = new Map<string, number>()
      for (const reg of registrations) {
        const date = new Date(reg.registered_at)
        const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`
        monthCounts.set(key, (monthCounts.get(key) ?? 0) + 1)
      }

      return Array.from(monthCounts.entries()).map(([month, count]) => ({
        month,
        count,
      }))
    },
    enabled: !!id,
    staleTime: 10 * 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  Impact by category                                                 */
/* ------------------------------------------------------------------ */

interface ImpactByCategory {
  category: string
  count: number
}

export function useImpactByCategory(userId?: string) {
