}

/* ------------------------------------------------------------------ */
/*  Promo code validation                                              */
/* ------------------------------------------------------------------ */

/* ------------------------------------------------------------------ */
/*  Shipping config                                                    */
/* ------------------------------------------------------------------ */

export function useShippingConfig() {
  return useQuery({
    queryKey: ['shipping-config'],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('shipping_config' as any)
        .select('*')
      if (error) throw error

      const config: ShippingConfig = {
        flat_rate_cents: 995,
        free_shipping_threshold_cents: null,
      }
      for (const row of (data ?? []) as any[]) {
        if (row.key === 'flat_rate_cents') config.flat_rate_cents = parseInt(row.value) || 995
        if (row.key === 'free_shipping_threshold_cents') {
          config.free_shipping_threshold_cents = row.value ? parseInt(row.value) || null : null
        }
      }
      return config
    },
    staleTime: 5 * 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  Promo code validation                                              */
/* ------------------------------------------------------------------ */

/** Validate a promo code (called imperatively) */
export async function validatePromoCode(code: string) {
  const { data, error } = await supabase
    .from('promo_codes')
    .select('*')
    .eq('code', code.toUpperCase().trim())
    .eq('is_active', true)
    .single()

  if (error || !data) return { valid: false, promo: null }

  const now = new Date()
  if (data.valid_to && new Date(data.valid_to) < now) return { valid: false, promo: null }
  if (data.max_uses && data.uses_count >= data.max_uses) return { valid: false, promo: null }

  return { valid: true, promo: data }
}

import { useQuery } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'
import type { Event, Collective } from '@/types/database.types'

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface Location {
  lat: number
  lng: number
}

interface EventWithCollective extends Event {
  collectives: Pick<Collective, 'id' | 'name'> | null
}

/* ------------------------------------------------------------------ */
/*  Nearby events                                                      */
/* ------------------------------------------------------------------ */

export function useNearbyEvents(
  location: Location | null,
  radiusKm: number = 50,
  activityTypes?: string[],
) {
  return useQuery({
    queryKey: ['nearby', 'events', location, radiusKm, activityTypes],
    queryFn: async () => {
      const now = new Date().toISOString()
      let query = supabase
        .from('events')
        .select('*, collectives(id, name)')
        .eq('status', 'published')
        .or(`date_start.gte.${now},date_end.gte.${now}`)
        .order('date_start', { ascending: true })

      if (activityTypes?.length) {
        query = query.in('activity_type', activityTypes as any)
      }

      // If location available, PostGIS distance filter via RPC would be ideal.
      // Fallback: return all published events, sorted by date.
      const { data, error } = await query.limit(20)
      if (error) throw error
      return (data ?? []) as EventWithCollective[]
    },
    staleTime: 5 * 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  Nearby collectives                                                 */
/* ------------------------------------------------------------------ */

export function useNearbyCollectives(
  location: Location | null,
  radiusKm: number = 100,
) {
  return useQuery({
    queryKey: ['nearby', 'collectives', location, radiusKm],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('collectives')
        .select('*')
        .eq('is_active', true)
        .order('member_count', { ascending: false })
        .limit(20)
      if (error) throw error
      return (data ?? []) as Collective[]
    },
    staleTime: 10 * 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  User location (browser geolocation)                                */
/* ------------------------------------------------------------------ */

export function useUserLocation() {
  return useQuery({
    queryKey: ['user-location'],
    queryFn: () =>
      new Promise<Location | null>((resolve) => {
        if (!navigator.geolocation) {
          resolve(null)
          return
        }
        navigator.geolocation.getCurrentPosition(
          (pos) =>
            resolve({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
          () => resolve(null),
          { timeout: 10000, maximumAge: 5 * 60 * 1000 },
        )
      }),
    staleTime: 10 * 60 * 1000,
    retry: false,
  })
}

