import type { Database } from '@/types/database.types'

type ProfileUpdate = Database['public']['Tables']['profiles']['Update']

export function useProfile(userId?: string) {
  const { user } = useAuth()
  const id = userId ?? user?.id

  return useQuery({
    queryKey: ['profile', id],
    queryFn: async () => {
      if (!id) throw new Error('No user ID')
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', id)
        .single()
      if (error) throw error
      return data
    },
    enabled: !!id,
    staleTime: 5 * 60 * 1000,
  })
}

export function useProfileCollectives(userId?: string) {
  const { user } = useAuth()
  const id = userId ?? user?.id

  return useQuery({
    queryKey: ['profile-collectives', id],
    queryFn: async () => {
      if (!id) throw new Error('No user ID')
      const { data, error } = await supabase
        .from('collective_members')
        .select('collective_id, role, collectives(id, name, slug, cover_image_url, region, member_count)')
        .eq('user_id', id)
        .eq('status', 'active')
      if (error) throw error
      return data
    },
    enabled: !!id,
    staleTime: 5 * 60 * 1000,
  })
}

export function useProfileStats(userId?: string) {
  const { user } = useAuth()
  const id = userId ?? user?.id

  return useQuery({
    queryKey: ['profile-stats', id],
    queryFn: async () => {
      if (!id) throw new Error('No user ID')

      // Get events attended
      const { count: eventsAttended } = await supabase
        .from('event_registrations')
        .select('*', { count: 'exact', head: true })
        .eq('user_id', id)
        .eq('status', 'attended')

      // Get total impact from events the user attended
      const { data: registrations } = await supabase
        .from('event_registrations')
        .select('event_id')
        .eq('user_id', id)
        .eq('status', 'attended')

      const eventIds = registrations?.map((r) => r.event_id) ?? []

      let totalTreesPlanted = 0
      let totalHours = 0
      let totalRubbishKg = 0
      let totalAreaSqm = 0
      let totalNativePlants = 0
      let totalWildlifeSightings = 0

      if (eventIds.length > 0) {
        const { data: impacts } = await supabase
          .from('event_impact')
          .select('trees_planted, hours_total, rubbish_kg, area_restored_sqm, native_plants, wildlife_sightings')
          .in('event_id', eventIds)

        if (impacts) {
          for (const impact of impacts) {
            totalTreesPlanted += impact.trees_planted
            totalHours += impact.hours_total
            totalRubbishKg += impact.rubbish_kg
            totalAreaSqm += impact.area_restored_sqm
            totalNativePlants += impact.native_plants
            totalWildlifeSightings += impact.wildlife_sightings
          }
        }
      }

      return {
        eventsAttended: eventsAttended ?? 0,
        treesPlanted: totalTreesPlanted,
        hoursVolunteered: totalHours,
        rubbishCollectedKg: totalRubbishKg,
        areaRestoredSqm: totalAreaSqm,
        nativePlants: totalNativePlants,
        wildlifeSightings: totalWildlifeSightings,
      }
    },
    enabled: !!id,
    staleTime: 5 * 60 * 1000,
  })
}

export function useMutualConnections(targetUserId: string) {
  const { user } = useAuth()

  return useQuery({
    queryKey: ['mutual-connections', user?.id, targetUserId],
    queryFn: async () => {
      if (!user) throw new Error('Not authenticated')

      // Shared collectives
      const { data: myCollectives } = await supabase
        .from('collective_members')
        .select('collective_id')
        .eq('user_id', user.id)
        .eq('status', 'active')

      const { data: theirCollectives } = await supabase
        .from('collective_members')
        .select('collective_id, collectives(name)')
        .eq('user_id', targetUserId)
        .eq('status', 'active')

      const myIds = new Set(myCollectives?.map((c) => c.collective_id) ?? [])
      const sharedCollectives = theirCollectives?.filter((c) => myIds.has(c.collective_id)) ?? []

      // Shared events
      const { data: myEvents } = await supabase
        .from('event_registrations')
        .select('event_id')
        .eq('user_id', user.id)
        .eq('status', 'attended')

      const { data: theirEvents } = await supabase
        .from('event_registrations')
        .select('event_id')
        .eq('user_id', targetUserId)
        .eq('status', 'attended')

      const myEventIds = new Set(myEvents?.map((e) => e.event_id) ?? [])
      const sharedEventCount = theirEvents?.filter((e) => myEventIds.has(e.event_id)).length ?? 0

      return {
        sharedCollectives: sharedCollectives.map((c) => ({
          id: c.collective_id,
          name: (c.collectives as { name: string } | null)?.name ?? '',
        })),
        sharedEventCount,
      }
    },
    enabled: !!user && !!targetUserId && user.id !== targetUserId,
    staleTime: 10 * 60 * 1000,
  })
}

export function useUpdateProfile() {
  const queryClient = useQueryClient()
  const { user, refreshProfile } = useAuth()

  return useMutation({
    mutationFn: async (updates: ProfileUpdate) => {
      if (!user) throw new Error('Not authenticated')
      const { error } = await supabase
        .from('profiles')
        .update(updates)
        .eq('id', user.id)
      if (error) throw error
    },
    onMutate: async (updates) => {
      await queryClient.cancelQueries({ queryKey: ['profile', user?.id] })
      const previous = queryClient.getQueryData(['profile', user?.id])
      queryClient.setQueryData(['profile', user?.id], (old: any) => old ? { ...old, ...updates } : old)
      return { previous }
    },
    onError: (_err, _, context) => {
      if (context?.previous) queryClient.setQueryData(['profile', user?.id], context.previous)
    },
    onSettled: () => {
      queryClient.invalidateQueries({ queryKey: ['profile', user?.id] })
      refreshProfile()
    },
  })
}

export function useUploadAvatar() {
  const queryClient = useQueryClient()
  const { user } = useAuth()

  return useMutation({
    mutationFn: async (file: File) => {
      if (!user) throw new Error('Not authenticated')
      const ext = file.name.split('.').pop()
      const path = `${user.id}/avatar.${ext}`

      const { error: uploadError } = await supabase.storage
        .from('avatars')
        .upload(path, file, { upsert: true })
      if (uploadError) throw uploadError

      const { data: { publicUrl } } = supabase.storage
        .from('avatars')
        .getPublicUrl(path)

      const { error: updateError } = await supabase
        .from('profiles')
        .update({ avatar_url: publicUrl })
        .eq('id', user.id)
      if (updateError) throw updateError

      return publicUrl
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['profile', user?.id] })
    },
  })
}

import { useEffect, useCallback, useRef } from 'react'
import { useNavigate } from 'react-router-dom'
import { Capacitor } from '@capacitor/core'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/hooks/use-auth'
import { resolveNotificationRoute } from '@/hooks/use-notifications'

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

interface PushNotificationToken {
  value: string
}

interface PushNotificationActionPerformed {
  actionId: string
  notification: {
    data?: Record<string, string>
    title?: string
    body?: string
  }
}

/* ------------------------------------------------------------------ */
/*  Capacitor Push Notifications - dynamic import                      */
/* ------------------------------------------------------------------ */

let PushNotifications: {
  requestPermissions: () => Promise<{ receive: string }>
  register: () => Promise<void>
  getDeliveredNotifications: () => Promise<{ notifications: unknown[] }>
  removeAllDeliveredNotifications: () => Promise<void>
  addListener: (event: string, handler: (...args: unknown[]) => void) => Promise<{ remove: () => void }>
} | null = null

async function loadPushPlugin() {
  if (!Capacitor.isNativePlatform()) return null
  try {
    const mod = await import('@capacitor/push-notifications')
    PushNotifications = mod.PushNotifications as typeof PushNotifications
    return PushNotifications
  } catch {
    console.warn('[push] @capacitor/push-notifications not available')
    return null
  }
}

/* ------------------------------------------------------------------ */
/*  Token storage (module-level, shared by both hooks)                 */
/* ------------------------------------------------------------------ */

function getDeviceInfo(): Record<string, string> {
  return {
    platform: Capacitor.getPlatform(),
    os_version: (navigator as { userAgent?: string }).userAgent ?? 'unknown',
  }
}

async function storeToken(userId: string, token: string, platform: string) {
  const { error } = await supabase
    .from('push_tokens')
    .upsert(
      {
        user_id: userId,
        token,
        platform,
        device_info: getDeviceInfo(),
        updated_at: new Date().toISOString(),
      },
      { onConflict: 'user_id,token' },
    )

  if (error) {
    console.error('[push] Failed to store token:', error)
  }
}

async function removeToken(userId: string, token: string) {
  await supabase
    .from('push_tokens')
    .delete()
    .eq('user_id', userId)
    .eq('token', token)
}

async function removeAllTokensForUser(userId: string) {
  await supabase
    .from('push_tokens')
    .delete()
    .eq('user_id', userId)
}

async function clearBadgeCount() {
  if (!Capacitor.isNativePlatform()) return
  try {
    const plugin = await loadPushPlugin()
    await plugin?.removeAllDeliveredNotifications()
  } catch {
    // badge API may not be available
  }
}

/* ------------------------------------------------------------------ */
/*  usePushRegistration — mount ONCE at app root (AppShell)            */
/*                                                                     */
/*  Handles:                                                           */
/*    - Requesting permission + registering with FCM/APNs              */
/*    - Listening for token refresh and persisting to push_tokens      */
/*    - Deep-link routing when user taps a notification                */
/*    - Re-registering on app resume (handles token rotation)          */
/*    - Clearing badge count on foreground                             */
/* ------------------------------------------------------------------ */

export function usePushRegistration() {
  const { user } = useAuth()
  const navigate = useNavigate()
  const tokenRef = useRef<string | null>(null)
  const listenersRef = useRef<Array<{ remove: () => void }>>([])

  useEffect(() => {
    if (!user) return

    let mounted = true

    async function setup() {
      const plugin = await loadPushPlugin()
      if (!plugin || !mounted) return

      const platform = Capacitor.getPlatform() // 'ios' | 'android'

      // Token received (initial registration or refresh)
      const regListener = await plugin.addListener(
        'registration',
        (token: unknown) => {
          const t = token as PushNotificationToken
          tokenRef.current = t.value
          storeToken(user!.id, t.value, platform)
        },
      )

      // Registration error
      const errListener = await plugin.addListener(
        'registrationError',
        (err: unknown) => {
          console.error('[push] registration error:', err)
        },
      )

      // Notification received while app is open (foreground)
      const receivedListener = await plugin.addListener(
        'pushNotificationReceived',
        (_notification: unknown) => {
          // Foreground notifications - could show in-app toast
        },
      )

      // Notification tapped — deep link routing
      const actionListener = await plugin.addListener(
        'pushNotificationActionPerformed',
        (action: unknown) => {
          const a = action as PushNotificationActionPerformed
          const route = resolveNotificationRoute(
            a.notification.data?.type ?? '',
            a.notification.data,
          )
          navigate(route)
        },
      )

      listenersRef.current = [regListener, errListener, receivedListener, actionListener]

      // Try to register (will use existing permission or silently succeed)
      try {
        const perm = await plugin.requestPermissions()
        if (perm.receive === 'granted') {
          await plugin.register()
        }
      } catch {
        // Permission not yet granted — that's fine, we'll prompt later
      }
    }

    setup()

    // Clear badge count when app opens
    clearBadgeCount()

    // Re-register on app resume to ensure token is current
    let resumeListener: { remove: () => void } | null = null
    if (Capacitor.isNativePlatform()) {
      import('@capacitor/app').then(({ App }) => {
        if (!mounted) return
        App.addListener('appStateChange', async ({ isActive }) => {
          if (isActive && mounted) {
            clearBadgeCount()
            try {
              const plugin = await loadPushPlugin()
              if (plugin) {
                const perm = await plugin.requestPermissions()
                if (perm.receive === 'granted') {
                  await plugin.register()
                }
              }
            } catch {
              // ignore
            }
          }
        }).then((l) => {
          if (mounted) {
            resumeListener = l
          } else {
            l.remove()
          }
        })
      })
    }

    return () => {
      mounted = false
      listenersRef.current.forEach((l) => l.remove())
      listenersRef.current = []
      resumeListener?.remove()
    }
  }, [user, navigate])

  return { tokenRef }
}

/* ------------------------------------------------------------------ */
/*  usePush — imperative actions (settings page, logout, dev tools)    */
/*                                                                     */
/*  NOT responsible for registration side-effects — that's             */
/*  usePushRegistration above. This hook is for explicit user actions. */
/* ------------------------------------------------------------------ */

export function usePush() {
  const { user } = useAuth()

  /** Prompt for permission (call at a strategic moment, e.g. after onboarding) */
  const requestPermission = useCallback(async () => {
    const plugin = await loadPushPlugin()
    if (!plugin) return false

    const result = await plugin.requestPermissions()
    if (result.receive === 'granted') {
      await plugin.register()
      return true
    }
    return false
  }, [])

  /** Remove this device's token on logout */
  const unregister = useCallback(async () => {
    if (user) {
      // Best-effort: remove all tokens for this user (covers multi-device)
      await removeAllTokensForUser(user.id)
    }
  }, [user])

  /** Clear badge/notification tray */
  const clearBadge = useCallback(async () => {
    await clearBadgeCount()
  }, [])

  return {
    requestPermission,
    unregister,
    clearBadgeCount: clearBadge,
  }
}

import { useState, useEffect, useCallback, useRef } from 'react'
import { useQuery } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'
import type { Event, Collective, Profile } from '@/types/database.types'

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface SearchResults {
  events: EventSearchResult[]
  collectives: CollectiveSearchResult[]
  people: ProfileSearchResult[]
}

export type EventSearchResult = Pick<
  Event,
  'id' | 'title' | 'activity_type' | 'date_start' | 'address' | 'cover_image_url'
>

export type CollectiveSearchResult = Pick<
  Collective,
  'id' | 'name' | 'slug' | 'region' | 'state' | 'cover_image_url' | 'member_count'
>

export type ProfileSearchResult = Pick<
  Profile,
  'id' | 'display_name' | 'avatar_url'
>

export interface SearchFilters {
  activityTypes: string[]
  dateFrom: string | null
  dateTo: string | null
  distanceKm: number
  state: string | null
}

const STORAGE_KEY = 'coexist-recent-searches'
const MAX_RECENT = 8

/* ------------------------------------------------------------------ */
/*  Recent searches (persisted to localStorage)                        */
/* ------------------------------------------------------------------ */

function loadRecentSearches(): string[] {
  try {
    const raw = localStorage.getItem(STORAGE_KEY)
    return raw ? (JSON.parse(raw) as string[]) : []
  } catch {
    return []
  }
}

function saveRecentSearches(searches: string[]) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(searches.slice(0, MAX_RECENT)))
}

/* ------------------------------------------------------------------ */
/*  Debounce hook                                                      */
/* ------------------------------------------------------------------ */

function useDebouncedValue<T>(value: T, delay: number): T {
  const [debounced, setDebounced] = useState(value)

  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay)
    return () => clearTimeout(timer)
  }, [value, delay])

  return debounced
}

/* ------------------------------------------------------------------ */
/*  Main search hook                                                   */
/* ------------------------------------------------------------------ */

export function useSearch(filters?: SearchFilters) {
  const [query, setQuery] = useState('')
  const [recentSearches, setRecentSearches] = useState(loadRecentSearches)
  const debouncedQuery = useDebouncedValue(query.trim(), 300)
  const lastCommittedRef = useRef('')

  const commitSearch = useCallback((term: string) => {
    const trimmed = term.trim()
    if (!trimmed || trimmed === lastCommittedRef.current) return
    lastCommittedRef.current = trimmed

    setRecentSearches((prev) => {
      const next = [trimmed, ...prev.filter((s) => s !== trimmed)].slice(0, MAX_RECENT)
      saveRecentSearches(next)
      return next
    })
  }, [])

  const clearRecentSearches = useCallback(() => {
    setRecentSearches([])
    localStorage.removeItem(STORAGE_KEY)
  }, [])

  const removeRecentSearch = useCallback((term: string) => {
    setRecentSearches((prev) => {
      const next = prev.filter((s) => s !== term)
      saveRecentSearches(next)
      return next
    })
  }, [])

  const results = useQuery({
    queryKey: ['search', debouncedQuery, filters],
    queryFn: async (): Promise<SearchResults> => {
      if (!debouncedQuery) return { events: [], collectives: [], people: [] }

      const escaped = debouncedQuery.replace(/[%_\\]/g, '\\$&')
      const pattern = `%${escaped}%`

      // Build events query
      let eventsQuery = supabase
        .from('events')
        .select('id, title, activity_type, date_start, address, cover_image_url')
        .eq('status', 'published')
        .ilike('title', pattern)

      if (filters?.activityTypes?.length) {
        eventsQuery = eventsQuery.in('activity_type', filters.activityTypes as any)
      }
      if (filters?.dateFrom) {
        eventsQuery = eventsQuery.gte('date_start', filters.dateFrom)
      }
      if (filters?.dateTo) {
        eventsQuery = eventsQuery.lte('date_start', filters.dateTo)
      }
      if (filters?.state) {
        eventsQuery = eventsQuery.ilike('address', `%${filters.state}%`)
      }

      const [eventsRes, collectivesRes, peopleRes] = await Promise.all([
        eventsQuery.order('date_start', { ascending: true }).limit(15),
        supabase
          .from('collectives')
          .select('id, name, slug, region, state, cover_image_url, member_count')
          .eq('is_active', true)
          .ilike('name', pattern)
          .order('member_count', { ascending: false })
          .limit(10),
        supabase
          .from('profiles')
          .select('id, display_name, avatar_url')
          .ilike('display_name', pattern)
          .limit(10),
      ])

      if (eventsRes.error) throw eventsRes.error
      if (collectivesRes.error) throw collectivesRes.error
      if (peopleRes.error) throw peopleRes.error

      return {
        events: (eventsRes.data ?? []) as EventSearchResult[],
        collectives: (collectivesRes.data ?? []) as CollectiveSearchResult[],
        people: (peopleRes.data ?? []) as ProfileSearchResult[],
      }
    },
    enabled: debouncedQuery.length >= 2,
    staleTime: 2 * 60 * 1000,
  })

  const totalResults =
    (results.data?.events.length ?? 0) +
    (results.data?.collectives.length ?? 0) +
    (results.data?.people.length ?? 0)

  return {
    query,
    setQuery,
    debouncedQuery,
    results,
    totalResults,
    recentSearches,
    commitSearch,
    clearRecentSearches,
    removeRecentSearch,
    hasQuery: debouncedQuery.length >= 2,
  }
}

