import { useEffect, useCallback, useRef, useMemo } from 'react'
import { useQuery, useMutation, useQueryClient, useInfiniteQuery } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/hooks/use-auth'
import type { ChatMessage, Profile } from '@/types/database.types'

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface StaffChannel {
  id: string
  type: 'staff_collective' | 'staff_state' | 'staff_national'
  collective_id: string | null
  state: string | null
  name: string
  created_at: string
}

export interface ChannelMessageWithSender {
  id: string
  channel_id: string
  collective_id: string | null
  user_id: string | null
  content: string | null
  image_url: string | null
  voice_url: string | null
  video_url: string | null
  reply_to_id: string | null
  is_pinned: boolean
  is_deleted: boolean
  created_at: string
  message_type?: 'text' | 'image' | 'voice' | 'video' | 'poll' | 'announcement' | 'system'
  poll_id?: string | null
  announcement_id?: string | null
  profiles: Pick<Profile, 'id' | 'display_name' | 'avatar_url'> | null
  reply_message: { id: string; content: string | null; user_id: string | null } | null
  _optimistic?: boolean
  _optimisticId?: string
  _confirmed?: boolean
}

/* ------------------------------------------------------------------ */
/*  useMyStaffChannels — channels the user is a member of              */
/* ------------------------------------------------------------------ */

export function useMyStaffChannels() {
  const { user } = useAuth()

  return useQuery({
    queryKey: ['my-staff-channels', user?.id],
    queryFn: async () => {
      if (!user) return []

      const { data, error } = await supabase
        .from('chat_channel_members' as any)
        .select('channel_id, chat_channels(id, type, collective_id, state, name, created_at)')
        .eq('user_id', user.id)

      if (error) throw error

      return (data ?? [])
        .map((row: any) => row.chat_channels as StaffChannel)
        .filter(Boolean)
        .sort((a: StaffChannel, b: StaffChannel) => {
          // National first, then state, then collective
          const typeOrder = { staff_national: 0, staff_state: 1, staff_collective: 2 }
          return (typeOrder[a.type] ?? 3) - (typeOrder[b.type] ?? 3)
        })
    },
    enabled: !!user,
    staleTime: 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  useChannelMessages — paginated messages for a channel              */
/* ------------------------------------------------------------------ */

const PAGE_SIZE = 40

export function useChannelMessages(channelId: string | undefined) {
  const { user } = useAuth()
  const queryClient = useQueryClient()

  const query = useInfiniteQuery({
    queryKey: ['channel-messages', channelId],
    queryFn: async ({ pageParam }: { pageParam: string | null }) => {
      if (!channelId) return []

      let q = supabase
        .from('chat_messages' as any)
        .select(`
          *,
          profiles!chat_messages_user_id_fkey(id, display_name, avatar_url)
        `)
        .eq('channel_id', channelId)
        .order('created_at', { ascending: false })
        .limit(PAGE_SIZE)

      if (pageParam) {
        q = q.lt('created_at', pageParam)
      }

      const { data, error } = await q
      if (error) throw error

      const messages = (data ?? []) as unknown as ChannelMessageWithSender[]

      // Resolve reply_message client-side (self-referencing FK not in PostgREST cache)
      const replyIds = messages
        .map((m) => (m as any).reply_to_id)
        .filter((id: unknown): id is string => !!id)

      if (replyIds.length > 0) {
        const { data: replies } = await supabase
          .from('chat_messages' as any)
          .select('id, content, user_id')
          .in('id', replyIds)

        const replyMap = new Map((replies ?? []).map((r: any) => [r.id, r]))
        for (const msg of messages) {
          msg.reply_message = (msg as any).reply_to_id ? (replyMap.get((msg as any).reply_to_id) ?? null) : null
        }
      } else {
        for (const msg of messages) {
          msg.reply_message = null
        }
      }

      return messages
    },
    initialPageParam: null as string | null,
    getNextPageParam: (lastPage) => {
      if (lastPage.length < PAGE_SIZE) return undefined
      return lastPage[lastPage.length - 1]?.created_at
    },
    enabled: !!channelId && !!user,
    staleTime: 10 * 1000,
  })

  // Realtime subscription for new messages
  useEffect(() => {
    if (!channelId) return

    const channel = supabase
      .channel(`channel-${channelId}`)
      .on(
        'postgres_changes',
        {
          event: 'INSERT',
          schema: 'public',
          table: 'chat_messages',
          filter: `channel_id=eq.${channelId}`,
        },
        (payload: any) => {
          // Invalidate to refetch — simple approach
          queryClient.invalidateQueries({ queryKey: ['channel-messages', channelId] })
        },
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [channelId, queryClient])

  // Flatten pages into a single array (pages are newest-first, reverse for display)
  const messages = useMemo(
    () => query.data?.pages.flat().reverse() ?? [],
    [query.data],
  )

  return {
    ...query,
    messages,
  }
}

/* ------------------------------------------------------------------ */
/*  useSendChannelMessage — send a message to a channel                */
/* ------------------------------------------------------------------ */

export function useSendChannelMessage() {
  const { user } = useAuth()
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async ({
      channelId,
      collectiveId,
      content,
      imageUrl,
      replyToId,
    }: {
      channelId: string
      collectiveId?: string | null
      content?: string
      imageUrl?: string
      replyToId?: string
    }) => {
      if (!user) throw new Error('Not authenticated')

      const { error } = await supabase
        .from('chat_messages' as any)
        .insert({
          channel_id: channelId,
          collective_id: collectiveId || null,
          user_id: user.id,
          content: content || null,
          image_url: imageUrl || null,
          reply_to_id: replyToId || null,
        })

      if (error) throw error
    },
    onSuccess: (_data, variables) => {
      queryClient.invalidateQueries({ queryKey: ['channel-messages', variables.channelId] })
      queryClient.invalidateQueries({ queryKey: ['channel-unread'] })
    },
  })
}

/* ------------------------------------------------------------------ */
/*  useChannelUnreadCounts — unread counts per channel                 */
/* ------------------------------------------------------------------ */

export function useChannelUnreadCounts() {
  const { user } = useAuth()

  return useQuery({
    queryKey: ['channel-unread', user?.id],
    queryFn: async () => {
      if (!user) return {}

      // Get user's channel memberships with collective_id
      const { data: memberships } = await supabase
        .from('chat_channel_members' as any)
        .select('channel_id, chat_channels(collective_id)')
        .eq('user_id', user.id)

      if (!memberships?.length) return {}

      // Build channel → collectiveId map
      const channelToCollective = new Map<string, string>()
      for (const m of memberships as any[]) {
        const cid = m.chat_channels?.collective_id
        if (cid) channelToCollective.set(m.channel_id, cid)
      }

      // Get read receipts by collective_id (that's the unique key on chat_read_receipts)
      const collectiveIds = [...new Set(channelToCollective.values())]
      const { data: receipts } = await supabase
        .from('chat_read_receipts' as any)
        .select('collective_id, last_read_at')
        .eq('user_id', user.id)
        .in('collective_id', collectiveIds)

      const receiptMap = new Map<string, string>()
      for (const r of receipts ?? []) {
        receiptMap.set((r as any).collective_id, (r as any).last_read_at)
      }

      // Count unread messages per channel
      const counts: Record<string, number> = {}
      for (const [channelId, collectiveId] of channelToCollective) {
        const lastRead = receiptMap.get(collectiveId)
        let q = supabase
          .from('chat_messages' as any)
          .select('id', { count: 'exact', head: true })
          .eq('channel_id', channelId)
          .eq('is_deleted', false)

        if (lastRead) {
          q = q.gt('created_at', lastRead)
        }

        // Exclude own messages
        q = q.neq('user_id', user.id)

        const { count } = await q
        if (count && count > 0) {
          counts[channelId] = count
        }
      }

      return counts
    },
    enabled: !!user,
    staleTime: 30 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  useMarkChannelRead — update read receipt for a channel             */
/* ------------------------------------------------------------------ */

export function useMarkChannelRead() {
  const { user } = useAuth()
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: async ({ channelId, collectiveId }: { channelId: string; collectiveId?: string | null }) => {
      if (!user || !collectiveId) return

      await supabase
        .from('chat_read_receipts' as any)
        .upsert({
          collective_id: collectiveId,
          user_id: user.id,
          last_read_at: new Date().toISOString(),
        }, { onConflict: 'collective_id,user_id' })
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['channel-unread'] })
    },
  })
}

import { useCallback, useEffect, useRef, useState, startTransition } from 'react'
import { useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/hooks/use-auth'
import { useToast } from '@/components/toast'

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

/** How long a reservation lasts (minutes) */
const RESERVATION_DURATION_MINUTES = 15

/** How often to check expiry and trigger countdown (ms) */
const TICK_INTERVAL = 1000

/** Warn when reservation has this many seconds left */
const EXPIRY_WARNING_THRESHOLD = 120

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface ReservationResult {
  success: boolean
  error?: string
  available?: number
  requested?: number
  expires_at?: string
  reserved?: number
}

export interface AvailableStockEntry {
  variant_key: string
  total_stock: number
  reserved: number
  available: number
}

/* ------------------------------------------------------------------ */
/*  useReserveStock — reserve/release a single variant                 */
/* ------------------------------------------------------------------ */

export function useReserveStock() {
  const { user } = useAuth()
  const queryClient = useQueryClient()

  const reserve = useCallback(
    async (productId: string, variantKey: string, quantity: number): Promise<ReservationResult> => {
      if (!user) return { success: false, error: 'not_authenticated' }

      const { data, error } = await (supabase.rpc as any)('reserve_stock', {
        p_user_id: user.id,
        p_product_id: productId,
        p_variant_key: variantKey,
        p_quantity: quantity,
        p_duration_minutes: RESERVATION_DURATION_MINUTES,
      })

      if (error) return { success: false, error: error.message }

      // Invalidate stock queries so UI reflects new availability
      queryClient.invalidateQueries({ queryKey: ['product-stock'] })
      queryClient.invalidateQueries({ queryKey: ['available-stock'] })

      return data as unknown as ReservationResult
    },
    [user, queryClient],
  )

  const release = useCallback(
    async (variantKey: string) => {
      if (!user) return
      await (supabase.rpc as any)('release_reservation', {
        p_user_id: user.id,
        p_variant_key: variantKey,
      })
      queryClient.invalidateQueries({ queryKey: ['product-stock'] })
      queryClient.invalidateQueries({ queryKey: ['available-stock'] })
    },
    [user, queryClient],
  )

  const releaseAll = useCallback(async () => {
    if (!user) return
    await (supabase.rpc as any)('release_all_reservations', {
      p_user_id: user.id,
    })
    queryClient.invalidateQueries({ queryKey: ['product-stock'] })
    queryClient.invalidateQueries({ queryKey: ['available-stock'] })
  }, [user, queryClient])

  return { reserve, release, releaseAll }
}

/* ------------------------------------------------------------------ */
/*  useAvailableStock — fetch available stock for a product            */
/*  (total - other users' reservations)                                */
/* ------------------------------------------------------------------ */

export function useAvailableStock(productId: string | undefined) {
  const { user } = useAuth()
  const [stockMap, setStockMap] = useState<Map<string, AvailableStockEntry>>(new Map())
  const [loading, setLoading] = useState(true)

  const fetchStock = useCallback(async () => {
    if (!productId) return
    const { data, error } = await (supabase.rpc as any)('get_product_available_stock', {
      p_product_id: productId,
      p_exclude_user_id: user?.id ?? null,
    })

    startTransition(() => {
      if (!error && data) {
        const entries = data as unknown as AvailableStockEntry[]
        const map = new Map<string, AvailableStockEntry>()
        for (const entry of entries) {
          map.set(entry.variant_key, entry)
        }
        setStockMap(map)
      }
      setLoading(false)
    })
  }, [productId, user?.id])

  // Initial fetch
  useEffect(() => {
    fetchStock()
  }, [fetchStock])

  // Subscribe to realtime changes on merch_inventory and cart_reservations
  useEffect(() => {
    if (!productId) return

    const channel = supabase
      .channel(`stock:${productId}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'merch_inventory',
          filter: `product_id=eq.${productId}`,
        },
        () => fetchStock(),
      )
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'cart_reservations',
          filter: `product_id=eq.${productId}`,
        },
        () => fetchStock(),
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [productId, fetchStock])

  const getAvailable = useCallback(
    (variantKey: string): number => {
      return stockMap.get(variantKey)?.available ?? 0
    },
    [stockMap],
  )

  return { stockMap, loading, getAvailable, refetch: fetchStock }
}

/* ------------------------------------------------------------------ */
/*  useMyReservations — track current user's active reservations        */
/* ------------------------------------------------------------------ */

export interface MyReservation {
  id: string
  variant_key: string
  product_id: string
  quantity: number
  expires_at: string
}

export function useMyReservations() {
  const { user } = useAuth()
  const [reservations, setReservations] = useState<MyReservation[]>([])

  const fetchReservations = useCallback(async () => {
    if (!user) return
    const { data } = await (supabase.from as any)('cart_reservations')
      .select('id, variant_key, product_id, quantity, expires_at')
      .eq('user_id', user.id)
      .gt('expires_at', new Date().toISOString())

    startTransition(() => {
      setReservations((data as unknown as MyReservation[]) ?? [])
    })
  }, [user])

  useEffect(() => {
    fetchReservations()
  }, [fetchReservations])

  // Realtime updates to own reservations
  useEffect(() => {
    if (!user) return

    const channel = supabase
      .channel(`my-reservations:${user.id}`)
      .on(
        'postgres_changes',
        {
          event: '*',
          schema: 'public',
          table: 'cart_reservations',
          filter: `user_id=eq.${user.id}`,
        },
        () => fetchReservations(),
      )
      .subscribe()

    return () => {
      supabase.removeChannel(channel)
    }
  }, [user, fetchReservations])

  const getReservation = useCallback(
    (variantKey: string) => reservations.find((r) => r.variant_key === variantKey),
    [reservations],
  )

  return { reservations, getReservation, refetch: fetchReservations }
}

/* ------------------------------------------------------------------ */
/*  useReservationCountdown — seconds remaining on a reservation       */
/* ------------------------------------------------------------------ */

export function useReservationCountdown(expiresAt: string | undefined) {
  const [secondsLeft, setSecondsLeft] = useState<number | null>(null)

  useEffect(() => {
    if (!expiresAt) {
      startTransition(() => setSecondsLeft(null))
      return
    }

    const update = () => {
      const diff = Math.max(0, Math.floor((new Date(expiresAt).getTime() - Date.now()) / 1000))
      startTransition(() => setSecondsLeft(diff))
    }

    update()
    const id = setInterval(update, TICK_INTERVAL)
    return () => clearInterval(id)
  }, [expiresAt])

  const isExpiring = secondsLeft !== null && secondsLeft <= EXPIRY_WARNING_THRESHOLD && secondsLeft > 0
  const isExpired = secondsLeft === 0

  return { secondsLeft, isExpiring, isExpired }
}

/* ------------------------------------------------------------------ */
/*  useCartReservationSync — keeps reservations in sync with cart      */
/*  Call this once at the cart/checkout level. It reserves stock for   */
/*  every cart item and releases when items are removed.               */
/* ------------------------------------------------------------------ */

export function useCartReservationSync(cartItems: { product: { id: string }; variant: { id: string }; quantity: number }[]) {
  const { reserve, release, releaseAll } = useReserveStock()
  const { toast } = useToast()
  const prevItemsRef = useRef<string>('')
  const isMountedRef = useRef(true)

  useEffect(() => {
    isMountedRef.current = true
    return () => { isMountedRef.current = false }
  }, [])

  // Sync reservations whenever cart changes
  useEffect(() => {
    const key = JSON.stringify(cartItems.map((i) => `${i.variant.id}:${i.quantity}`).sort())
    if (key === prevItemsRef.current) return
    prevItemsRef.current = key

    const sync = async () => {
      for (const item of cartItems) {
        const result = await reserve(item.product.id, item.variant.id, item.quantity)
        if (!result.success && result.error === 'insufficient_stock' && isMountedRef.current) {
          toast.error(
            `Only ${result.available} left for one of your items. Please update your cart.`,
          )
        }
      }
    }

    sync()
  }, [cartItems, reserve, toast])

  // Release all on unmount (e.g. user leaves checkout flow)
  // Note: we do NOT release on unmount by default — reservations
  // are time-bound and should persist across page navigations.
  // They auto-expire after RESERVATION_DURATION_MINUTES.

  return { releaseAll }
}

/* ------------------------------------------------------------------ */
/*  Expiry warning threshold (exported for UI)                         */
/* ------------------------------------------------------------------ */

export { EXPIRY_WARNING_THRESHOLD, RESERVATION_DURATION_MINUTES }

import { useCallback, useMemo } from 'react'
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/hooks/use-auth'
import { getCurrentPeriodKey, getDueDate, type TaskTemplate, type TaskInstance } from '@/hooks/use-admin-tasks'
import { resolveAndGenerateDynamicInstances } from '@/hooks/use-timeline-rules'

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export interface MyTask extends TaskInstance {
  template: TaskTemplate
  collective: { id: string; name: string }
  event?: { id: string; title: string } | null
}

export interface CollectiveTaskGroup {
  collective_id: string
  collective_name: string
  tasks: MyTask[]
  pendingCount: number
  overdueCount: number
}

/* ------------------------------------------------------------------ */
/*  useMyTasks — all pending tasks for current user across collectives */
/* ------------------------------------------------------------------ */

export function useMyTasks() {
  const { user, collectiveRoles } = useAuth()

  // Find collectives where user is assist_leader+
  const staffCollectiveIds = useMemo(
    () =>
      collectiveRoles
        .filter((m) => m.role === 'assist_leader' || m.role === 'co_leader' || m.role === 'leader')
        .map((m) => m.collective_id),
    [collectiveRoles],
  )

  return useQuery({
    queryKey: ['my-tasks', user?.id, staffCollectiveIds],
    queryFn: async () => {
      if (!user || staffCollectiveIds.length === 0) return []

      const { data, error } = await supabase
        .from('task_instances' as any)
        .select(`
          *,
          task_templates(*),
          collectives(id, name),
          events(id, title),
          profiles!task_instances_completed_by_fkey(display_name, avatar_url)
        `)
        .in('collective_id', staffCollectiveIds)
        .order('due_date', { ascending: true })

      if (error) throw error

      // Filter: for individual tasks (assigned_user_id set), only show the current user's instances
      return (data ?? [])
        .filter((row: any) => !row.assigned_user_id || row.assigned_user_id === user!.id)
        .map((row: any) => ({
          ...row,
          template: row.task_templates,
          collective: row.collectives,
          event: row.events,
          completer: row.profiles ?? null,
        })) as MyTask[]
    },
    enabled: !!user && staffCollectiveIds.length > 0,
    staleTime: 30 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  useCollectiveTasks — tasks for a specific collective               */
/* ------------------------------------------------------------------ */

export function useCollectiveTasks(collectiveId: string | undefined) {
  const { user } = useAuth()

  return useQuery({
    queryKey: ['collective-tasks', collectiveId],
    queryFn: async () => {
      if (!collectiveId) return []

      const { data, error } = await supabase
        .from('task_instances' as any)
        .select(`
          *,
          task_templates(*),
          collectives(id, name),
          events(id, title),
          profiles!task_instances_completed_by_fkey(display_name, avatar_url)
        `)
        .eq('collective_id', collectiveId)
        .order('due_date', { ascending: true })

      if (error) throw error

      return (data ?? []).map((row: any) => ({
        ...row,
        template: row.task_templates,
        collective: row.collectives,
        event: row.events,
        completer: row.profiles ?? null,
      })) as MyTask[]
    },
    enabled: !!user && !!collectiveId,
    staleTime: 30 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  useCompleteTask — mark a task instance as completed                */
/* ------------------------------------------------------------------ */

export function useCompleteTask() {
  const queryClient = useQueryClient()
  const { user } = useAuth()

  return useMutation({
    mutationFn: async ({
      instanceId,
      notes,
    }: {
      instanceId: string
      notes?: string
    }) => {
      if (!user) throw new Error('Not authenticated')

      const { error } = await supabase
        .from('task_instances' as any)
        .update({
          status: 'completed',
          completed_at: new Date().toISOString(),
          completed_by: user.id,
          completion_notes: notes || null,
        })
        .eq('id', instanceId)

      if (error) throw error
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['my-tasks'] })
      queryClient.invalidateQueries({ queryKey: ['collective-tasks'] })
