/* ------------------------------------------------------------------ */
/*  useGenerateTaskInstances — lazy generation for current period      */
/* ------------------------------------------------------------------ */

export function useGenerateTaskInstances() {
  const queryClient = useQueryClient()
  const { user, collectiveRoles } = useAuth()

  return useMutation({
    mutationFn: async () => {
      if (!user) return

      const staffCollectiveIds = collectiveRoles
        .filter((m) => m.role === 'assist_leader' || m.role === 'co_leader' || m.role === 'leader')
        .map((m) => m.collective_id)

      if (staffCollectiveIds.length === 0) return

      // Fetch active templates that apply to user's collectives
      const { data: templates } = await supabase
        .from('task_templates' as any)
        .select('*')
        .eq('is_active', true)
        .neq('schedule_type', 'event_relative') // Event-relative handled separately

      if (!templates?.length) return

      // Separate once vs recurring templates, and split recurring by assignment mode
      const onceTemplates = (templates as any[]).filter((t) => t.schedule_type === 'once')
      const collectiveRecurring = (templates as any[]).filter(
        (t) => t.schedule_type !== 'once' && (t.assignment_mode ?? 'collective') === 'collective',
      )
      const individualRecurring = (templates as any[]).filter(
        (t) => t.schedule_type !== 'once' && t.assignment_mode === 'individual',
      )

      // --- Handle collective recurring templates (weekly/monthly) ---
      // One instance per collective per period — any staff can complete
      for (const template of collectiveRecurring) {
        const periodKey = getCurrentPeriodKey(template.schedule_type)
        if (!periodKey) continue

        const targetCollectives = template.collective_id
          ? [template.collective_id].filter((id: string) => staffCollectiveIds.includes(id))
          : staffCollectiveIds

        for (const collectiveId of targetCollectives) {
          const dueDate = getDueDate(template as TaskTemplate, periodKey)
          await supabase
            .from('task_instances' as any)
            .upsert(
              {
                template_id: template.id,
                collective_id: collectiveId,
                due_date: dueDate,
                period_key: periodKey,
                status: 'pending',
              },
              { onConflict: 'template_id,collective_id,period_key' },
            )
        }
      }

      // --- Handle individual recurring templates (weekly/monthly) ---
      // One instance per USER per collective per period
      if (individualRecurring.length > 0) {
        const indivTemplateIds = individualRecurring.map((t: any) => t.id)

        // Check which individual-recurring tasks this user already has for the current periods
        const periodsToCheck: string[] = []
        for (const template of individualRecurring) {
          const pk = getCurrentPeriodKey(template.schedule_type)
          if (pk) periodsToCheck.push(`${pk}:${user.id}`)
        }

        const { data: existingIndiv } = await supabase
          .from('task_instances' as any)
          .select('template_id, collective_id, period_key')
          .in('template_id', indivTemplateIds)
          .eq('assigned_user_id', user.id)

        const existingIndivKeys = new Set(
          (existingIndiv ?? []).map((r: any) => `${r.template_id}:${r.collective_id}:${r.period_key}`),
        )

        for (const template of individualRecurring) {
          const basePeriodKey = getCurrentPeriodKey(template.schedule_type)
          if (!basePeriodKey) continue

          const periodKey = `${basePeriodKey}:${user.id}`
          const targetCollectives = template.collective_id
            ? [template.collective_id].filter((id: string) => staffCollectiveIds.includes(id))
            : staffCollectiveIds

          for (const collectiveId of targetCollectives) {
            const key = `${template.id}:${collectiveId}:${periodKey}`
            if (existingIndivKeys.has(key)) continue

            const dueDate = getDueDate(template as TaskTemplate, basePeriodKey)
            await supabase
              .from('task_instances' as any)
              .insert({
                template_id: template.id,
                collective_id: collectiveId,
                due_date: dueDate,
                period_key: periodKey,
                assigned_user_id: user.id,
                status: 'pending',
              })
          }
        }
      }

      // --- Handle once templates (per-user, never regenerate after any status) ---
      if (onceTemplates.length > 0) {
        const onceTemplateIds = onceTemplates.map((t: any) => t.id)

        const { data: existingOnce } = await supabase
          .from('task_instances' as any)
          .select('template_id, collective_id')
          .in('template_id', onceTemplateIds)
          .eq('assigned_user_id', user.id)

        const existingKeys = new Set(
          (existingOnce ?? []).map((r: any) => `${r.template_id}:${r.collective_id}`),
        )

        for (const template of onceTemplates) {
          const targetCollectives = template.collective_id
            ? [template.collective_id].filter((id: string) => staffCollectiveIds.includes(id))
            : staffCollectiveIds

          for (const collectiveId of targetCollectives) {
            const key = `${template.id}:${collectiveId}`
            if (existingKeys.has(key)) continue

            const periodKey = `once:${user.id}`
            const dueDate = new Date()
            dueDate.setDate(dueDate.getDate() + 7)
            dueDate.setHours(23, 59, 59, 999)

            await supabase
              .from('task_instances' as any)
              .insert({
                template_id: template.id,
                collective_id: collectiveId,
                due_date: dueDate.toISOString(),
                period_key: periodKey,
                assigned_user_id: user.id,
                status: 'pending',
              })
          }
        }
      }

      // --- Handle dynamic timeline templates (event_relative with smart resolution) ---
      await resolveAndGenerateDynamicInstances(staffCollectiveIds)
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['my-tasks'] })
      queryClient.invalidateQueries({ queryKey: ['collective-tasks'] })
    },
  })
}

/* ------------------------------------------------------------------ */
/*  useGroupedTasks — group tasks by collective for display            */
/* ------------------------------------------------------------------ */

export function useGroupedTasks(tasks: MyTask[] | undefined): CollectiveTaskGroup[] {
  return useMemo(() => {
    if (!tasks?.length) return []

    const groups = new Map<string, CollectiveTaskGroup>()
    const now = new Date()

    for (const task of tasks) {
      const cId = task.collective_id
      if (!groups.has(cId)) {
        groups.set(cId, {
          collective_id: cId,
          collective_name: task.collective?.name ?? 'Unknown',
          tasks: [],
          pendingCount: 0,
          overdueCount: 0,
        })
      }
      const group = groups.get(cId)!
      group.tasks.push(task)
      if (task.status === 'pending') {
        group.pendingCount++
        if (new Date(task.due_date) < now) group.overdueCount++
      }
    }

    // Sort groups: ones with overdue tasks first, then by name
    return Array.from(groups.values()).sort((a, b) => {
      if (a.overdueCount > 0 && b.overdueCount === 0) return -1
      if (a.overdueCount === 0 && b.overdueCount > 0) return 1
      return a.collective_name.localeCompare(b.collective_name)
    })
  }, [tasks])
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { supabase } from '@/lib/supabase'

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

export type TimelineAnchor = 'next_event' | 'next_event_of_type' | 'event_series'

export interface TimelineRule {
  id: string
  template_id: string
  anchor: TimelineAnchor
  activity_type_filter: string | null
  series_id_filter: string | null
  offset_days: number
  lookahead_days: number
  match_all_events: boolean
  display_label: string | null
  created_at: string
  updated_at: string
}

export interface TimelineRuleInput {
  template_id: string
  anchor: TimelineAnchor
  activity_type_filter?: string | null
  series_id_filter?: string | null
  offset_days: number
  lookahead_days?: number
  match_all_events?: boolean
}

/* ------------------------------------------------------------------ */
/*  Display label generator                                            */
/* ------------------------------------------------------------------ */

const ACTIVITY_TYPE_LABELS: Record<string, string> = {
  shore_cleanup: 'shore cleanup',
  tree_planting: 'tree planting',
  land_regeneration: 'land regeneration',
  nature_walk: 'nature walk',
  camp_out: 'camp out',
  retreat: 'retreat',
  film_screening: 'film screening',
  marine_restoration: 'marine restoration',
  workshop: 'workshop',
}

export function buildDisplayLabel(rule: {
  anchor: TimelineAnchor
  offset_days: number
  activity_type_filter?: string | null
  match_all_events?: boolean
}): string {
  const days = Math.abs(rule.offset_days)
  const direction = rule.offset_days < 0 ? 'before' : rule.offset_days > 0 ? 'after' : 'on the day of'
  const dayLabel = days === 0 ? '' : `${days} day${days !== 1 ? 's' : ''} ${direction}`

  const allOrNext = rule.match_all_events ? 'each' : "the next"

  let eventLabel = 'event'
  if (rule.anchor === 'next_event_of_type' && rule.activity_type_filter) {
    eventLabel = ACTIVITY_TYPE_LABELS[rule.activity_type_filter] ?? rule.activity_type_filter
  } else if (rule.anchor === 'event_series') {
    eventLabel = 'event in the series'
  }

  if (days === 0) return `On the day of ${allOrNext} ${eventLabel}`
  return `${dayLabel} ${allOrNext} ${eventLabel}`
}

/* ------------------------------------------------------------------ */
/*  Hooks                                                              */
/* ------------------------------------------------------------------ */

export function useTimelineRule(templateId: string | undefined) {
  return useQuery({
    queryKey: ['timeline-rule', templateId],
    queryFn: async () => {
      if (!templateId) return null
      const { data, error } = await supabase
        .from('timeline_rules' as any)
        .select('*')
        .eq('template_id', templateId)
        .maybeSingle()
      if (error) throw error
      return data as TimelineRule | null
    },
    enabled: !!templateId,
    staleTime: 60 * 1000,
  })
}

export function useUpsertTimelineRule() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (input: TimelineRuleInput) => {
      const label = buildDisplayLabel(input)
      const { data, error } = await supabase
        .from('timeline_rules' as any)
        .upsert(
          {
            template_id: input.template_id,
            anchor: input.anchor,
            activity_type_filter: input.activity_type_filter || null,
            series_id_filter: input.series_id_filter || null,
            offset_days: input.offset_days,
            lookahead_days: input.lookahead_days ?? 60,
            match_all_events: input.match_all_events ?? false,
            display_label: label,
          },
          { onConflict: 'template_id' },
        )
        .select('*')
        .single()
      if (error) throw error
      return data as unknown as TimelineRule
    },
    onSuccess: (rule) => {
      queryClient.setQueryData(['timeline-rule', rule.template_id], rule)
      queryClient.invalidateQueries({ queryKey: ['admin-task-templates'] })
    },
  })
}

export function useDeleteTimelineRule() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (templateId: string) => {
      const { error } = await supabase
        .from('timeline_rules' as any)
        .delete()
        .eq('template_id', templateId)
      if (error) throw error
    },
    onSuccess: (_d, templateId) => {
      queryClient.setQueryData(['timeline-rule', templateId], null)
      queryClient.invalidateQueries({ queryKey: ['admin-task-templates'] })
    },
  })
}

/* ------------------------------------------------------------------ */
/*  Dynamic instance resolution                                        */
/* ------------------------------------------------------------------ */

/**
 * Given a list of collectives the current user is staff in, fetch all
 * active event_relative templates with dynamic timelines, resolve their
 * matching events per collective, and generate task instances.
 *
 * This is the core engine. Called during lazy task generation.
 */
export async function resolveAndGenerateDynamicInstances(
  staffCollectiveIds: string[],
): Promise<void> {
  if (staffCollectiveIds.length === 0) return

  // 1. Fetch all active templates that use dynamic timeline
  const { data: templates } = await supabase
    .from('task_templates' as any)
    .select('*')
    .eq('is_active', true)
    .eq('schedule_type', 'event_relative')
    .eq('use_dynamic_timeline', true)

  if (!templates?.length) return

  // 2. Fetch timeline rules for these templates
  const templateIds = (templates as any[]).map((t) => t.id)
  const { data: rules } = await supabase
    .from('timeline_rules' as any)
    .select('*')
    .in('template_id', templateIds)

  if (!rules?.length) return

  const ruleMap = new Map((rules as any[]).map((r) => [r.template_id, r]))

  // 3. For each template + collective combo, find matching events
  const now = new Date()

  for (const template of templates as any[]) {
    const rule = ruleMap.get(template.id)
    if (!rule) continue

    const targetCollectives = template.collective_id
      ? [template.collective_id].filter((id: string) => staffCollectiveIds.includes(id))
      : staffCollectiveIds

    for (const collectiveId of targetCollectives) {
      // Build event query for this collective
      const lookaheadEnd = new Date(now)
      lookaheadEnd.setDate(lookaheadEnd.getDate() + rule.lookahead_days)

      let eventQuery = supabase
        .from('events')
        .select('id, title, date_start, activity_type, series_id')
        .eq('collective_id', collectiveId)
        .eq('status', 'published')
        .gte('date_start', now.toISOString())
        .lte('date_start', lookaheadEnd.toISOString())
        .order('date_start', { ascending: true })

      // Apply anchor-specific filters
      if (rule.anchor === 'next_event_of_type' && rule.activity_type_filter) {
        eventQuery = eventQuery.eq('activity_type', rule.activity_type_filter)
      }
      if (rule.anchor === 'event_series' && rule.series_id_filter) {
        eventQuery = eventQuery.eq('series_id', rule.series_id_filter)
      }

      // Limit to 1 if not matching all events
      if (!rule.match_all_events) {
        eventQuery = eventQuery.limit(1)
      }

      const { data: events } = await eventQuery
      if (!events?.length) continue

      // Generate an instance for each matched event
      for (const event of events) {
        const eventDate = new Date(event.date_start)
        const dueDate = new Date(eventDate)
        dueDate.setDate(dueDate.getDate() + rule.offset_days)
        dueDate.setHours(23, 59, 59, 999)

        const periodKey = `event:${event.id}`

        // Upsert — deduplication by (template_id, collective_id, period_key)
        await supabase
          .from('task_instances' as any)
          .upsert(
            {
              template_id: template.id,
              collective_id: collectiveId,
              event_id: event.id,
              due_date: dueDate.toISOString(),
              period_key: periodKey,
              status: 'pending',
            },
            { onConflict: 'template_id,collective_id,period_key' },
          )
      }
    }
  }
}

import { supabase } from '@/lib/supabase'

interface AuditEntry {
  action: string
  target_type?: string
  target_id?: string | null
  details?: Record<string, unknown>
}

/**
 * Log an admin action to the audit_log table.
 * Non-throwing — logs errors to console but never blocks the caller.
 */
export async function logAudit(entry: AuditEntry): Promise<void> {
  try {
    const { data: { user } } = await supabase.auth.getUser()
    if (!user) return

    await supabase.from('audit_log' as any).insert({
      user_id: user.id,
      action: entry.action,
      target_type: entry.target_type ?? null,
      target_id: entry.target_id ?? null,
      details: entry.details ?? {},
    })
  } catch (err) {
    console.error('[audit] Failed to log:', entry.action, err)
  }
}

/* ------------------------------------------------------------------ */
/*  Sentry Error Logging                                               */
/*                                                                     */
/*  Setup:                                                             */
/*  1. npm install @sentry/react                                       */
/*  2. Set VITE_SENTRY_DSN in .env                                     */
/*  3. Call initSentry() in main.tsx before React renders              */
/*  4. Wrap <App /> with <SentryErrorBoundary>                         */
/* ------------------------------------------------------------------ */

import { type ReactNode, Component, type ErrorInfo } from 'react'
import { Capacitor } from '@capacitor/core'
import { Button } from '@/components/button'

/* ------------------------------------------------------------------ */
/*  Sentry initialisation                                              */
/* ------------------------------------------------------------------ */

let Sentry: {
  init: (opts: Record<string, unknown>) => void
  captureException: (error: unknown, context?: Record<string, unknown>) => void
  captureMessage: (message: string, level?: unknown) => void
  setUser: (user: { id: string; email?: string } | null) => void
  setTag: (key: string, value: string) => void
  addBreadcrumb: (breadcrumb: Record<string, unknown>) => void
} | null = null

export async function initSentry() {
  const dsn = import.meta.env.VITE_SENTRY_DSN
  if (!dsn) {
    console.warn('[sentry] No DSN configured - error reporting disabled')
    return
  }

  try {
    // eslint-disable-next-line @typescript-eslint/ban-ts-comment
    // @ts-ignore - optional dependency, may not be installed
    const mod = await import(/* @vite-ignore */ '@sentry/react')
    Sentry = mod as any

    mod.init({
      dsn,
      environment: import.meta.env.MODE,
      release: `coexist@${import.meta.env.VITE_APP_VERSION || '1.0.0'}`,
      tracesSampleRate: import.meta.env.PROD ? 0.1 : 1.0,
      replaysSessionSampleRate: 0,
      replaysOnErrorSampleRate: import.meta.env.PROD ? 0.5 : 0,
      integrations: [],
      beforeSend(event) {
        // Strip PII from breadcrumbs if needed
        return event
      },
    })

    // Tag platform
    mod.setTag('platform', Capacitor.getPlatform())
    mod.setTag('is_native', String(Capacitor.isNativePlatform()))
  } catch {
    console.warn('[sentry] @sentry/react not installed - error reporting disabled')
  }
}

/* ------------------------------------------------------------------ */
/*  Public API (safe to call even if Sentry not loaded)                */
/* ------------------------------------------------------------------ */

export function captureException(error: unknown, context?: Record<string, unknown>) {
  console.error('[error]', error)
  Sentry?.captureException(error, context)
}

export function captureMessage(message: string, level: 'info' | 'warning' | 'error' = 'info') {
  Sentry?.captureMessage(message, level)
}

export function setUser(user: { id: string; email?: string } | null) {
  Sentry?.setUser(user)
}

export function addBreadcrumb(breadcrumb: {
  category?: string
  message: string
  level?: 'info' | 'warning' | 'error'
  data?: Record<string, unknown>
}) {
  Sentry?.addBreadcrumb(breadcrumb)
}

/* ------------------------------------------------------------------ */
/*  Error Boundary with branded error screen                           */
/* ------------------------------------------------------------------ */

interface ErrorBoundaryProps {
  children: ReactNode
  fallback?: ReactNode
}

interface ErrorBoundaryState {
  hasError: boolean
  error: Error | null
}

export class SentryErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  constructor(props: ErrorBoundaryProps) {
    super(props)
    this.state = { hasError: false, error: null }
  }

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error }
  }

  componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    captureException(error, {
      extra: { componentStack: errorInfo.componentStack },
    })
  }

  handleRetry = () => {
    this.setState({ hasError: false, error: null })
  }

  handleReload = () => {
    window.location.reload()
  }

  render() {
    if (this.state.hasError) {
      if (this.props.fallback) return this.props.fallback

      return (
        <div className="flex flex-col items-center justify-center min-h-dvh p-6 text-center bg-white">
          <div className="w-16 h-16 mb-4 rounded-2xl bg-error-100 flex items-center justify-center">
            <svg
              width="28"
              height="28"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
              className="text-error-600"
            >
              <circle cx="12" cy="12" r="10" />
              <line x1="12" y1="8" x2="12" y2="12" />
              <line x1="12" y1="16" x2="12.01" y2="16" />
            </svg>
          </div>
          <h2 className="font-heading text-xl font-bold text-primary-800 mb-2">
            Something went wrong
          </h2>
          <p className="text-sm text-primary-400 mb-6 max-w-xs leading-relaxed">
            We&apos;ve been notified and are looking into it.
            Try refreshing or going back.
          </p>
          <div className="flex gap-2">
            <Button variant="secondary" onClick={this.handleRetry}>
              Try Again
            </Button>
            <Button variant="primary" onClick={this.handleReload}>
              Refresh App
            </Button>
          </div>
          {import.meta.env.DEV && this.state.error && (
            <pre className="mt-6 text-left text-xs text-error-600 bg-error-50 p-3 rounded-lg max-w-sm overflow-auto max-h-40">
              {this.state.error.message}
              {'\n'}
              {this.state.error.stack}
            </pre>
          )}
        </div>
      )
    }

    return this.props.children
  }
}

