          </div>
        </motion.div>
      )}

      {/* ── Leadership team ── */}
      <motion.div
        initial={rm ? { opacity: 1 } : { opacity: 0, y: 12 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.3, delay: 0.35 }}
