const healthConfig = {
  healthy: { color: 'bg-success-100 text-success-700', label: 'Healthy' },
  moderate: { color: 'bg-warning-100 text-warning-700', label: 'Moderate' },
  'needs-attention': { color: 'bg-error-100 text-error-700', label: 'Needs Attention' },
} as const

const AUSTRALIAN_STATES = [
  '', 'NSW', 'VIC', 'QLD', 'WA', 'SA', 'TAS', 'ACT', 'NT',
] as const

type StatusFilter = 'all' | 'active' | 'archived'

/* ------------------------------------------------------------------ */
/*  Hero stat card (matches /admin dashboard)                          */
/* ------------------------------------------------------------------ */

function HeroStatCard({
  value,
  label,
  icon,
  reducedMotion,
  delay = 0,
}: {
  value: number
  label: string
  icon: React.ReactNode
  reducedMotion: boolean
  delay?: number
}) {
  const display = useCountUp(value, 1200, !reducedMotion)

  return (
    <motion.div
      initial={reducedMotion ? { opacity: 1 } : { opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{
        duration: 0.5,
        delay: reducedMotion ? 0 : 0.2 + delay * 0.8,
        ease: [0.25, 0.46, 0.45, 0.94],
      }}
      className="flex flex-col items-center text-center py-6 px-3"
      aria-label={`${label}: ${value}`}
    >
      <span className="flex items-center justify-center w-10 h-10 rounded-xl bg-white/[0.08] text-white/70 mb-3" aria-hidden="true">
        {icon}
      </span>
      <p
        style={{ fontFamily: 'system-ui, -apple-system, sans-serif' }}
        className="text-3xl sm:text-4xl font-bold tracking-tight tabular-nums text-white"
      >
        {display.toLocaleString()}
      </p>
      <p className="mt-1.5 text-xs font-medium text-white/45 tracking-wide uppercase">{label}</p>
    </motion.div>
  )
}

/* ------------------------------------------------------------------ */
/*  Create collective modal                                            */
/* ------------------------------------------------------------------ */

function CreateCollectiveModal({
  open,
  onClose,
}: {
  open: boolean
  onClose: () => void
}) {
  const { toast } = useToast()
  const createCollective = useCreateCollective()
  const [name, setName] = useState('')
  const [description, setDescription] = useState('')
  const [region, setRegion] = useState('')
  const [state, setState] = useState('')

  const handleCreate = async () => {
    try {
      await createCollective.mutateAsync({
        name,
        description: description || undefined,
        region: region || undefined,
        state: state || undefined,
      })
      toast.success('Collective created')
      setName('')
      setDescription('')
      setRegion('')
      setState('')
      onClose()
    } catch {
      toast.error('Failed to create collective')
    }
  }

  return (
    <Modal open={open} onClose={onClose} title="Create Collective">
      <div className="space-y-4">
        <Input
          label="Collective Name"
          value={name}
          onChange={(e) => setName(e.target.value)}
          required
          placeholder="e.g. Byron Bay Collective"
        />
        <div>
          <label className="block text-xs font-semibold text-primary-500 uppercase tracking-wider mb-1">
            Description
          </label>
          <textarea
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            placeholder="What does this collective focus on?"
            rows={3}
            className={cn(
              'w-full rounded-xl bg-primary-50/50 px-3 py-2.5 text-sm text-primary-800',
              'placeholder:text-primary-400',
              'focus:outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white',
              'resize-none',
            )}
          />
        </div>
        <Input
          label="Region"
          value={region}
          onChange={(e) => setRegion(e.target.value)}
          placeholder="e.g. Byron Bay"
        />
        <div>
          <label className="block text-xs font-semibold text-primary-500 uppercase tracking-wider mb-1">
            State
          </label>
          <select
            value={state}
            onChange={(e) => setState(e.target.value)}
            className={cn(
              'w-full rounded-xl bg-primary-50/50 px-3 py-2.5 text-sm text-primary-800',
              'focus:outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white',
            )}
          >
            <option value="">Select state...</option>
            {AUSTRALIAN_STATES.filter(Boolean).map((s) => (
              <option key={s} value={s}>{s}</option>
            ))}
          </select>
        </div>
        <Button
          variant="primary"
          fullWidth
          onClick={handleCreate}
          loading={createCollective.isPending}
          disabled={!name.trim()}
        >
          Create Collective
        </Button>
      </div>
    </Modal>
  )
}

