/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

interface AdminEvent {
  id: string
  title: string
  date_start: string
  date_end: string | null
  address: string | null
  cover_image_url: string | null
  collective_id: string
  capacity: number | null
  activity_type: string | null
  status: 'draft' | 'published' | 'cancelled' | 'completed'
  collectives: { name: string; region: string | null; state: string | null } | null
  registrationCount: number
}

interface CollectiveGroup {
  collectiveId: string
  collectiveName: string
  region: string | null
  state: string | null
  events: AdminEvent[]
  totalRegistrations: number
}

type StatusFilter = 'upcoming' | 'past' | 'all' | 'draft' | 'cancelled'

/* ------------------------------------------------------------------ */
/*  Activity type styling                                              */
/* ------------------------------------------------------------------ */

const activityColors: Record<string, string> = {
  shore_cleanup: 'bg-sky-100 text-sky-700',
  tree_planting: 'bg-sprout-100 text-sprout-700',
  land_regeneration: 'bg-moss-100 text-moss-700',
  nature_walk: 'bg-bark-100 text-bark-700',
  camp_out: 'bg-moss-100 text-moss-700',
  retreat: 'bg-plum-100 text-plum-700',
  film_screening: 'bg-coral-100 text-coral-700',
  marine_restoration: 'bg-primary-100 text-primary-700',
  workshop: 'bg-bark-100 text-bark-700',
}

function activityLabel(type: string | null): string {
  if (!type) return 'Event'
  return type
    .replace(/_/g, ' ')
    .replace(/\b\w/g, (c) => c.toUpperCase())
}

const statusBadgeStyles: Record<string, { label: string; className: string }> = {
  draft: { label: 'Draft', className: 'bg-primary-100 text-primary-600' },
  published: { label: 'Live', className: 'bg-success-100 text-success-700' },
  cancelled: { label: 'Cancelled', className: 'bg-error-100 text-error-700' },
  completed: { label: 'Completed', className: 'bg-info-100 text-info-700' },
}

/* ------------------------------------------------------------------ */
/*  Data hooks                                                         */
/* ------------------------------------------------------------------ */

function useAdminEventsData() {
  return useQuery({
    queryKey: ['admin-events-dashboard'],
    queryFn: async () => {
      const now = new Date().toISOString()

      // Fetch all events with collective info
      const { data: events, error } = await supabase
        .from('events')
        .select(
          'id, title, date_start, date_end, address, cover_image_url, collective_id, capacity, activity_type, status, collectives(name, region, state)' as any,
        )
        .order('date_start' as any, { ascending: true })
        .limit(200)

      if (error) throw error

      // Get registration counts in parallel
      const enriched: AdminEvent[] = await Promise.all(
        ((events ?? []) as any[]).map(async (event: any) => {
          const { count } = await supabase
            .from('event_registrations')
            .select('id', { count: 'exact', head: true })
            .eq('event_id', event.id)

          return { ...event, registrationCount: count ?? 0 }
        }),
      )

      // Split into upcoming and past
      const upcoming = enriched.filter((e) => e.date_start >= now)
      const past = enriched.filter((e) => e.date_start < now)

      // Calculate stats
      const totalRegistrations = enriched.reduce((sum, e) => sum + e.registrationCount, 0)
      const upcomingRegistrations = upcoming.reduce((sum, e) => sum + e.registrationCount, 0)
      const avgAttendance =
        past.length > 0
          ? Math.round(past.reduce((sum, e) => sum + e.registrationCount, 0) / past.length)
          : 0

      // Find the hottest upcoming event (most registrations)
      const hottestEvent = upcoming.length > 0
        ? upcoming.reduce((a, b) => (a.registrationCount > b.registrationCount ? a : b))
        : null

      // Count unique collectives with upcoming events
      const activeCollectives = new Set(upcoming.map((e) => e.collective_id)).size

      return {
        all: enriched,
        upcoming,
        past,
        stats: {
          total: enriched.length,
          upcoming: upcoming.length,
          totalRegistrations,
          upcomingRegistrations,
          avgAttendance,
          activeCollectives,
          hottestEvent,
        },
      }
    },
    staleTime: 60 * 1000,
  })
}

/* ------------------------------------------------------------------ */
/*  Helpers                                                            */
/* ------------------------------------------------------------------ */

function formatDate(dateStr: string): string {
  return new Date(dateStr).toLocaleDateString('en-AU', {
    weekday: 'short',
    day: 'numeric',
    month: 'short',
  })
}

function formatTime(dateStr: string): string {
  return new Date(dateStr).toLocaleTimeString('en-AU', {
    hour: 'numeric',
    minute: '2-digit',
  })
}

function daysUntil(dateStr: string): number {
  const now = new Date()
  const target = new Date(dateStr)
  return Math.ceil((target.getTime() - now.getTime()) / (1000 * 60 * 60 * 24))
}

function groupByCollective(events: AdminEvent[]): CollectiveGroup[] {
  const map = new Map<string, CollectiveGroup>()

  for (const event of events) {
    const key = event.collective_id
    if (!map.has(key)) {
      map.set(key, {
        collectiveId: key,
        collectiveName: event.collectives?.name ?? 'Unknown',
        region: event.collectives?.region ?? null,
        state: event.collectives?.state ?? null,
        events: [],
        totalRegistrations: 0,
      })
    }
    const group = map.get(key)!
    group.events.push(event)
    group.totalRegistrations += event.registrationCount
  }

  // Sort by nearest upcoming event first
  return Array.from(map.values()).sort((a, b) => {
    const aNext = a.events[0]?.date_start ?? ''
    const bNext = b.events[0]?.date_start ?? ''
    return aNext.localeCompare(bNext)
  })
}

/* ------------------------------------------------------------------ */
/*  Countdown badge                                                    */
/* ------------------------------------------------------------------ */

function CountdownBadge({ dateStr }: { dateStr: string }) {
  const days = daysUntil(dateStr)

  if (days < 0) return null
  if (days === 0) {
    return (
      <span className="inline-flex items-center gap-1 text-[11px] font-bold px-2 py-0.5 rounded-full bg-success-100 text-success-700 animate-pulse">
        <Flame size={10} /> Today
      </span>
    )
  }
  if (days <= 3) {
    return (
      <span className="inline-flex items-center gap-1 text-[11px] font-bold px-2 py-0.5 rounded-full bg-warning-100 text-warning-700">
        <Clock size={10} /> {days}d away
      </span>
    )
  }
  if (days <= 14) {
    return (
      <span className="text-[11px] font-semibold px-2 py-0.5 rounded-full bg-primary-50 text-primary-500">
        {days}d away
      </span>
    )
  }
  return null
}

