  const [email, setEmail] = useState('')
  const [message, setMessage] = useState('')
  const [sending, setSending] = useState(false)

  const canSubmit = name.trim() && email.trim() && message.trim() && !sending

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!canSubmit) return

    setSending(true)
    try {
      const { error } = await (supabase as any)
        .from('contact_submissions')
        .insert({
          name: name.trim(),
          email: email.trim(),
          message: message.trim(),
          user_id: profile?.id ?? null,
        })

      if (error) throw error

      toast.toast.success('Message sent! We\'ll get back to you soon.')
      setMessage('')
    } catch {
      toast.toast.error('Something went wrong. Please try emailing us directly.')
    } finally {
      setSending(false)
    }
  }

  return (
    <Page
      header={
        <header
          className="sticky top-0 z-40 px-5 pt-2 pb-3"
