            className="font-heading text-2xl font-bold text-primary-800"
          >
            Thank you!
          </motion.h1>

          {/* Amount */}
          <motion.p
            initial={shouldReduceMotion ? false : { opacity: 0, y: 12 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.4 }}
            className="mt-2 text-lg font-semibold text-primary-400"
