                type="button"
                onClick={() => navigate(-1)}
                whileTap={{ scale: 0.9 }}
                className="flex items-center justify-center w-10 h-10 rounded-full bg-black/50 text-white cursor-pointer select-none active:scale-95 transition-all duration-150"
                aria-label="Go back"
              >
                <ArrowLeft size={20} />
              </motion.button>
              <motion.button
                type="button"
                onClick={handleShare}
                whileTap={{ scale: 0.9 }}
                className="flex items-center justify-center w-10 h-10 rounded-full bg-black/50 text-white cursor-pointer select-none active:scale-95 transition-all duration-150"
                aria-label="Share event"
              >
                <Share2 size={18} />
              </motion.button>
            </div>

            {/* Activity badge on image */}
            <div className="absolute top-16 right-3" style={{ marginTop: 'var(--safe-top, 0px)' }}>
              <Badge
                variant="activity"
                activity={activityToBadge[event.activity_type] ?? 'workshop'}
                size="md"
              >
                {ACTIVITY_TYPE_LABELS[event.activity_type] ?? event.activity_type}
              </Badge>
            </div>

            {/* Title overlay */}
            <div className="absolute bottom-0 left-0 right-0 p-5 pb-10 z-[5]">
