/* ------------------------------------------------------------------ */
/*  Date range selector with quick presets                             */
/* ------------------------------------------------------------------ */

function DateRangeSelector({
  dateFrom,
  dateTo,
  onChange,
}: {
  dateFrom: string | null
  dateTo: string | null
  onChange: (from: string | null, to: string | null) => void
}) {
  const presets = useMemo(() => getDatePresets(), [])
  const activePreset = presets.find(
    (p) => p.from === dateFrom && p.to === dateTo,
  )

  return (
    <div className="space-y-4">
      {/* Quick presets */}
      <div className="grid grid-cols-2 gap-2">
        {presets.map((preset) => {
          const isActive = activePreset === preset
          return (
            <button
              key={preset.label}
              type="button"
              onClick={() => {
                if (isActive) {
                  onChange(null, null)
                } else {
                  onChange(preset.from, preset.to)
                }
              }}
              className={cn(
                'flex items-center gap-2 px-3 py-2.5 min-h-11 rounded-xl',
                'text-sm font-medium text-left active:scale-[0.97] transition-all duration-150 cursor-pointer select-none',
                'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-primary-400',
                isActive
                  ? 'bg-primary-600 text-white shadow-sm'
                  : 'bg-white text-primary-600 ring-1 ring-primary-100 hover:ring-primary-200 hover:bg-primary-50/50',
              )}
              aria-pressed={isActive}
            >
              <Calendar size={14} className={isActive ? 'text-white/70' : 'text-primary-300'} />
              {preset.label}
            </button>
          )
        })}
      </div>

      {/* Custom date inputs - collapsible */}
      <div>
        <p className="text-xs font-medium text-primary-400 mb-2">
          Or pick exact dates
        </p>
        <div className="grid grid-cols-2 gap-3">
          <div>
            <label className="text-[11px] font-medium text-primary-400 uppercase tracking-wider block mb-1">
              From
            </label>
            <input
              type="date"
              value={dateFrom ?? ''}
              onChange={(e) =>
                onChange(e.target.value || null, dateTo)
              }
              className={cn(
                'w-full h-11 px-3 rounded-xl',
                'text-sm bg-primary-50/50',
                'focus:outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white',
                'transition-all duration-150',
                dateFrom
                  ? 'text-primary-800'
                  : 'text-primary-400',
              )}
              style={{ fontSize: '16px' }}
            />
          </div>
          <div>
            <label className="text-[11px] font-medium text-primary-400 uppercase tracking-wider block mb-1">
              To
            </label>
            <input
              type="date"
              value={dateTo ?? ''}
              onChange={(e) =>
                onChange(dateFrom, e.target.value || null)
              }
              className={cn(
                'w-full h-11 px-3 rounded-xl',
                'text-sm bg-primary-50/50',
                'focus:outline-none focus:ring-2 focus:ring-primary-400 focus:bg-white',
                'transition-all duration-150',
                dateTo
                  ? 'text-primary-800'
                  : 'text-primary-400',
              )}
              style={{ fontSize: '16px' }}
            />
          </div>
        </div>
      </div>
    </div>
  )
}

