                <Chip
                  key={type}
                  label={formatActivityType(type)}
                  icon={meta.icon}
                  selected
                  variant="activity"
                  onDismiss={() => toggleActivityFilter(type)}
                />
              )
            })}
            {filters.state && (
              <Chip
                label={
                  AU_STATES.find((s) => s.value === filters.state)?.label ??
                  filters.state
