                </div>
              ))}
            </div>
          </motion.section>
        )}

        {/* ─── Export / Share ─── */}
        <motion.div variants={fadeUp} className="mx-5 mt-10 flex gap-3">
          <Button
            variant="primary"
            icon={<Download size={16} />}
            onClick={exportPDF}
          >
            Export PDF
          </Button>
          <Button
            variant="secondary"
            icon={<Share2 size={16} />}
            onClick={shareLink}
          >
            Share
          </Button>
        </motion.div>
      </motion.div>
  )

  if (isAdmin) return content

  return (
    <Page
      header={
        <Header
          title="National Impact"
          back
        />
      }
    >
      {content}
    </Page>
  )
}

