import { useNavigate } from 'react-router-dom'
import { motion, useReducedMotion, type Variants } from 'framer-motion'
import {
  Settings,
  ShoppingBag,
  Heart,
  Bell,
  Megaphone,
  Users,
  BarChart3,
  Plus,
  Shield,
  Handshake,
  Mail,
  ChevronRight,
  Leaf,
  CalendarDays,
} from 'lucide-react'
import { Page } from '@/components/page'
import { Avatar } from '@/components/avatar'
import { cn } from '@/lib/cn'
import { useAuth } from '@/hooks/use-auth'
interface MenuLink {
  label: string
  to: string
  icon: React.ReactNode
  iconBg: string
  iconColor: string
  description?: string
}

const stagger: Variants = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.04 } },
}

const fadeUp: Variants = {
  hidden: { opacity: 0, y: 12 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.25, ease: [0.25, 0.1, 0.25, 1] } },
}

function MenuSection({
  title,
  items,
  navigate,
  shouldReduceMotion,
}: {
  title: string
  items: MenuLink[]
  navigate: (to: string) => void
  shouldReduceMotion: boolean | null
}) {
  return (
    <motion.section
      variants={shouldReduceMotion ? undefined : fadeUp}
    >
      <h3 className="text-[11px] font-semibold uppercase tracking-wider text-primary-400/70 mb-1.5 px-1">
        {title}
      </h3>
      <div className="rounded-2xl bg-surface-0 shadow-sm overflow-hidden">
        {items.map(({ label, to, icon, iconBg, iconColor, description }, idx) => (
          <button
            key={to}
            type="button"
            onClick={() => navigate(to)}
            className={cn(
              'w-full flex items-center gap-3.5 px-4 py-3',
              'text-left transition-all duration-150',
              'active:bg-surface-3',
              'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-primary-400',
              'cursor-pointer select-none',
              idx > 0 && 'border-t border-primary-100/20',
            )}
          >
            <span
              className={cn(
                'flex items-center justify-center w-8 h-8 rounded-lg shrink-0',
                iconBg,
                iconColor,
              )}
            >
              {icon}
            </span>
            <div className="flex-1 min-w-0">
              <p className="text-[15px] font-medium text-primary-900 leading-tight">{label}</p>
            </div>
            <ChevronRight size={16} className="text-primary-300/60 shrink-0" />
          </button>
        ))}
      </div>
    </motion.section>
  )
}

