import { useState, useCallback } from 'react'
import { useNavigate } from 'react-router-dom'
import { motion, AnimatePresence, useReducedMotion } from 'framer-motion'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/hooks/use-auth'
import { cn } from '@/lib/cn'

import { StepProfilePhoto } from './steps/step-profile-photo'
import { StepNameHandle } from './steps/step-name-handle'
import { StepLocation } from './steps/step-location'
import { StepInterests } from './steps/step-interests'
import { StepCollective } from './steps/step-collective'
import { StepFirstEvent } from './steps/step-first-event'
import { StepCelebration } from './steps/step-celebration'

const TOTAL_STEPS = 6

const slideVariants = {
  enter: (direction: number) => ({
    x: direction > 0 ? '100%' : '-100%',
    opacity: 0,
  }),
  center: { x: 0, opacity: 1 },
  exit: (direction: number) => ({
    x: direction > 0 ? '-100%' : '100%',
    opacity: 0,
  }),
}

export default function OnboardingPage() {
  const navigate = useNavigate()
  const { user, refreshProfile, markOnboardingComplete } = useAuth()
  const shouldReduceMotion = useReducedMotion()

  const [step, setStep] = useState(0)
  const [direction, setDirection] = useState(1)
  const [showCelebration, setShowCelebration] = useState(false)

  // Shared onboarding data
  const [data, setData] = useState({
    avatarUrl: null as string | null,
    displayName: '',
    instagramHandle: '',
    location: '',
    locationPoint: null as { lat: number; lng: number } | null,
    interests: [] as string[],
    collectiveId: null as string | null,
  })

  const updateData = useCallback(
    (patch: Partial<typeof data>) => setData((prev) => ({ ...prev, ...patch })),
    [],
  )

  const completeOnboarding = useCallback(async () => {
    if (!user) return

    // Build profile payload - upsert guarantees the row exists even if the
    // auth trigger hasn't fired yet, preventing the FK violation on
    // collective_members when we insert below.
    const profilePayload: Record<string, unknown> = {
      id: user.id,
      onboarding_completed: true,
      updated_at: new Date().toISOString(),
    }

    if (data.displayName) profilePayload.display_name = data.displayName
    if (data.instagramHandle) profilePayload.instagram_handle = data.instagramHandle
    if (data.location) profilePayload.location = data.location
    if (data.interests.length > 0) profilePayload.interests = data.interests
    if (data.avatarUrl) profilePayload.avatar_url = data.avatarUrl

    const { error: profileError } = await supabase
      .from('profiles')
      .upsert(profilePayload as any, { onConflict: 'id' })

    if (profileError) {
      console.error('[onboarding] Failed to save profile:', profileError)
      return
    }

    // Join collective if selected - profile row is now guaranteed to exist
    if (data.collectiveId) {
      const { error: memberError } = await supabase
        .from('collective_members')
        .insert({
          collective_id: data.collectiveId,
          user_id: user.id,
          role: 'member',
          status: 'active',
        })

      if (memberError) {
        console.error('[onboarding] Failed to join collective:', memberError)
      }
    }

    markOnboardingComplete()
    await refreshProfile()
    setShowCelebration(true)
  }, [user, data, markOnboardingComplete, refreshProfile])

  const goNext = useCallback(() => {
    if (step < TOTAL_STEPS - 1) {
      setDirection(1)
      setStep((s) => s + 1)
    } else {
      completeOnboarding()
    }
  }, [step, completeOnboarding])

  const goBack = useCallback(() => {
    if (step > 0) {
      setDirection(-1)
      setStep((s) => s - 1)
    }
  }, [step])

  if (showCelebration) {
    return <StepCelebration onContinue={() => navigate('/', { replace: true })} />
  }

  const steps = [
    <StepProfilePhoto
      key="photo"
      avatarUrl={data.avatarUrl}
      onUpload={(url) => updateData({ avatarUrl: url })}
      onNext={goNext}
      onSkip={goNext}
    />,
    <StepNameHandle
      key="name"
      displayName={data.displayName}
      instagramHandle={data.instagramHandle}
      onChange={(name, handle) => updateData({ displayName: name, instagramHandle: handle })}
      onNext={goNext}
      onSkip={goNext}
    />,
    <StepLocation
      key="location"
      location={data.location}
      onChange={(loc, point) => updateData({ location: loc, locationPoint: point })}
      onNext={goNext}
      onSkip={goNext}
    />,
    <StepInterests
      key="interests"
      selected={data.interests}
      onChange={(interests) => updateData({ interests })}
      onNext={goNext}
      onSkip={goNext}
    />,
    <StepCollective
      key="collective"
      selectedId={data.collectiveId}
      onSelect={(id) => updateData({ collectiveId: id })}
      onNext={goNext}
      onSkip={goNext}
    />,
    <StepFirstEvent
      key="event"
      collectiveId={data.collectiveId}
      onNext={goNext}
      onSkip={goNext}
    />,
  ]

  return (
    <div className="h-dvh flex flex-col bg-white overflow-hidden">
      {/* Progress dots */}
      <div className="flex items-center justify-center gap-2 pt-6 pb-4 px-6">
        {Array.from({ length: TOTAL_STEPS }, (_, i) => (
          <motion.div
            key={i}
            className={cn(
              'h-1.5 rounded-full transition-colors duration-300',
              i === step ? 'bg-primary-500 w-6' : i < step ? 'bg-primary-300 w-1.5' : 'bg-white w-1.5',
            )}
            layout={!shouldReduceMotion}
          />
        ))}
      </div>

      {/* Back button (visible from step 1 onward) */}
      {step > 0 && (
        <button
          type="button"
          onClick={goBack}
          className="self-start ml-4 mb-2 text-sm text-primary-400 hover:text-primary-800 cursor-pointer"
        >
          &larr; Back
        </button>
      )}

      {/* Step content with animated transitions */}
      <div className="flex-1 relative overflow-hidden">
        <AnimatePresence mode="wait" custom={direction}>
          <motion.div
            key={step}
            custom={direction}
            variants={shouldReduceMotion ? undefined : slideVariants}
            initial={shouldReduceMotion ? false : 'enter'}
            animate="center"
            exit={shouldReduceMotion ? undefined : 'exit'}
            transition={{ type: 'spring', stiffness: 300, damping: 30 }}
            className="absolute inset-0 flex flex-col"
          >
            {steps[step]}
          </motion.div>
        </AnimatePresence>
      </div>
    </div>
  )
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { motion, useReducedMotion } from 'framer-motion'
import { Calendar, MapPin, Check } from 'lucide-react'
import { supabase } from '@/lib/supabase'
import { useAuth } from '@/hooks/use-auth'
import { useDelayedLoading } from '@/hooks/use-delayed-loading'
import { Button } from '@/components/button'
import { Skeleton } from '@/components/skeleton'
import { cn } from '@/lib/cn'
import type { Database } from '@/types/database.types'

type Event = Database['public']['Tables']['events']['Row']

const stagger = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.04 } },
}

const fadeUp = {
  hidden: { opacity: 0, y: 12 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.25 } },
}

interface StepFirstEventProps {
  collectiveId: string | null
  onNext: () => void
  onSkip: () => void
}

export function StepFirstEvent({ collectiveId, onNext, onSkip }: StepFirstEventProps) {
  const { user } = useAuth()
  const shouldReduceMotion = useReducedMotion()
  const queryClient = useQueryClient()

  const { data: events, isLoading } = useQuery({
    queryKey: ['onboarding-events', collectiveId],
    queryFn: async () => {
      let query = supabase
        .from('events')
        .select('*')
        .eq('status', 'published')
        .gte('date_start', new Date().toISOString())
        .order('date_start', { ascending: true })
        .limit(5)

      if (collectiveId) {
        query = query.eq('collective_id', collectiveId)
      }

      const { data } = await query
      return data as Event[]
    },
  })
  const showLoading = useDelayedLoading(isLoading)

  const rsvpMutation = useMutation({
    mutationFn: async (eventId: string) => {
      if (!user) throw new Error('Not authenticated')
      const { error } = await supabase
        .from('event_registrations')
        .insert({ event_id: eventId, user_id: user.id, status: 'registered' })
      if (error) throw error
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['onboarding-events'] })
    },
  })

  function formatDate(dateStr: string) {
    const d = new Date(dateStr)
    return d.toLocaleDateString('en-AU', { weekday: 'short', month: 'short', day: 'numeric' })
  }

  return (
    <div className="flex-1 flex flex-col px-6 pt-8 min-h-0">
      <motion.div
        className="flex-1 overflow-y-auto"
        variants={shouldReduceMotion ? undefined : stagger}
        initial="hidden"
        animate="visible"
      >
        <motion.h2 variants={fadeUp} className="font-heading text-2xl font-bold text-primary-800">
          Find your first event
        </motion.h2>
        <motion.p variants={fadeUp} className="mt-2 text-primary-400 leading-relaxed">
          Jump in! One tap to RSVP.
        </motion.p>

        <div className="mt-6 space-y-3">
          {showLoading ? (
            <Skeleton variant="list-item" count={3} />
          ) : events && events.length > 0 ? (
            events.map((event) => (
              <motion.div
                key={event.id}
                variants={fadeUp}
                className="flex items-start gap-3 p-4 rounded-xl shadow-sm bg-white"
              >
                <div className="w-12 h-12 rounded-lg bg-accent-100 flex flex-col items-center justify-center shrink-0">
                  <Calendar size={16} className="text-primary-400" />
                </div>

                <div className="flex-1 min-w-0">
                  <p className="font-semibold text-primary-800 truncate">{event.title}</p>
                  <p className="text-xs text-primary-400 mt-0.5">{formatDate(event.date_start)}</p>
                  {event.address && (
                    <p className="flex items-center gap-1 text-xs text-primary-400 mt-0.5">
                      <MapPin size={10} />
                      <span className="truncate">{event.address}</span>
                    </p>
                  )}
                </div>

                <Button
                  size="sm"
                  variant={rsvpMutation.isPending ? 'ghost' : 'primary'}
                  onClick={() => rsvpMutation.mutate(event.id)}
                  disabled={rsvpMutation.isPending}
                  icon={rsvpMutation.isSuccess ? <Check size={14} /> : undefined}
                >
                  {rsvpMutation.isSuccess ? 'Going' : 'RSVP'}
                </Button>
              </motion.div>
            ))
          ) : (
            <div className="text-center py-8">
              <p className="text-sm text-primary-400">No upcoming events right now.</p>
              <p className="text-xs text-primary-400 mt-1">Don't worry - we'll notify you when one pops up!</p>
            </div>
          )}
        </div>
      </motion.div>

      <div
        className="py-6 space-y-3"
        style={{ paddingBottom: 'max(1.5rem, env(safe-area-inset-bottom))' }}
      >
        <Button variant="primary" size="lg" fullWidth onClick={onNext}>
          Continue
        </Button>
        <Button variant="ghost" size="lg" fullWidth onClick={onSkip}>
          Skip for now
        </Button>
      </div>
    </div>
  )
}

