                return (
                  <Card
                    key={collective.id}
                    variant="collective"
                    onClick={() => navigate(`/collectives/${collective.slug}`)}
                    className="flex flex-row items-center gap-3 p-3 bg-gradient-to-r from-moss-100 via-moss-50 to-white shadow-md border border-moss-200/80"
                  >
                    <div className="shrink-0 w-12 h-12 rounded-xl overflow-hidden bg-gradient-to-br from-moss-300 to-primary-300 shadow-sm">
                      {collective.cover_image_url ? (
                        <img
                          src={collective.cover_image_url}
                          alt={collective.name}
                          className="w-full h-full object-cover"
                        />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center text-white">
                          <TreePine size={20} />
                        </div>
                      )}
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="font-heading font-bold text-sm text-primary-800 truncate">
                        {collective.name}
                      </p>
                      <p className="text-xs text-moss-600 font-medium">
                        {collective.region} · {collective.member_count} members
                      </p>
                    </div>
                    <Badge variant="default" size="sm">
                      {membership.role.replace('_', ' ')}
                    </Badge>
                  </Card>
                )
              })}
            </div>
          ) : (
            <EmptyState
              illustration="wildlife"
              title="No collectives yet"
              description="Join a local collective to start your conservation journey"
              action={{ label: 'Explore Collectives', to: '/collectives' }}
              className="min-h-[180px]"
            />
          )}
        </motion.section>

        {/* Interests */}
        {profile.interests && profile.interests.length > 0 && (
          <motion.section
            variants={fadeUp}
            className="mt-6"
          >
            <SectionHeading
              icon={<Sprout size={14} />}
              iconBg="bg-sprout-600"
              title="Interests"
            />
            <div className="rounded-2xl bg-gradient-to-br from-sprout-200/80 via-sprout-100 to-primary-100/60 border border-sprout-200 p-4 shadow-sm">
              <div className="flex flex-wrap gap-2">
                {profile.interests.map((interest) => (
                  <Chip key={interest} label={interest} selected />
                ))}
              </div>
            </div>
          </motion.section>
        )}

      </motion.div>
    </Page>
  )
}

import { useParams, useNavigate } from 'react-router-dom'
import { motion, useReducedMotion } from 'framer-motion'
import {
  MapPin,
  Instagram,
  Calendar,
  Clock,
  TreePine,
  Users,
  Trash2,
  Sprout,
  Bird,
  Ruler,
} from 'lucide-react'
import { Page } from '@/components/page'
import { Header } from '@/components/header'
import { Avatar } from '@/components/avatar'
import { Chip } from '@/components/chip'
import { StatCard } from '@/components/stat-card'
import { Skeleton } from '@/components/skeleton'
import { EmptyState } from '@/components/empty-state'
import { cn } from '@/lib/cn'
import { parseLocationPoint } from '@/lib/geo'
import { MapView } from '@/components'
import { useProfile, useProfileCollectives, useProfileStats, useMutualConnections } from '@/hooks/use-profile'
import { useDelayedLoading } from '@/hooks/use-delayed-loading'

function ViewProfileSkeleton() {
  return (
    <div className="space-y-6 py-6">
      <div className="flex flex-col items-center gap-3">
        <Skeleton variant="avatar" className="h-24 w-24" />
        <Skeleton variant="title" className="w-40" />
        <Skeleton variant="text" className="w-24" />
      </div>
      <div className="grid grid-cols-3 gap-3">
        <Skeleton variant="stat-card" />
        <Skeleton variant="stat-card" />
        <Skeleton variant="stat-card" />
      </div>
    </div>
  )
}

export default function ViewProfilePage() {
  const { userId } = useParams<{ userId: string }>()
  const navigate = useNavigate()
  const shouldReduceMotion = useReducedMotion()
  const { data: profile, isLoading } = useProfile(userId)
  const showLoading = useDelayedLoading(isLoading)
  const { data: collectives } = useProfileCollectives(userId)
  const { data: stats } = useProfileStats(userId)
  const { data: mutualData } = useMutualConnections(userId ?? '')

  if (showLoading) {
    return (
      <Page header={<Header title="Profile" back />}>
        <ViewProfileSkeleton />
      </Page>
    )
  }
  if (!profile) {
    return (
      <Page header={<Header title="Profile" back />}>
        <EmptyState
          illustration="error"
          title="User not found"
          description="This profile doesn't exist or has been removed"
          action={{ label: 'Go Back', onClick: () => navigate(-1) }}
        />
      </Page>
    )
  }

  const stagger = {
    hidden: {},
    visible: { transition: { staggerChildren: 0.04 } },
  }

  const fadeUp = {
    hidden: { opacity: 0, y: 12 },
    visible: { opacity: 1, y: 0, transition: { duration: 0.25 } },
  }

  const memberSince = new Date(profile.created_at).toLocaleDateString('en-AU', {
    month: 'long',
    year: 'numeric',
  })

  return (
    <Page header={<Header title={profile.display_name ?? 'Profile'} back />}>
      <motion.div variants={shouldReduceMotion ? undefined : stagger} initial="hidden" animate="visible" className="pb-8">
        {/* Profile Header */}
        <motion.div
          variants={fadeUp}
          className="flex flex-col items-center pt-6 pb-4"
        >
          <Avatar
            src={profile.avatar_url}
            name={profile.display_name ?? ''}
            size="xl"
          />

          <h2 className="mt-3 font-heading text-xl font-bold text-primary-800">
            {profile.display_name}
          </h2>
          {profile.pronouns && (
            <span className="text-sm text-primary-400">{profile.pronouns}</span>
          )}

          {profile.bio && (
            <p className="mt-3 text-center text-sm text-primary-400 max-w-xs leading-relaxed">
              {profile.bio}
            </p>
          )}

          <div className="mt-3 flex flex-wrap items-center justify-center gap-3">
            {profile.location && (
              <span className="flex items-center gap-1 text-sm text-primary-400">
                <MapPin size={14} />
                {profile.location}
              </span>
            )}
            {profile.instagram_handle && (
              <a
                href={`https://instagram.com/${profile.instagram_handle.replace('@', '')}`}
                target="_blank"
                rel="noopener noreferrer"
                className="flex items-center gap-1 text-sm text-primary-400 hover:text-primary-400 transition-colors"
              >
                <Instagram size={14} />
                {profile.instagram_handle.startsWith('@')
                  ? profile.instagram_handle
                  : `@${profile.instagram_handle}`}
              </a>
            )}
          </div>

          <p className="mt-2 text-xs text-primary-400">Member since {memberSince}</p>
        </motion.div>

        {/* Mutual Connections */}
        {mutualData && (mutualData.sharedCollectives.length > 0 || mutualData.sharedEventCount > 0) && (
          <motion.div
            variants={fadeUp}
            className="mt-2 rounded-xl bg-surface-0 shadow-sm px-4 py-3"
          >
            <div className="flex items-center gap-2 text-sm text-primary-400">
              <Users size={16} />
              <div>
                {mutualData.sharedCollectives.length > 0 && (
                  <p>
                    You&apos;re both in{' '}
                    <span className="font-semibold">
                      {mutualData.sharedCollectives.map((c) => c.name).join(', ')}
                    </span>
                  </p>
                )}
                {mutualData.sharedEventCount > 0 && (
                  <p>
                    You&apos;ve attended{' '}
                    <span className="font-semibold">{mutualData.sharedEventCount} events</span>{' '}
                    together
                  </p>
                )}
              </div>
            </div>
          </motion.div>
        )}

        {/* Stats */}
        <motion.div
          variants={fadeUp}
          className="mt-6 grid grid-cols-3 gap-3"
        >
          <StatCard
            value={stats?.eventsAttended ?? 0}
            label="Events"
            icon={<Calendar size={20} />}
          />
          <StatCard
            value={stats?.hoursVolunteered ?? 0}
            label="Hours"
            icon={<Clock size={20} />}
          />
          <StatCard
            value={stats?.treesPlanted ?? 0}
            label="Trees"
            icon={<TreePine size={20} />}
          />
          {(stats?.rubbishCollectedKg ?? 0) > 0 && (
            <StatCard
              value={stats?.rubbishCollectedKg ?? 0}
              label="kg Rubbish"
              icon={<Trash2 size={20} />}
            />
          )}
          {(stats?.areaRestoredSqm ?? 0) > 0 && (
            <StatCard
              value={stats?.areaRestoredSqm ?? 0}
              label="Area (sqm)"
              icon={<Ruler size={20} />}
            />
          )}
          {(stats?.nativePlants ?? 0) > 0 && (
            <StatCard
              value={stats?.nativePlants ?? 0}
              label="Native Plants"
              icon={<Sprout size={20} />}
            />
          )}
          {(stats?.wildlifeSightings ?? 0) > 0 && (
            <StatCard
              value={stats?.wildlifeSightings ?? 0}
              label="Wildlife"
              icon={<Bird size={20} />}
            />
          )}
        </motion.div>

        {/* Collectives */}
        {collectives && collectives.length > 0 && (
          <motion.section
            variants={fadeUp}
            className="mt-6"
          >
            <h3 className="font-heading text-base font-semibold text-primary-800 mb-3">
              Collectives
            </h3>
            <div className="flex flex-wrap gap-2">
              {collectives.map((membership) => {
                const collective = membership.collectives as { name: string } | null
                return (
                  <Chip
                    key={membership.collective_id}
                    label={collective?.name ?? ''}
                    selected
                  />
                )
              })}
            </div>
          </motion.section>
        )}


        {/* Interests */}
        {profile.interests && profile.interests.length > 0 && (
          <motion.section
            variants={fadeUp}
            className="mt-6"
          >
            <h3 className="font-heading text-base font-semibold text-primary-800 mb-3">
              Interests
            </h3>
            <div className="flex flex-wrap gap-2">
              {profile.interests.map((interest) => (
                <Chip key={interest} label={interest} selected />
              ))}
            </div>
          </motion.section>
        )}

        {/* Location mini-map */}
        {(() => {
          const pos = parseLocationPoint(profile.location_point)
          if (!pos) return null
          return (
            <motion.section
              variants={fadeUp}
              className="mt-6"
            >
              <h3 className="font-heading text-base font-semibold text-primary-800 mb-3">
                Location
              </h3>
              <MapView
                center={pos}
                zoom={12}
                markers={[{ id: userId ?? 'user', position: pos, variant: 'default', label: profile.location ?? undefined }]}
                interactive={false}
                aria-label={`${profile.display_name ?? 'User'} location`}
                className="h-40 rounded-2xl"
              />
            </motion.section>
          )
        })()}
      </motion.div>
    </Page>
  )
}

import { useParams } from 'react-router-dom'
import { useQuery } from '@tanstack/react-query'
import { motion, useReducedMotion } from 'framer-motion'
import { Calendar, MapPin, Users, Clock, TreePine, ExternalLink, Download } from 'lucide-react'
import { useDelayedLoading } from '@/hooks/use-delayed-loading'
import { supabase } from '@/lib/supabase'
import { cn } from '@/lib/cn'
import { Button } from '@/components/button'
import { Skeleton } from '@/components/skeleton'
import { OGMeta, SITE_URL } from '@/components/og-meta'
import { APP_NAME } from '@/lib/constants'
import { WebFooter } from '@/components/web-footer'

function formatDate(date: string) {
  return new Date(date).toLocaleDateString('en-AU', {
    weekday: 'long',
    day: 'numeric',
    month: 'long',
    year: 'numeric',
  })
}

function formatTime(date: string) {
  return new Date(date).toLocaleTimeString('en-AU', {
    hour: 'numeric',
    minute: '2-digit',
  })
}

const ACTIVITY_LABELS: Record<string, string> = {
  shore_cleanup: 'Shore Cleanup',
  tree_planting: 'Tree Planting',
  land_regeneration: 'Land Regeneration',
  nature_walk: 'Nature Walks',
  camp_out: 'Camp Out',
  retreat: 'Retreats',
  film_screening: 'Film Screening',
  marine_restoration: 'Marine Restoration',
  workshop: 'Workshop',
}

const stagger = {
  hidden: {},
  visible: { transition: { staggerChildren: 0.04 } },
}

const fadeUp = {
  hidden: { opacity: 0, y: 12 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.25 } },
}

export default function PublicEventPage() {
  const { id } = useParams<{ id: string }>()
  const shouldReduceMotion = useReducedMotion()

  const { data: event, isLoading, error } = useQuery({
    queryKey: ['public-event', id],
    queryFn: async () => {
      const { data, error } = await supabase
        .from('events')
        .select('*, collectives(name, slug)')
        .eq('id', id!)
        .eq('is_public', true)
        .single()
      if (error) throw error
      return data
    },
    enabled: !!id,
  })
  const showLoading = useDelayedLoading(isLoading)

  if (showLoading) {
    return (
      <div className="min-h-dvh bg-white">
        <div className="h-64 animate-pulse bg-white" />
        <div className="mx-auto max-w-2xl p-6 space-y-4">
          <Skeleton variant="title" />
          <Skeleton variant="text" count={4} />
        </div>
      </div>
    )
  }
  if (error || !event) {
    return (
      <div className="flex min-h-dvh flex-col items-center justify-center bg-white p-6">
        <OGMeta title="Event Not Found" description="This event doesn't exist or is no longer available." />
        <h1 className="font-heading text-2xl font-bold text-primary-800">Event not found</h1>
        <p className="mt-2 text-primary-400">This event doesn't exist or is no longer public.</p>
        <Button variant="primary" className="mt-6" onClick={() => window.location.href = '/download'}>
          Get the {APP_NAME} App
        </Button>
      </div>
    )
  }

  const collectiveName = (event as Record<string, unknown>).collectives
    ? ((event as Record<string, unknown>).collectives as { name: string }).name
    : undefined

  const canonicalPath = `/event/${event.id}`
  const activityLabel = ACTIVITY_LABELS[event.activity_type] || 'conservation'
  const metaDescription = event.description
    ? event.description.slice(0, 155) + (event.description.length > 155 ? '...' : '')
    : `Join this ${activityLabel} event with Co-Exist${collectiveName ? `, hosted by ${collectiveName}` : ''} in Australia.`

  const eventJsonLd: Record<string, unknown> = {
    '@context': 'https://schema.org',
    '@type': 'Event',
    name: event.title,
    description: event.description || metaDescription,
    startDate: event.date_start,
    ...(event.date_end && { endDate: event.date_end }),
    eventAttendanceMode: 'https://schema.org/OfflineEventAttendanceMode',
    eventStatus: 'https://schema.org/EventScheduled',
    ...(event.address && {
      location: {
        '@type': 'Place',
        name: event.address,
        address: { '@type': 'PostalAddress', addressCountry: 'AU', streetAddress: event.address },
      },
    }),
    ...(event.cover_image_url && { image: event.cover_image_url }),
    organizer: {
      '@type': 'Organization',
      name: collectiveName || 'Co-Exist Australia',
      url: 'https://www.coexistaus.org',
    },
    ...(event.capacity && {
      maximumAttendeeCapacity: event.capacity,
    }),
    isAccessibleForFree: true,
    url: `${SITE_URL}${canonicalPath}`,
  }

  return (
    <div className="min-h-dvh bg-white">
      <OGMeta
        title={event.title}
        description={metaDescription}
        canonicalPath={canonicalPath}
        image={event.cover_image_url || undefined}
        jsonLd={eventJsonLd}
      />

      {/* Hero image */}
      <div className="relative h-64 sm:h-80 bg-primary-800 overflow-hidden">
        {event.cover_image_url ? (
          <img
            src={event.cover_image_url}
            alt={event.title}
            className="h-full w-full object-cover"
          />
        ) : (
          <div className="flex h-full items-center justify-center">
            <TreePine size={64} className="text-primary-300" />
          </div>
        )}
        <div className="absolute inset-0 bg-gradient-to-t from-black/70 via-black/20 to-transparent" />

        {/* Activity badge */}
        <motion.div
          initial={shouldReduceMotion ? false : { y: 10, opacity: 0 }}
          animate={{ y: 0, opacity: 1 }}
          className="absolute bottom-4 left-4"
        >
          <span className="inline-flex items-center gap-1.5 rounded-full bg-white/95 px-3 py-1.5 text-sm font-semibold text-primary-400 shadow-md">
            <TreePine size={14} />
            {ACTIVITY_LABELS[event.activity_type] || event.activity_type}
          </span>
        </motion.div>
      </div>

      {/* Content */}
      <motion.div
        className="mx-auto max-w-2xl px-4 py-6 sm:px-6"
        variants={shouldReduceMotion ? undefined : stagger}
        initial="hidden"
        animate="visible"
      >
        {/* Title */}
        <motion.div variants={shouldReduceMotion ? undefined : fadeUp}>
          <h1 className="font-heading text-2xl font-bold text-primary-800 sm:text-3xl">
            {event.title}
          </h1>

          {collectiveName && (
            <p className="mt-1 text-sm font-medium text-primary-400">
              Hosted by {collectiveName}
            </p>
          )}
        </motion.div>

        {/* Details grid */}
        <motion.div variants={shouldReduceMotion ? undefined : fadeUp} className="mt-6 space-y-3">
          <div className="flex items-start gap-3">
            <Calendar size={20} className="mt-0.5 shrink-0 text-primary-500" />
            <div>
              <p className="font-medium text-primary-800">{formatDate(event.date_start)}</p>
              <p className="text-sm text-primary-400">
                {formatTime(event.date_start)}
                {event.date_end && ` - ${formatTime(event.date_end)}`}
              </p>
            </div>
          </div>

          {event.address && (
            <div className="flex items-start gap-3">
              <MapPin size={20} className="mt-0.5 shrink-0 text-primary-500" />
              <p className="text-primary-800">{event.address}</p>
            </div>
          )}

          {event.capacity && (
            <div className="flex items-start gap-3">
              <Users size={20} className="mt-0.5 shrink-0 text-primary-500" />
              <p className="text-primary-800">{event.capacity} spots</p>
            </div>
          )}
        </motion.div>

        {/* Description */}
        {event.description && (
          <motion.div variants={shouldReduceMotion ? undefined : fadeUp} className="mt-6">
            <h2 className="font-heading text-lg font-semibold text-primary-800">About this event</h2>
            <p className="mt-2 whitespace-pre-line text-primary-400 leading-relaxed">
              {event.description}
            </p>
          </motion.div>
        )}

        {/* CTAs */}
        <motion.div
          variants={shouldReduceMotion ? undefined : fadeUp}
          className={cn(
            'mt-8 flex flex-col gap-3',
            'sticky bottom-4 rounded-2xl bg-white/95 p-4 shadow-lg',
            'sm:relative sm:bottom-auto sm:bg-transparent sm:p-0 sm:shadow-none',
          )}
        >
          <Button
            variant="primary"
            size="lg"
            fullWidth
            icon={<ExternalLink size={18} />}
            onClick={() => {
              // Try to open in-app, fallback to app store
              window.location.href = `coexist://events/${event.id}`
              setTimeout(() => {
                window.location.href = '/download'
              }, 1500)
            }}
          >
            Open in App
          </Button>
          <Button
            variant="secondary"
            size="lg"
            fullWidth
            icon={<Download size={18} />}
            onClick={() => window.location.href = '/download'}
          >
            Download {APP_NAME}
          </Button>
        </motion.div>

      </motion.div>

      <WebFooter />
    </div>
  )
}

