/* ------------------------------------------------------------------ */
/*  Change Password Sheet                                              */
/* ------------------------------------------------------------------ */

function ChangePasswordSheet({
  open,
  onClose,
}: {
  open: boolean
  onClose: () => void
}) {
  const { updatePassword } = useAuth()
  const { toast } = useToast()
  const [newPassword, setNewPassword] = useState('')
  const [confirmPassword, setConfirmPassword] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  const handleSubmit = async () => {
    setError('')
    if (newPassword.length < 8) {
      setError('Password must be at least 8 characters')
      return
    }
    if (newPassword !== confirmPassword) {
      setError('Passwords do not match')
      return
    }
    setLoading(true)
    const { error: err } = await updatePassword(newPassword)
    setLoading(false)
    if (err) {
      setError(err.message)
    } else {
      toast.success('Password updated')
      setNewPassword('')
      setConfirmPassword('')
      onClose()
    }
  }

  return (
    <BottomSheet open={open} onClose={onClose} snapPoints={[0.5]}>
      <h2 className="font-heading text-lg font-semibold text-primary-800 mb-4">
        Change Password
      </h2>
      <div className="space-y-3">
        <Input
          type="password"
          label="New Password"
          value={newPassword}
          onChange={(e) => setNewPassword(e.target.value)}
          autoComplete="new-password"
          error={error && !confirmPassword ? error : undefined}
        />
        <Input
          type="password"
          label="Confirm Password"
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
          autoComplete="new-password"
          error={error && confirmPassword ? error : undefined}
        />
        <Button
          variant="primary"
          fullWidth
          loading={loading}
          onClick={handleSubmit}
        >
          Update Password
        </Button>
      </div>
    </BottomSheet>
  )
}

/* ------------------------------------------------------------------ */
/*  Change Email Sheet                                                 */
/* ------------------------------------------------------------------ */

function ChangeEmailSheet({
  open,
  onClose,
}: {
  open: boolean
  onClose: () => void
}) {
  const { user } = useAuth()
  const { toast } = useToast()
  const [newEmail, setNewEmail] = useState('')
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')

  const handleSubmit = async () => {
    setError('')
    if (!newEmail.includes('@')) {
      setError('Please enter a valid email')
      return
    }
    setLoading(true)
    const { error: err } = await supabase.auth.updateUser({ email: newEmail })
    setLoading(false)
    if (err) {
      setError(err.message)
    } else {
      toast.success('Verification email sent to your new address')
      setNewEmail('')
      onClose()
    }
  }

  return (
    <BottomSheet open={open} onClose={onClose} snapPoints={[0.4]}>
      <h2 className="font-heading text-lg font-semibold text-primary-800 mb-2">
        Change Email
      </h2>
      <p className="text-sm text-primary-400 mb-4">
        Current: {user?.email}
      </p>
      <div className="space-y-3">
        <Input
          type="email"
          label="New Email"
          value={newEmail}
          onChange={(e) => setNewEmail(e.target.value)}
          autoComplete="email"
          error={error || undefined}
        />
        <Button
          variant="primary"
          fullWidth
          loading={loading}
          onClick={handleSubmit}
        >
          Send Verification
        </Button>
      </div>
    </BottomSheet>
  )
}

