  it('renders children', () => {
    render(
      <BottomSheet open onClose={onClose}>
        <p>Hello from sheet</p>
      </BottomSheet>,
    )
    expect(screen.getByText('Hello from sheet')).toBeInTheDocument()
  })

  it('calls onClose on Escape key', async () => {
