describe('Celebration', () => {
  const onClose = vi.fn()

  beforeEach(() => {
    vi.useFakeTimers()
    vi.clearAllMocks()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  it('renders nothing when closed', () => {
    render(
      <Celebration open={false} onClose={onClose} title="Badge Unlocked!" />,
    )
    expect(screen.queryByRole('dialog')).not.toBeInTheDocument()
  })

  it('renders dialog when open', () => {
    render(
      <Celebration open onClose={onClose} title="Badge Unlocked!" />,
    )
    expect(screen.getByRole('dialog')).toBeInTheDocument()
    expect(screen.getByRole('dialog')).toHaveAttribute('aria-modal', 'true')
    expect(screen.getByRole('dialog')).toHaveAttribute('aria-label', 'Badge Unlocked!')
  })

  it('renders title', () => {
    render(
      <Celebration open onClose={onClose} title="Level Up!" />,
    )
    expect(screen.getByText('Level Up!')).toBeInTheDocument()
  })

  it('renders subtitle when provided', () => {
    render(
      <Celebration
        open
        onClose={onClose}
        title="Badge Unlocked!"
        subtitle="You earned the Tree Hugger badge"
      />,
    )
    expect(screen.getByText('You earned the Tree Hugger badge')).toBeInTheDocument()
  })

  it('renders icon when provided', () => {
    render(
      <Celebration
        open
        onClose={onClose}
        title="Test"
        icon={<span data-testid="icon">T</span>}
      />,
    )
    expect(screen.getByTestId('icon')).toBeInTheDocument()
  })

  it('auto-dismisses after autoDismiss delay', () => {
    render(
      <Celebration open onClose={onClose} title="Test" autoDismiss={3000} />,
    )
    expect(onClose).not.toHaveBeenCalled()
    act(() => {
      vi.advanceTimersByTime(3000)
    })
    expect(onClose).toHaveBeenCalledOnce()
  })

  it('does not auto-dismiss when autoDismiss is 0', () => {
    render(
      <Celebration open onClose={onClose} title="Test" autoDismiss={0} />,
    )
    act(() => {
      vi.advanceTimersByTime(10000)
    })
    expect(onClose).not.toHaveBeenCalled()
  })

  it('calls onClose when clicked', async () => {
    vi.useRealTimers()
    const user = userEvent.setup()
    render(
      <Celebration open onClose={onClose} title="Test" autoDismiss={0} />,
    )
    await user.click(screen.getByRole('dialog'))
    expect(onClose).toHaveBeenCalled()
  })

  it('shows tap to dismiss hint', () => {
    render(
      <Celebration open onClose={onClose} title="Test" />,
    )
    expect(screen.getByText('Tap anywhere to continue')).toBeInTheDocument()
  })
})

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { render, screen, act } from '@testing-library/react'
import { Confetti } from '@/components/confetti'

// Mock framer-motion
vi.mock('framer-motion', async () => {
  const actual = await vi.importActual<typeof import('framer-motion')>('framer-motion')
  return {
    ...actual,
    motion: {
      ...actual.motion,
      div: ({ children, ...props }: any) => <div {...props}>{children}</div>,
    },
    useReducedMotion: () => false,
    AnimatePresence: ({ children }: { children: React.ReactNode }) => <>{children}</>,
  }
})

describe('Confetti', () => {
  beforeEach(() => {
    vi.useFakeTimers()
  })

  afterEach(() => {
    vi.useRealTimers()
  })

  it('renders nothing when not active', () => {
    const { container } = render(<Confetti active={false} />)
    expect(container.querySelector('[aria-hidden="true"]')).toBeNull()
  })

  it('renders particles when active', () => {
    render(<Confetti active count={10} />)
    // The container is aria-hidden
    const confettiContainer = document.querySelector('[aria-hidden="true"]')
    expect(confettiContainer).toBeInTheDocument()
  })

  it('auto-clears after duration', () => {
    const { container } = render(<Confetti active count={5} duration={1000} />)
    // Initially visible
    expect(document.querySelector('[aria-hidden="true"]')).toBeInTheDocument()

    act(() => {
      vi.advanceTimersByTime(1000)
    })

    // After duration, should be cleared
    // Note: AnimatePresence may still render briefly, but particles should be gone
  })

  it('respects count prop', () => {
    render(<Confetti active count={3} />)
    // 3 particles should be rendered (each as an absolute div)
    const container = document.querySelector('[aria-hidden="true"]')
    expect(container).toBeInTheDocument()
    // Each particle is a .absolute div inside the container
    const particles = container?.querySelectorAll('.absolute')
    expect(particles?.length).toBe(3)
  })
})

