/* ------------------------------------------------------------------ */
/*  SendGrid API call                                                  */
/* ------------------------------------------------------------------ */

interface SendEmailPayload {
  /** Email type - must match a key in EMAIL_TEMPLATES */
  type: string
  /** Recipient email address */
  to: string
  /** Dynamic template data (Handlebars variables) */
  data?: Record<string, unknown>
  /** Optional: override the subject (for non-template sends) */
  subject?: string
  /** For internal requests (e.g. data export) */
  userId?: string
  email?: string
}

async function sendViaSendGrid(
  to: string,
  templateId: string,
  dynamicData: Record<string, unknown>,
  category: string,
): Promise<{ success: boolean; error?: string }> {
  const resp = await fetch('https://api.sendgrid.com/v3/mail/send', {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${SENDGRID_API_KEY}`,
      'Content-Type': 'application/json',
    },
    body: JSON.stringify({
      personalizations: [
        {
          to: [{ email: to }],
          dynamic_template_data: dynamicData,
        },
      ],
      from: { email: FROM_EMAIL, name: FROM_NAME },
      template_id: templateId,
      categories: [category],
      // CAN-SPAM: one-click unsubscribe header
      headers: {
        'List-Unsubscribe': `<mailto:unsubscribe@coexistaus.org?subject=Unsubscribe>, <https://app.coexistaus.org/unsubscribe?email=${encodeURIComponent(to)}>`,
        'List-Unsubscribe-Post': 'List-Unsubscribe=One-Click',
      },
    }),
  })

  if (!resp.ok) {
    const err = await resp.text()
    console.error(`[send-email] SendGrid error:`, err)
    return { success: false, error: err }
  }

  return { success: true }
}

/* ------------------------------------------------------------------ */
/*  Unsubscribe handling (CAN-SPAM compliant)                          */
/* ------------------------------------------------------------------ */

async function handleUnsubscribe(
  supabaseAdmin: ReturnType<typeof createClient>,
  email: string,
) {
  // Find user by email - paginate through all users (listUsers default page is 50)
  let page = 1
  const perPage = 1000
  let found = false

  while (!found) {
    const { data: usersPage } = await supabaseAdmin.auth.admin.listUsers({
      page,
      perPage,
    })

    if (!usersPage?.users?.length) break

    const user = usersPage.users.find((u: { email?: string }) => u.email === email)
    if (user) {
      await supabaseAdmin
        .from('profiles')
        .update({ marketing_opt_in: false })
        .eq('id', user.id)
      found = true
    }

    // If we got fewer results than page size, we've reached the end
    if (usersPage.users.length < perPage) break
    page++
  }
}

/* ------------------------------------------------------------------ */
/*  Main handler                                                       */
/* ------------------------------------------------------------------ */

serve(async (req: Request) => {
  try {
    const url = new URL(req.url)

    // Handle one-click unsubscribe (POST to /unsubscribe)
    if (url.pathname.endsWith('/unsubscribe') && req.method === 'POST') {
      const formData = await req.formData().catch(() => null)
      const email = formData?.get('email') as string | null
        || url.searchParams.get('email')

      if (email) {
        const supabaseAdmin = createClient(
          Deno.env.get('SUPABASE_URL')!,
          Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!,
        )
        await handleUnsubscribe(supabaseAdmin, email)
      }

      return new Response('Unsubscribed', { status: 200 })
    }

    const payload = (await req.json()) as SendEmailPayload
    const { type, data = {} } = payload

    // Resolve recipient
    let toEmail = payload.to || payload.email || ''

    // If userId provided but no email, look it up
    if (!toEmail && payload.userId) {
      const supabaseAdmin = createClient(
        Deno.env.get('SUPABASE_URL')!,
        Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!,
      )
      const { data: userData } = await supabaseAdmin.auth.admin.getUserById(payload.userId)
      toEmail = userData?.user?.email ?? ''
    }

    if (!toEmail) {
      return new Response(
        JSON.stringify({ success: false, error: 'No recipient email' }),
        { status: 400, headers: { 'Content-Type': 'application/json' } },
      )
    }

    // Look up template
    const templateDef = EMAIL_TEMPLATES[type]
    if (!templateDef) {
      return new Response(
        JSON.stringify({ success: false, error: `Unknown email type: ${type}` }),
        { status: 400, headers: { 'Content-Type': 'application/json' } },
      )
    }

    // Check marketing opt-in for marketing emails
    if (templateDef.category === 'marketing') {
      if (!payload.userId) {
        return new Response(
          JSON.stringify({ success: false, error: 'userId required for marketing emails' }),
          { status: 400, headers: { 'Content-Type': 'application/json' } },
        )
      }
      const supabaseAdmin = createClient(
        Deno.env.get('SUPABASE_URL')!,
        Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!,
      )
      const { data: profile } = await supabaseAdmin
        .from('profiles')
        .select('marketing_opt_in')
        .eq('id', payload.userId)
        .single()

      // If profile not found or user has opted out, don't send
      if (!profile || profile.marketing_opt_in === false) {
        return new Response(
          JSON.stringify({ success: false, error: 'User opted out of marketing or not found' }),
          { status: 200, headers: { 'Content-Type': 'application/json' } },
        )
      }
    }

    const templateId = Deno.env.get(templateDef.templateIdEnvKey)
    if (!templateId) {
      console.error(`[send-email] Missing env var: ${templateDef.templateIdEnvKey}`)
      return new Response(
        JSON.stringify({ success: false, error: 'Template not configured' }),
        { status: 500, headers: { 'Content-Type': 'application/json' } },
      )
    }

    const result = await sendViaSendGrid(
      toEmail,
      templateId,
      data,
      templateDef.category,
    )

    return new Response(JSON.stringify(result), {
      status: result.success ? 200 : 500,
      headers: { 'Content-Type': 'application/json' },
    })
  } catch (err) {
    console.error('[send-email] Error:', err)
    return new Response(
      JSON.stringify({ success: false, error: 'Internal error' }),
      { status: 500, headers: { 'Content-Type': 'application/json' } },
    )
  }
})

// @ts-nocheck - Deno Edge Function
import { serve } from 'https://deno.land/std@0.168.0/http/server.ts'
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2'

/* ------------------------------------------------------------------ */
/*  Types                                                              */
/* ------------------------------------------------------------------ */

interface PushPayload {
  /** Target a single user */
  userId?: string
  /** Target multiple users */
  userIds?: string[]
  /** Target all members of a collective */
  collectiveId?: string
  /** Notification content */
  title: string
  body: string
  /** Deep link data */
  data?: Record<string, string>
  /** Silent notification (data-only, no alert) */
  silent?: boolean
}

interface PushToken {
  token: string
  platform: 'ios' | 'android'
  user_id: string
}

/* ------------------------------------------------------------------ */
/*  FCM HTTP v1 sender                                                 */
/* ------------------------------------------------------------------ */

const FCM_PROJECT_ID = Deno.env.get('FCM_PROJECT_ID') ?? ''
const FCM_SERVICE_ACCOUNT_KEY = Deno.env.get('FCM_SERVICE_ACCOUNT_KEY') ?? ''

// Base64url encoding (RFC 4648 §5) - required for JWT
function base64url(input: string | ArrayBuffer): string {
  let b64: string
  if (typeof input === 'string') {
    b64 = btoa(input)
  } else {
    b64 = btoa(String.fromCharCode(...new Uint8Array(input)))
  }
  return b64.replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '')
}

// Cache the OAuth token to avoid requesting a new one per push send
let cachedAccessToken: string | null = null
let tokenExpiresAt = 0

async function getAccessToken(): Promise<string> {
  // Return cached token if still valid (with 5-minute safety margin)
  if (cachedAccessToken && Date.now() < tokenExpiresAt - 5 * 60 * 1000) {
    return cachedAccessToken
  }

  // Use service account key to get OAuth2 token for FCM v1 API
  const key = JSON.parse(FCM_SERVICE_ACCOUNT_KEY)
  const now = Math.floor(Date.now() / 1000)

  const header = base64url(JSON.stringify({ alg: 'RS256', typ: 'JWT' }))
  const claim = base64url(
    JSON.stringify({
      iss: key.client_email,
      scope: 'https://www.googleapis.com/auth/firebase.messaging',
      aud: 'https://oauth2.googleapis.com/token',
      iat: now,
      exp: now + 3600,
    }),
  )

  // Sign JWT with private key
  const encoder = new TextEncoder()
  const data = encoder.encode(`${header}.${claim}`)

  const cryptoKey = await crypto.subtle.importKey(
    'pkcs8',
    pemToArrayBuffer(key.private_key),
    { name: 'RSASSA-PKCS1-v1_5', hash: 'SHA-256' },
    false,
    ['sign'],
  )

  const signature = await crypto.subtle.sign('RSASSA-PKCS1-v1_5', cryptoKey, data)
  const jwt = `${header}.${claim}.${base64url(signature)}`

  const resp = await fetch('https://oauth2.googleapis.com/token', {
    method: 'POST',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: `grant_type=urn:ietf:params:oauth:grant-type:jwt-bearer&assertion=${jwt}`,
  })

  const json = await resp.json()
  cachedAccessToken = json.access_token
  tokenExpiresAt = Date.now() + 3600 * 1000 // 1 hour
  return json.access_token
}

function pemToArrayBuffer(pem: string): ArrayBuffer {
  const b64 = pem
    .replace(/-----BEGIN PRIVATE KEY-----/, '')
    .replace(/-----END PRIVATE KEY-----/, '')
    .replace(/\n/g, '')
  const bin = atob(b64)
  const buf = new Uint8Array(bin.length)
  for (let i = 0; i < bin.length; i++) buf[i] = bin.charCodeAt(i)
  return buf.buffer
}

async function sendFcmMessage(
  token: string,
  title: string,
  body: string,
  data: Record<string, string>,
  silent: boolean,
): Promise<'sent' | 'invalid' | 'transient'> {
  const accessToken = await getAccessToken()

  const message: Record<string, unknown> = {
    token,
    data,
  }

  if (!silent) {
    message.notification = { title, body }
    message.android = {
      priority: 'high',
      notification: { sound: 'default', channel_id: 'coexist_default' },
    }
    message.apns = {
      payload: { aps: { sound: 'default', badge: 1 } },
    }
  } else {
    // Silent / data-only
    message.android = { priority: 'high' }
    message.apns = {
      payload: { aps: { 'content-available': 1 } },
    }
  }

  const resp = await fetch(
    `https://fcm.googleapis.com/v1/projects/${FCM_PROJECT_ID}/messages:send`,
    {
      method: 'POST',
      headers: {
        Authorization: `Bearer ${accessToken}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ message }),
    },
  )

  if (!resp.ok) {
    const err = await resp.text()
    console.error(`[send-push] FCM error for token ${token.slice(0, 12)}...:`, err)
    // Return error detail so caller can distinguish permanent vs transient failures
    try {
      const parsed = JSON.parse(err)
      const errorCode = parsed?.error?.details?.[0]?.errorCode ?? parsed?.error?.status ?? ''
      // Only mark as invalid if the token is permanently unregistered
      if (errorCode === 'UNREGISTERED' || errorCode === 'INVALID_ARGUMENT') {
        return 'invalid'
      }
    } catch { /* non-JSON error response */ }
    return 'transient'
  }
  return 'sent'
}

/* ------------------------------------------------------------------ */
/*  Main handler                                                       */
/* ------------------------------------------------------------------ */

serve(async (req: Request) => {
  try {
    const payload = (await req.json()) as PushPayload

    // ---- Input validation ----
    const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i

    if (!payload.title || typeof payload.title !== 'string' || payload.title.length > 200) {
      return new Response(JSON.stringify({ error: 'title required (max 200 chars)', sent: 0 }), {
        status: 400, headers: { 'Content-Type': 'application/json' },
      })
    }
    if (!payload.body || typeof payload.body !== 'string' || payload.body.length > 1000) {
      return new Response(JSON.stringify({ error: 'body required (max 1000 chars)', sent: 0 }), {
        status: 400, headers: { 'Content-Type': 'application/json' },
      })
    }
    if (payload.userId && !UUID_RE.test(payload.userId)) {
      return new Response(JSON.stringify({ error: 'Invalid userId', sent: 0 }), {
        status: 400, headers: { 'Content-Type': 'application/json' },
      })
    }
    if (payload.userIds) {
      if (!Array.isArray(payload.userIds) || payload.userIds.length > 500) {
        return new Response(JSON.stringify({ error: 'userIds must be array (max 500)', sent: 0 }), {
          status: 400, headers: { 'Content-Type': 'application/json' },
        })
      }
      if (payload.userIds.some((id: string) => !UUID_RE.test(id))) {
        return new Response(JSON.stringify({ error: 'Invalid UUID in userIds', sent: 0 }), {
          status: 400, headers: { 'Content-Type': 'application/json' },
        })
      }
    }
    if (payload.collectiveId && !UUID_RE.test(payload.collectiveId)) {
      return new Response(JSON.stringify({ error: 'Invalid collectiveId', sent: 0 }), {
        status: 400, headers: { 'Content-Type': 'application/json' },
      })
    }

    // Init Supabase with service role
    const supabaseAdmin = createClient(
      Deno.env.get('SUPABASE_URL')!,
      Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!,
    )

    // Resolve target user IDs
    let targetUserIds: string[] = []

    if (payload.userId) {
      targetUserIds = [payload.userId]
    } else if (payload.userIds) {
      targetUserIds = payload.userIds
    } else if (payload.collectiveId) {
      const { data: members } = await supabaseAdmin
        .from('collective_members')
        .select('user_id')
        .eq('collective_id', payload.collectiveId)
        .eq('status', 'active')
      targetUserIds = (members ?? []).map((m: { user_id: string }) => m.user_id)
    }

    if (targetUserIds.length === 0) {
      return new Response(JSON.stringify({ sent: 0 }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // Fetch push tokens for target users
    const { data: tokens } = await supabaseAdmin
      .from('push_tokens')
      .select('token, platform, user_id')
      .in('user_id', targetUserIds)

    if (!tokens || tokens.length === 0) {
      return new Response(JSON.stringify({ sent: 0 }), {
        headers: { 'Content-Type': 'application/json' },
      })
    }

    // Check notification preferences + quiet hours
    const { data: profiles } = await supabaseAdmin
      .from('profiles')
      .select('id, notification_preferences')
      .in('id', targetUserIds)

    const prefsMap = new Map<string, Record<string, unknown>>()
    for (const p of profiles ?? []) {
      if (p.notification_preferences) {
        prefsMap.set(p.id, p.notification_preferences as Record<string, unknown>)
      }
    }

    // Filter tokens by user preferences
    const notifType = payload.data?.type
    const filteredTokens = (tokens as PushToken[]).filter((t) => {
      const userPrefs = prefsMap.get(t.user_id)
      if (!userPrefs || !notifType) return true

      // Check if notification type is disabled
      if (userPrefs[notifType] === false) return false

      // Check quiet hours (using user's timezone, not server UTC)
      if (userPrefs.quiet_hours_enabled) {
        const userTz = (userPrefs.timezone as string) || 'Australia/Sydney'
        const now = new Date()
        // Get current time in the user's timezone
        const userTime = new Intl.DateTimeFormat('en-AU', {
          hour: '2-digit',
          minute: '2-digit',
          hour12: false,
          timeZone: userTz,
        }).format(now)
        const current = userTime // "HH:MM"
        const start = (userPrefs.quiet_hours_start as string) ?? '22:00'
        const end = (userPrefs.quiet_hours_end as string) ?? '07:00'

        // Handle overnight range (e.g. 22:00 - 07:00)
        if (start > end) {
          if (current >= start || current < end) return false
        } else {
          if (current >= start && current < end) return false
        }
      }

      return true
    })

    // Send to all filtered tokens in parallel
    const results = await Promise.allSettled(
      filteredTokens.map((t) =>
        sendFcmMessage(
          t.token,
          payload.title,
          payload.body,
          payload.data ?? {},
          payload.silent ?? false,
        ),
      ),
    )

    const sent = results.filter(
      (r) => r.status === 'fulfilled' && r.value === 'sent',
    ).length

    // Only clean up tokens that are permanently invalid (UNREGISTERED), not transient failures
    const invalidTokens = filteredTokens.filter(
      (_, i) => results[i].status === 'fulfilled' && (results[i] as PromiseFulfilledResult<string>).value === 'invalid',
    )
    if (invalidTokens.length > 0) {
      await supabaseAdmin
        .from('push_tokens')
        .delete()
        .in('token', invalidTokens.map((t) => t.token))
    }

    return new Response(JSON.stringify({ sent, total: filteredTokens.length }), {
      headers: { 'Content-Type': 'application/json' },
    })
  } catch (err) {
    console.error('[send-push] Error:', err)
    // Return 200 to prevent retries
    return new Response(
      JSON.stringify({ error: 'Internal error', sent: 0 }),
      { status: 200, headers: { 'Content-Type': 'application/json' } },
    )
  }
})
